import type { InfoPageCopy } from './info-page-i18n';
import type { LandingLocaleCode } from './i18n';

type Guides = NonNullable<InfoPageCopy['agentGuides']>;


export function localizedAgentGuidesPartB(en: Guides): Partial<Record<LandingLocaleCode, Guides>> {
  return {
    'fr': {
      'claude-code': {
        ...en['claude-code']!,
        title: "Claude Code pour le design — Open Design",
        description: "Comment les designers utilisent Claude Code pour le design d’interfaces et de sites web, et comment Open Design en fait un véritable agent de design — local-first, BYOK, avec une bibliothèque organisée de skills et de design systems.",
        breadcrumb: "Claude Code",
        label: "Agent · Claude Code",
        heading: "Claude Code pour le design.",
        lead: "Claude Code est l’agent de code en terminal d’Anthropic. On l’utilise déjà pour construire des interfaces, des design systems et des landing pages. Open Design le branche sur un véritable workflow de design — apportez votre clé Anthropic ou votre abonnement Claude, gardez chaque fichier en local.",
        rich: {"heroCtaLead": "Open Design transforme Claude Code en un agent de design open source et local-first — votre clé Anthropic ou votre abonnement Claude, vos fichiers, et autour, une bibliothèque organisée de skills et de design systems.", "heroCtaActions": [{"label": "Utiliser Claude Code dans Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Star sur GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Télécharger l’application desktop", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Claude Code est largement considéré comme l’agent de code au meilleur goût en frontend — il raisonne sur les interfaces avec une précision inhabituelle, nommant des valeurs hex exactes, des espacements et des échelles typographiques, et il refactorise l’UI à travers une grande base de code sans perdre le fil. Mais tel quel, il dérive encore vers un rendu générique tant que vous ne lui fournissez pas un design system, des skills et de vraies références. Voici un guide pratique et complet pour utiliser Claude Code dans un travail d’UI, de frontend et de design system, et pour l’intégrer à un workflow structuré avec Open Design.", "Il couvre ce qu’est réellement Claude Code, pourquoi il excelle en frontend, comment le configurer à partir de zéro, le workflow CLAUDE.md et Skills, l’aller-retour officiel avec Figma, sa comparaison avec Codex et Cursor, les pièges qui rendent les sorties d’IA génériques, et comment Open Design comble l’écart en tant que couche de design ouverte et local-first."], "heroImage": {"src": "/agents/claude-code-design/claude-code-design-hero.webp", "alt": "Boucle de rétroaction de design avec Claude Code : un agent en terminal prenant des décisions de design précises, un navigateur affichant l’UI et un espace de travail, avec une flèche de rétroaction qui boucle", "caption": "La boucle centrale : Claude Code raisonne sur des décisions d’UI précises dans le terminal, les affiche et les vérifie dans un vrai navigateur, et converge vers vos références."}, "tocLabel": "Sur cette page", "toc": [{"id": "what-is-claude-code", "label": "Ce qu’est réellement Claude Code"}, {"id": "why-design", "label": "Pourquoi Claude Code est bon en design"}, {"id": "setup", "label": "Configurer Claude Code pour le design (à partir de zéro)"}, {"id": "skills-workflow", "label": "Le workflow CLAUDE.md et Skills"}, {"id": "figma", "label": "Aller-retour Claude Code + Figma"}, {"id": "vs", "label": "Claude Code vs Codex vs Cursor"}, {"id": "pitfalls", "label": "Les pièges et le rendu « AI slop »"}, {"id": "open-design", "label": "Concevoir avec Claude Code dans Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-claude-code", "heading": "Ce qu’est réellement Claude Code", "blocks": [{"kind": "p", "text": "Claude Code est l’outil de code agentique d’Anthropic. Il lit votre base de code, modifie des fichiers, exécute des commandes et s’intègre à vos outils de développement — il planifie, écrit et vérifie le travail à partir de tâches en langage naturel, plutôt que de se contenter de compléter des lignes."}, {"kind": "p", "text": "Il se décline sur plusieurs surfaces qui partagent toutes le même moteur : une CLI en terminal, des extensions IDE pour VS Code, Cursor et JetBrains, une application desktop avec revue visuelle des diffs, et une expérience web pour les tâches de longue durée. Vos fichiers CLAUDE.md, vos réglages et vos serveurs MCP s’appliquent à toutes."}, {"kind": "steps", "items": [{"label": "Fichier d’instructions", "body": "Claude Code lit un fichier CLAUDE.md à la racine de votre projet au début de chaque session — l’endroit naturel pour encoder vos conventions de design, vos tokens et vos checklists de revue."}, {"label": "Skills", "body": "Les Agent Skills regroupent des instructions, scripts et ressources réutilisables que Claude charge à la demande, y compris la skill officielle Frontend Design d’Anthropic pour le goût."}, {"label": "Plan et sous-agents", "body": "Il peut planifier avant d’agir et lancer des sous-agents qui travaillent en parallèle sur différentes parties d’une tâche, ce qui maintient la cohérence des grands refactors d’UI."}]}, {"kind": "ul", "items": ["Éditeur : Anthropic", "Identifiant : clé API Anthropic (BYOK, via la Console) ou abonnement Claude (Pro / Max)", "Surfaces : CLI en terminal, extensions VS Code / Cursor / JetBrains, application desktop, web"]}]}, {"id": "why-design", "heading": "Pourquoi Claude Code est bon en design", "blocks": [{"kind": "p", "text": "Parmi les agents de code, Claude Code a une réputation de goût pour le travail en frontend. Quelques raisons l’expliquent."}, {"kind": "steps", "items": [{"label": "Des décisions précises, pas vagues", "body": "Claude Code a tendance à s’engager sur des choix concrets — valeurs hex exactes, échelles d’espacement, rampes typographiques et hiérarchie des composants — au lieu de rester évasif, ce qui distingue une vraie interface d’une maquette de remplissage."}, {"label": "Un raisonnement conscient de la base de code", "body": "Avec un large contexte de travail, il refactorise l’UI à travers de nombreux fichiers à la fois, en réutilisant vos composants et tokens existants au lieu de réinventer des styles isolés."}, {"label": "Une skill frontend officielle", "body": "Anthropic fournit une skill Frontend Design qui amène Claude à définir d’abord une direction de design et l’éloigne délibérément des polices système génériques et des dégradés violets prévisibles."}]}, {"kind": "image", "src": "/agents/claude-code-design/claude-code-design-taste-triangle.webp", "alt": "Schéma montrant un design system, une skill et une image de référence convergeant vers une bonne sortie de design", "caption": "Le goût vient de trois entrées que vous fournissez : un design system, une skill et de vraies images de référence."}, {"kind": "p", "text": "La leçon est la même que celle qu’Anthropic formule à propos de ses propres modèles : Claude n’a pas de goût par défaut — laissé à lui-même, il converge vers le centre statistique du web design (Inter, dégradés violets, ombres douces). Il produit de bons designs quand vous lui donnez des contraintes. Open Design empaquette précisément ces entrées, et c’est pourquoi les deux s’accordent (plus de détails ci-dessous)."}]}, {"id": "setup", "heading": "Configurer Claude Code pour le design, à partir de zéro", "blocks": [{"kind": "p", "text": "Voici le parcours complet, d’une machine vierge à un Claude Code capable de construire et de vérifier des UI."}, {"kind": "code", "lang": "bash", "code": "# 1. Install Claude Code (native install, recommended)\ncurl -fsSL https://claude.ai/install.sh | bash\n# or: brew install --cask claude-code\n# Windows PowerShell: irm https://claude.ai/install.ps1 | iex\n\n# 2. Start it in your project and sign in on first run\ncd your-project\nclaude            # sign in with your Claude subscription or API key\n\n# 3. Generate project context\n/init             # creates a CLAUDE.md for this project\n\n# 4. Add the official Frontend Design skill\nclaude plugin install frontend-design@claude-plugins-official\n\n# 5. Wire the Figma MCP server (optional, for design handoff)\nclaude plugin install figma@claude-plugins-official"}, {"kind": "image", "src": "/agents/claude-code-design/claude-code-design-setup-flow.webp", "alt": "Flux de configuration en cinq étapes : installer, authentifier, configurer CLAUDE.md, ajouter une skill, vérifier", "caption": "La séquence de configuration : installer → authentifier → configurer CLAUDE.md → ajouter la skill Frontend Design → activer la vérification en navigateur."}, {"kind": "steps", "items": [{"label": "Encodez vos règles de design", "body": "Mettez vos tokens, primitives et conventions dans CLAUDE.md et orientez Claude vers eux, pour que les sorties correspondent à une marque au lieu de retomber sur un rendu générique."}, {"label": "Ajoutez la vérification en navigateur", "body": "Branchez un MCP Playwright ou Chrome pour que Claude rende dans un vrai navigateur et contrôle ses sorties sur les différents breakpoints, au lieu de simplement confirmer que le build passe."}]}]}, {"id": "skills-workflow", "heading": "Le workflow CLAUDE.md et Skills", "blocks": [{"kind": "p", "text": "La boucle de design la plus efficace avec Claude Code consiste à lui donner de vraies références ainsi que votre contexte de design, puis à itérer jusqu’à ce que l’UI corresponde — avec CLAUDE.md et les Skills qui portent les contraintes pour ne pas avoir à les réexpliquer à chaque prompt."}, {"kind": "ol", "items": ["Partez des références visuelles les plus claires dont vous disposez — et incluez plusieurs états (desktop et mobile, survol, vide, chargement), pas seulement un visuel héros.", "Soyez précis dans le prompt ; des prompts vagues produisent une UI générique, même avec un agent puissant.", "Gardez votre design system et vos conventions dans CLAUDE.md, et indiquez à Claude où se trouvent les tokens et les primitives canoniques.", "Ajoutez la skill Frontend Design pour que Claude s’engage sur une véritable direction esthétique avant d’écrire du code.", "Branchez la vérification en navigateur pour que Claude rende, redimensionne aux breakpoints et compare aux références — au lieu de simplement confirmer que ça build."]}, {"kind": "p", "text": "Déposez une image de référence dans la session et formulez le prompt avec des contraintes concrètes :"}, {"kind": "code", "lang": "bash", "code": "claude \"Implement reference-desktop.png and reference-mobile.png in\n  React + Vite + Tailwind + TypeScript.\n  Reuse the design-system components and tokens described in CLAUDE.md.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Render it in the browser, verify it matches the references across\n  breakpoints, and iterate until it does.\""}, {"kind": "p", "text": "Faites tourner un serveur de dev en parallèle, gardez des prompts courts et ciblés, committez les bonnes itérations / annulez les mauvaises (en prévenant Claude quand vous revenez en arrière) pour que chaque passe parte d’une base propre. Utilisez le mode plan pour les refactors plus importants afin de pouvoir relire l’approche avant toute modification de fichier."}]}, {"id": "figma", "heading": "Claude Code + Figma : aller-retour design ↔ code", "blocks": [{"kind": "p", "text": "En février 2026, Anthropic et Figma ont livré une intégration bidirectionnelle de premier ordre via le serveur Figma MCP. Elle fonctionne dans les deux sens."}, {"kind": "steps", "items": [{"label": "Design → Code", "body": "Sélectionnez une frame dans Figma ou collez un lien dans Claude Code, récupérez le contexte de design et demandez-lui d’implémenter la maquette avec votre bibliothèque de composants existante. Code Connect garde les sorties alignées sur vos vrais composants."}, {"label": "Code → Design", "body": "Construisez et prévisualisez une fonctionnalité dans le navigateur, puis dites « Send this to Figma » pour capturer l’UI en cours d’exécution sous forme de calques Figma éditables — écran entier ou élément sélectionné."}]}, {"kind": "p", "text": "Installez-le une fois avec claude plugin install figma@claude-plugins-official (le MCP Dev Mode requiert un plan Figma payant). Le même Figma MCP est disponible pour Claude Code, Codex, Cursor et VS Code — exactement le genre de capacité portable et multi-agent qu’Open Design est conçu pour orchestrer."}]}, {"id": "vs", "heading": "Claude Code vs Codex vs Cursor pour le design", "blocks": [{"kind": "p", "text": "Il n’y a pas de vainqueur unique pour le travail de design — chaque agent a une force différente, et les équipes expérimentées les combinent. Un résumé équilibré :"}, {"kind": "table", "columns": ["Agent", "Force en design", "Idéal pour"], "rows": [["Claude Code", "Décisions de design précises (hex, espacement, typographie) et raisonnement UX conscient de la base de code", "Le raisonnement frontend et les refactors à large contexte"], ["Codex", "Forte finition visuelle et compréhension d’images ; builds async en sandbox", "Les builds async délégués et les règles AGENTS.md portables"], ["Cursor", "Boucle visuelle construire-et-voir avec aperçu en direct et éditions inline", "Le travail d’UI en boucle serrée d’itération au sein d’un IDE"]]}, {"kind": "p", "text": "Le verdict récurrent de la communauté est que le goût vient des humains : les trois retombent sur une esthétique générique sans skills, références et contraintes. C’est le vrai problème à résoudre — et il a la forme d’un outil de design, pas d’un modèle."}]}, {"id": "pitfalls", "heading": "Les pièges, et comment éviter le rendu « AI slop »", "blocks": [{"kind": "p", "text": "Malgré la réputation de goût de Claude Code, la critique la plus fréquente à l’égard du design généré par IA est qu’il a l’air générique — polices Inter, dégradés violets sur blanc, ombres douces, coins arrondis surdimensionnés, une esthétique qui « crie qu’une IA a fait ça ». Anthropic elle-même attribue cela à une convergence distributionnelle : les choix sûrs dominent les données d’entraînement du web. Parmi les autres problèmes signalés : des mises en page mobiles cassées et des instructions qui fuient dans les textes de l’UI."}, {"kind": "steps", "items": [{"label": "Installez la skill Frontend Design", "body": "Elle force Claude à s’engager sur une vraie direction et évite explicitement les polices et dégradés surexploités par l’IA."}, {"label": "Activez la vérification en navigateur", "body": "Faites en sorte que Claude rende et se contrôle lui-même sur les différents breakpoints pour que les mises en page ne cassent pas en silence sur mobile."}, {"label": "Fournissez tokens et références", "body": "De vrais tokens de design et des captures de référence sont le plus grand levier sur la qualité des sorties."}, {"label": "Encodez les règles dans CLAUDE.md", "body": "Mettez des règles de style comme « pas de hero cards, deux familles typographiques au maximum, hiérarchie qui met la marque d’abord » là où l’agent les lit à chaque exécution."}]}, {"kind": "p", "text": "Remarquez que chaque parade revient à donner à l’agent un contexte de design organisé. Maintenir ce contexte à la main, projet par projet, est le labeur qu’Open Design supprime."}]}, {"id": "open-design", "heading": "Concevoir avec Claude Code dans Open Design", "blocks": [{"kind": "p", "text": "Open Design est la couche de design open source que le workflow ci-dessus ne cesse de réclamer. Il traite Claude Code comme un adaptateur de première partie et l’entoure d’une bibliothèque organisée de skills et de design systems, d’un pipeline de rendu structuré et d’une UI desktop locale — pour que le contexte de design qui rend Claude Code bon soit présent dès la première exécution, et non assemblé à la main à chaque fois."}, {"kind": "ol", "items": ["Installez Open Design et sélectionnez Claude Code comme agent.", "Authentifiez-vous avec votre clé API Anthropic (BYOK) ou votre abonnement Claude — les identifiants restent sur votre machine et ne transitent jamais par nos serveurs.", "Choisissez un design system et une skill, puis générez des decks, des prototypes et des landing pages avec un goût cohérent.", "Chaque artefact et fichier DESIGN.md vit dans votre propre dépôt, pas dans un cloud hébergé."]}, {"kind": "p", "text": "Le même agent Claude Code, la même clé — auxquels s’ajoute un véritable workflow de design open source, portable, autour de lui. C’est local-first et Apache-2.0, donc rien de votre travail ni de vos identifiants ne quitte votre machine."}]}], "faqTitle": "Questions fréquentes", "faq": [{"name": "Claude Code est-il bon pour le travail de design ?", "text": "Oui — il est largement considéré comme l’agent de code au meilleur goût en frontend, prenant des décisions précises et conscientes de la base de code sur les valeurs hex, l’espacement et les échelles typographiques. Avec la skill Frontend Design, un design system et de vraies images de référence dans le contexte, il produit une UI responsive de qualité production et peut la vérifier dans un navigateur. Sans ce contexte, il a tendance à retomber sur un rendu générique, et c’est l’écart que comble Open Design."}, {"name": "Ai-je besoin d’un abonnement Claude pour concevoir avec Claude Code ?", "text": "Vous pouvez utiliser soit une clé API Anthropic (BYOK, via la Console), soit un abonnement Claude (Pro / Max). Dans les deux cas, Open Design ne fait jamais transiter vos identifiants — ils sont utilisés directement par votre agent sur votre machine."}, {"name": "Claude Code ou Codex pour le design frontend ?", "text": "Les deux sont solides. Claude Code est reconnu pour ses décisions de design précises et conscientes de la base de code et pour son raisonnement frontend ; Codex offre une forte finition visuelle et excelle dans les builds délégués en sandbox. Beaucoup d’équipes utilisent les deux — Open Design vous laisse changer d’agent sans changer votre workflow de design."}, {"name": "Comment connecter Claude Code à Figma ?", "text": "Installez le plugin Figma officiel avec claude plugin install figma@claude-plugins-official. Vous pouvez ensuite implémenter des frames Figma en code à partir du contexte de design, et renvoyer une UI en cours d’exécution vers des frames Figma éditables avec « Send this to Figma ». Le MCP Dev Mode requiert un plan Figma payant."}, {"name": "Que sont les Skills et CLAUDE.md ?", "text": "CLAUDE.md est un fichier markdown à la racine de votre projet que Claude Code lit au début de chaque session — l’endroit où encoder vos conventions de design. Les Skills regroupent des instructions et ressources réutilisables que Claude charge à la demande, y compris la skill officielle Frontend Design d’Anthropic. Open Design fournit une bibliothèque organisée des deux pour vous éviter la configuration projet par projet."}, {"name": "Comment éviter l’esthétique générique « AI slop » ?", "text": "Installez la skill Frontend Design, fournissez de vrais tokens de design et des captures de référence, encodez les règles de marque dans CLAUDE.md et activez la vérification en navigateur. Open Design les livre sous forme de bibliothèque organisée pour vous éviter la configuration projet par projet."}, {"name": "Open Design est-il affilié à Anthropic ?", "text": "Non. Claude Code est un produit d’Anthropic ; Open Design est un projet open source indépendant qui le prend en charge comme adaptateur de première partie. Claude et Claude Code sont des marques d’Anthropic."}, {"name": "Mes fichiers et identifiants sont-ils en sécurité ?", "text": "Oui — Open Design est local-first et Apache-2.0. Vos fichiers, artefacts et DESIGN.md restent dans votre propre dépôt, et vos identifiants Anthropic sont utilisés directement par votre agent, jamais routés via les serveurs d’Open Design."}], "ctaTitle": "Concevez avec Claude Code, à la manière ouverte.", "ctaBody": "Apportez votre propre clé Anthropic ou votre abonnement Claude, gardez chaque fichier en local et obtenez une bibliothèque de design organisée autour de l’agent que vous utilisez déjà.", "ctaActions": [{"label": "Utiliser Claude Code dans Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Star sur GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Télécharger l’application desktop", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Voir tous les agents pris en charge"},
      },
      'codex': {
        ...en['codex']!,
        title: "Codex pour le design — Open Design",
        description: "Comment on utilise OpenAI Codex pour le design d’interfaces et de sites web — le plugin Product Design, l’intégration Figma, les skills frontend — et comment Open Design en fait un agent de design open source et local-first.",
        breadcrumb: "Codex",
        label: "Agent · Codex",
        heading: "Codex pour le design.",
        lead: "Codex est l’agent de code d’OpenAI. Avec son plugin Product Design et son intégration Figma, il est devenu un véritable outil de design. Open Design branche Codex sur un workflow de design open source — votre clé OpenAI ou votre abonnement ChatGPT, vos fichiers, local-first.",
        rich: {"heroCtaLead": "Open Design transforme Codex en un agent de design open source et local-first — votre clé OpenAI, vos fichiers, et autour, une bibliothèque organisée de skills et de design systems.", "heroCtaActions": [{"label": "Utiliser Codex dans Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Star sur GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Télécharger l’application desktop", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["OpenAI Codex a démarré comme générateur de code, mais en 2026 il est devenu un outil crédible pour concevoir de vraies interfaces — à condition de lui donner les bonnes références, les bonnes skills et une boucle de vérification. Voici un guide pratique et complet pour utiliser Codex dans un travail d’UI, de frontend et de design system, et pour l’intégrer à un workflow de design structuré avec Open Design.", "Il couvre ce qu’est Codex aujourd’hui, pourquoi il est soudain bon en frontend, comment le configurer à partir de zéro, la boucle capture-vers-UI, l’aller-retour officiel avec Figma, sa comparaison avec Cursor et Claude Code, les pièges qui rendent les sorties d’IA génériques, et comment Open Design comble l’écart en tant que couche de design ouverte et local-first."], "heroImage": {"src": "/agents/codex-design/codex-design-workflow-loop.webp", "alt": "Boucle de rétroaction de design avec Codex : un agent en terminal, un navigateur affichant l’UI et un espace de travail, avec une flèche de rétroaction qui boucle", "caption": "La boucle centrale : Codex construit l’UI dans le terminal, la rend et la vérifie dans un vrai navigateur, et itère par rapport à vos références."}, "tocLabel": "Sur cette page", "toc": [{"id": "what-is-codex", "label": "Ce qu’est réellement OpenAI Codex"}, {"id": "why-design", "label": "Pourquoi Codex est bon en design désormais"}, {"id": "setup", "label": "Configurer Codex pour le design (à partir de zéro)"}, {"id": "screenshot-workflow", "label": "Le workflow capture-vers-UI"}, {"id": "figma", "label": "Aller-retour Codex + Figma"}, {"id": "vs", "label": "Codex vs Cursor vs Claude Code"}, {"id": "pitfalls", "label": "Les pièges et le rendu « AI slop »"}, {"id": "open-design", "label": "Concevoir avec Codex dans Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-codex", "heading": "Ce qu’est réellement OpenAI Codex (et ce qu’il n’est pas)", "blocks": [{"kind": "p", "text": "D’abord, une mise au point qui désarçonne presque tous ceux qui cherchent « Codex ». Le Codex d’OpenAI d’origine était un modèle de complétion de code de 2021 qui propulsait les premiers GitHub Copilot et a été déprécié en 2023. Ce n’est pas le sujet de cette page. Le Codex d’aujourd’hui est l’outil de code agentique d’OpenAI — il planifie, écrit, exécute et vérifie du code à partir de tâches en langage naturel."}, {"kind": "p", "text": "Le Codex moderne se décline sur quatre surfaces : une CLI en terminal (réécrite en Rust, sous licence Apache-2.0), une extension IDE pour VS Code, Cursor et Windsurf, une expérience cloud/web pour les tâches async déléguées, et une application desktop avec un navigateur intégré et Computer Use."}, {"kind": "steps", "items": [{"label": "Modèle par défaut", "body": "À la mi-2026, le modèle recommandé est gpt-5.5, gpt-5.4 étant le modèle qu’OpenAI a explicitement entraîné pour le frontend et l’usage de l’ordinateur."}, {"label": "Fichier d’instructions", "body": "Codex lit un fichier AGENTS.md dans votre projet (un standard inter-outils) pour les règles de projet — l’endroit naturel pour encoder vos conventions de design."}, {"label": "Sandbox", "body": "Il s’exécute dans un sandbox au niveau noyau (workspace-write par défaut), de sorte qu’un agent qui modifie votre UI ne peut pas sortir du projet."}]}, {"kind": "ul", "items": ["Éditeur : OpenAI", "Identifiant : clé API OpenAI (BYOK) ou abonnement ChatGPT (Free / Go / Plus / Pro / Business / Enterprise)", "Licence de la CLI : Apache-2.0, open source"]}]}, {"id": "why-design", "heading": "Pourquoi Codex est bon en design désormais", "blocks": [{"kind": "p", "text": "Trois choses ont convergé début 2026 pour faire de Codex un véritable outil de design plutôt qu’un générateur de code générique."}, {"kind": "steps", "items": [{"label": "Un modèle entraîné pour le frontend", "body": "OpenAI a livré GPT-5.4, son premier modèle mainline entraîné pour le frontend et l’usage de l’ordinateur, avec une bien meilleure compréhension d’images tout au long du workflow de design et une auto-vérification renforcée. Il peut même générer des mood boards et des options visuelles avant de s’engager sur les assets finaux."}, {"label": "Une skill frontend officielle", "body": "Le catalogue openai/skills fournit une frontend-skill organisée qui impose un vrai goût : des mises en page sans cartes, des héros pleine largeur, une hiérarchie qui met la marque d’abord, un mouvement sobre, deux familles typographiques et une couleur d’accent au maximum — et amène Codex à écrire une thèse visuelle avant de construire."}, {"label": "La vérification en navigateur", "body": "Avec la skill Playwright, Codex ouvre un vrai navigateur, redimensionne aux breakpoints et compare ses sorties à la référence au lieu de simplement vérifier que le build passe."}]}, {"kind": "image", "src": "/agents/codex-design/codex-design-taste-triangle.webp", "alt": "Schéma montrant un design system, une skill et une image de référence convergeant vers une bonne sortie de design", "caption": "Le goût vient de trois entrées que vous fournissez : un design system, une skill et de vraies images de référence."}, {"kind": "p", "text": "La leçon derrière ces trois points : Codex n’a pas de goût par défaut. Il produit de bons designs quand vous lui donnez des contraintes — un design system, une skill esthétique et des références concrètes. Open Design empaquette précisément ces entrées, et c’est pourquoi les deux s’accordent (plus de détails ci-dessous)."}]}, {"id": "setup", "heading": "Configurer Codex pour le design, à partir de zéro", "blocks": [{"kind": "p", "text": "Voici le parcours complet, d’une machine vierge à un Codex capable de construire et de vérifier des UI."}, {"kind": "code", "lang": "bash", "code": "# 1. Install the Codex CLI\nnpm install -g @openai/codex\n# or: brew install --cask codex\n# or: curl -fsSL https://chatgpt.com/codex/install.sh | sh\n\n# 2. Authenticate (ChatGPT sign-in recommended for higher limits)\ncodex            # then choose “Sign in with ChatGPT”\n\n# 3. Generate project context\ncodex            # inside your project, run /init to create AGENTS.md\n\n# 4. Add the official frontend skill, then restart Codex\n# (in the Codex app) $skill-installer frontend-skill\n\n# 5. Wire the Figma MCP server (optional, for design handoff)\ncodex mcp add figma --url https://mcp.figma.com/mcp"}, {"kind": "image", "src": "/agents/codex-design/codex-design-setup-flow.webp", "alt": "Flux de configuration en cinq étapes : installer, authentifier, configurer, installer la skill, vérifier", "caption": "La séquence de configuration : installer → authentifier → configurer AGENTS.md → installer la skill frontend → activer la vérification en navigateur."}, {"kind": "steps", "items": [{"label": "Encodez vos règles de design", "body": "Mettez vos tokens, primitives et conventions dans AGENTS.md ou un DESIGN.md et orientez Codex vers eux, pour que les sorties correspondent à une marque au lieu de retomber sur un rendu générique."}, {"label": "Choisissez le bon niveau de raisonnement", "body": "OpenAI note que les niveaux de raisonnement faibles à moyens produisent souvent de meilleurs résultats frontend que le réglage le plus élevé."}]}]}, {"id": "screenshot-workflow", "heading": "Le workflow capture-vers-UI", "blocks": [{"kind": "p", "text": "La boucle de design la plus efficace avec Codex consiste à transformer une image de référence en une UI fonctionnelle et responsive, puis à itérer jusqu’à ce qu’elle corresponde. Les recommandations d’OpenAI elles-mêmes se résument à cinq étapes."}, {"kind": "ol", "items": ["Partez des références visuelles les plus claires dont vous disposez — et incluez plusieurs états (desktop et mobile, survol, vide, chargement), pas seulement un visuel héros.", "Soyez précis dans le prompt ; des prompts vagues produisent une UI générique.", "Préparez un design system et indiquez à Codex où se trouvent les tokens et les primitives canoniques.", "Activez la skill interactive Playwright pour que Codex rende dans un vrai navigateur et redimensionne aux breakpoints.", "Itérez en faisant comparer à Codex son implémentation avec les captures — au lieu de simplement confirmer que ça build."]}, {"kind": "p", "text": "Fournissez les images en glissant une capture dans le terminal ou via le flag image, puis formulez le prompt avec des contraintes concrètes :"}, {"kind": "code", "lang": "bash", "code": "codex -i reference-desktop.png -i reference-mobile.png \\\n  \"Implement this design in React + Vite + Tailwind + TypeScript.\n   Reuse my existing design-system components and tokens.\n   Match spacing, layout, and hierarchy; make it responsive.\n   Use the Playwright skill to verify the UI matches the\n   references and iterate until it does.\""}, {"kind": "p", "text": "Faites tourner un serveur de dev dans un second terminal, gardez des prompts courts et ciblés, committez les bonnes itérations / annulez les mauvaises (en prévenant Codex quand vous revenez en arrière) pour que chaque passe parte d’une base propre."}]}, {"id": "figma", "heading": "Codex + Figma : aller-retour design ↔ code", "blocks": [{"kind": "p", "text": "En février 2026, OpenAI et Figma ont annoncé un partenariat officiel, transformant la précédente bêta du Figma MCP en une intégration bidirectionnelle de premier ordre. Elle fonctionne dans les deux sens."}, {"kind": "steps", "items": [{"label": "Design → Code", "body": "Copiez le « link to selection » d’une frame dans Figma, collez-le dans Codex avec get_design_context, et demandez-lui d’implémenter la maquette avec votre bibliothèque de composants existante."}, {"label": "Code → Design", "body": "L’outil generate_figma_design (« Code to Canvas ») retransforme une UI en cours d’exécution en frames Figma éditables — écran entier, élément sélectionné ou fichier complet."}]}, {"kind": "p", "text": "Le Figma MCP s’exécute comme un serveur distant et est exempté des limites de débit. Ajoutez-le une fois et il est disponible pour Codex, Claude Code, Cursor, VS Code et plus encore — exactement le genre de capacité portable et multi-agent qu’Open Design est conçu pour orchestrer."}]}, {"id": "vs", "heading": "Codex vs Cursor vs Claude Code pour le design", "blocks": [{"kind": "p", "text": "Il n’y a pas de vainqueur unique pour le travail de design — chaque agent a une force différente, et les équipes expérimentées les combinent. Un résumé équilibré :"}, {"kind": "table", "columns": ["Agent", "Force en design", "Idéal pour"], "rows": [["Codex", "Forte finition visuelle après GPT-5.4 + frontend-skill ; compréhension d’images", "Les builds async délégués, les exécutions en sandbox, les règles AGENTS.md portables"], ["Cursor", "Boucle visuelle construire-et-voir avec aperçu en direct et éditions inline", "Le travail d’UI en boucle serrée d’itération au sein d’un IDE"], ["Claude Code", "Décisions de design précises (hex, espacement, typographie) et UX consciente de la base de code", "Le raisonnement frontend et les refactors à large contexte"]]}, {"kind": "p", "text": "Le verdict récurrent de la communauté est que le goût vient des humains : les trois retombent sur une esthétique générique sans skills, références et contraintes. C’est le vrai problème à résoudre — et il a la forme d’un outil de design, pas d’un modèle."}]}, {"id": "pitfalls", "heading": "Les pièges, et comment éviter le rendu « AI slop »", "blocks": [{"kind": "p", "text": "La critique la plus fréquente à l’égard du design généré par Codex est qu’il a l’air générique — dégradés doux, panneaux flottants, coins arrondis surdimensionnés, ombres spectaculaires, une ambiance Inter-et-violet qui « crie qu’une IA a fait ça ». Parmi les autres problèmes signalés : des mises en page mobiles cassées, des instructions qui fuient dans les textes de l’UI et des limites d’usage atteintes rapidement."}, {"kind": "steps", "items": [{"label": "Installez une skill frontend", "body": "Une skill esthétique organisée force Codex à s’engager sur une vraie direction au lieu du rendu par défaut."}, {"label": "Activez la vérification Playwright", "body": "Faites en sorte que Codex rende et se contrôle lui-même sur les différents breakpoints pour que les mises en page ne cassent pas en silence sur mobile."}, {"label": "Fournissez tokens et références", "body": "De vrais tokens de design et des captures de référence sont le plus grand levier sur la qualité des sorties."}, {"label": "Encodez les règles dans AGENTS.md", "body": "Mettez des règles de style comme « pas de hero cards, deux familles typographiques au maximum, hiérarchie qui met la marque d’abord » là où l’agent les lit à chaque exécution."}]}, {"kind": "p", "text": "Remarquez que chaque parade revient à donner à l’agent un contexte de design organisé. Maintenir ce contexte à la main, projet par projet, est le labeur qu’Open Design supprime."}]}, {"id": "open-design", "heading": "Concevoir avec Codex dans Open Design", "blocks": [{"kind": "p", "text": "Open Design est la couche de design open source que le workflow ci-dessus ne cesse de réclamer. Il traite Codex comme un adaptateur de première partie et l’entoure d’une bibliothèque organisée de skills et de design systems, d’un pipeline de rendu structuré et d’une UI desktop locale — pour que le contexte de design qui rend Codex bon soit présent dès la première exécution, et non assemblé à la main à chaque fois."}, {"kind": "ol", "items": ["Installez Open Design et sélectionnez Codex comme agent.", "Authentifiez-vous avec votre clé API OpenAI (BYOK) ou votre abonnement ChatGPT — les identifiants restent sur votre machine et ne transitent jamais par nos serveurs.", "Choisissez un design system et une skill, puis générez des decks, des prototypes et des landing pages avec un goût cohérent.", "Chaque artefact et fichier DESIGN.md vit dans votre propre dépôt, pas dans un cloud hébergé."]}, {"kind": "p", "text": "Le même agent Codex, la même clé — auxquels s’ajoute un véritable workflow de design open source, portable, autour de lui. C’est local-first et Apache-2.0, donc rien de votre travail ni de vos identifiants ne quitte votre machine."}]}], "faqTitle": "Questions fréquentes", "faq": [{"name": "OpenAI Codex peut-il vraiment faire du travail de design ?", "text": "Oui — avec une skill frontend, un design system et de vraies images de référence dans le contexte, Codex (surtout sur GPT-5.4) produit une UI responsive de qualité production et peut la vérifier dans un navigateur. Sans ce contexte, il a tendance à retomber sur un rendu générique, et c’est l’écart que comble Open Design."}, {"name": "S’agit-il du plugin Product Design d’OpenAI Codex ?", "text": "Non. Open Design est un projet open source indépendant qui intègre Codex comme agent. Il complète l’outillage propre d’OpenAI avec une bibliothèque de skills et de design systems ouverte et local-first."}, {"name": "Ai-je besoin d’un abonnement ChatGPT pour concevoir avec Codex ?", "text": "Vous pouvez utiliser soit une clé API OpenAI (BYOK), soit votre abonnement ChatGPT. La connexion ChatGPT offre généralement des limites plus généreuses ; Open Design ne fait jamais transiter vos identifiants, dans les deux cas."}, {"name": "Codex ou Claude Code pour le design frontend ?", "text": "Les deux sont solides. Claude Code est reconnu pour ses décisions de design précises et conscientes de la base de code ; Codex offre une forte finition visuelle après GPT-5.4 et excelle dans les builds délégués en sandbox. Beaucoup d’équipes utilisent les deux — Open Design vous laisse changer d’agent sans changer votre workflow de design."}, {"name": "Comment connecter Codex à Figma ?", "text": "Ajoutez le serveur Figma MCP officiel (codex mcp add figma --url https://mcp.figma.com/mcp). Vous pouvez ensuite implémenter des frames Figma en code avec get_design_context et renvoyer une UI en cours d’exécution vers des frames Figma éditables avec generate_figma_design."}, {"name": "Comment éviter l’esthétique générique « AI slop » ?", "text": "Installez une skill frontend, fournissez de vrais tokens de design et des captures de référence, encodez les règles de marque dans AGENTS.md et activez la vérification Playwright. Open Design les livre sous forme de bibliothèque organisée pour vous éviter la configuration projet par projet."}, {"name": "Open Design est-il affilié à OpenAI ?", "text": "Non. Codex est un produit d’OpenAI ; Open Design est un projet open source indépendant qui le prend en charge comme adaptateur de première partie. OpenAI et Codex sont des marques d’OpenAI."}, {"name": "Mes fichiers et identifiants sont-ils en sécurité ?", "text": "Oui — Open Design est local-first. Vos fichiers, artefacts et DESIGN.md restent dans votre propre dépôt, et vos identifiants OpenAI sont utilisés directement par votre agent, jamais routés via les serveurs d’Open Design."}], "ctaTitle": "Concevez avec Codex, à la manière ouverte.", "ctaBody": "Apportez votre propre clé OpenAI, gardez chaque fichier en local et obtenez une bibliothèque de design organisée autour de l’agent que vous utilisez déjà.", "ctaActions": [{"label": "Utiliser Codex dans Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Star sur GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Télécharger l’application desktop", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Voir tous les agents pris en charge"},
      },
      'cursor': {
        ...en['cursor']!,
        title: "Cursor pour les designers — Open Design",
        description: "Comment les designers utilisent Cursor pour le design d’interfaces et de sites web — le Design Mode, Figma-vers-code, le Figma MCP — et comment Open Design en fait un agent de design open source et local-first.",
        breadcrumb: "Cursor",
        label: "Agent · Cursor",
        heading: "Cursor pour les designers.",
        lead: "Cursor est l’éditeur de code IA, désormais doté d’un Design Mode visuel. Les designers l’utilisent pour modifier l’UI en pointant et en dessinant, et pour transformer Figma en code. Open Design branche Cursor Agent sur un workflow de design open source qui garde vos fichiers en local.",
        rich: {"heroCtaLead": "Open Design transforme Cursor en un agent de design open source et local-first — votre compte Cursor ou vos clés de modèle, vos fichiers, et autour, une bibliothèque organisée de skills et de design systems.", "heroCtaActions": [{"label": "Utiliser Cursor dans Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Star sur GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Télécharger l’application desktop", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Cursor est l’éditeur de code IA-first qui a fait de « construire et regarder le rendu » la façon par défaut de livrer de l’UI. Avec le mode Agent, les éditions inline, un aperçu intégré à l’éditeur et Figma via MCP, il est devenu un véritable outil de design — à condition de lui donner les bonnes références, les bonnes règles et une boucle de vérification. Voici un guide pratique et complet pour utiliser Cursor dans un travail d’UI, de frontend et de design system, et pour l’intégrer à un workflow de design structuré avec Open Design.", "Il couvre ce qu’est réellement Cursor, pourquoi sa boucle serrée d’itération est bonne pour le design, comment le configurer à partir de zéro, la boucle capture-et-aperçu-vers-UI, l’aller-retour Figma via MCP, sa comparaison avec Codex et Claude Code, les pièges qui rendent les sorties d’IA génériques, et comment Open Design comble l’écart en tant que couche de design ouverte et local-first."], "heroImage": {"src": "/agents/cursor-design/cursor-design-hero.webp", "alt": "Convergence de design avec Cursor : l’éditeur à gauche, un hub organisé de skills et de design systems au centre avec la marque Cursor au milieu, et une UI rendue à droite", "caption": "L’idée centrale : Cursor modifie et affiche l’UI dans l’éditeur, tandis qu’un hub de design organisé lui fournit le système, les skills et les références qui font paraître les sorties intentionnelles."}, "tocLabel": "Sur cette page", "toc": [{"id": "what-is-cursor", "label": "Ce qu’est réellement Cursor"}, {"id": "why-design", "label": "Pourquoi Cursor est bon en design"}, {"id": "setup", "label": "Configurer Cursor pour le design (à partir de zéro)"}, {"id": "preview-workflow", "label": "Le workflow aperçu-vers-UI"}, {"id": "figma", "label": "Cursor + Figma via MCP"}, {"id": "vs", "label": "Cursor vs Codex vs Claude Code"}, {"id": "pitfalls", "label": "Les pièges et le rendu « AI slop »"}, {"id": "open-design", "label": "Concevoir avec Cursor dans Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-cursor", "heading": "Ce qu’est réellement Cursor", "blocks": [{"kind": "p", "text": "Cursor est un éditeur de code IA-first conçu par Anysphere. C’est un fork de VS Code, il conserve donc l’éditeur, les extensions et les raccourcis clavier familiers, mais reconstruit le workflow autour d’un agent IA capable de lire tout votre projet, de modifier plusieurs fichiers, d’exécuter des commandes et d’itérer avec vous dans la boucle."}, {"kind": "p", "text": "Pour le travail de design, les surfaces importantes sont le mode Agent (vous décrivez un résultat et Cursor planifie et modifie à travers les fichiers), les éditions inline et les complétions Tab pour des ajustements rapides, un aperçu / navigateur intégré à l’éditeur pour voir l’UI en cours d’exécution sans quitter la fenêtre, et le support MCP qui lui permet d’intégrer du contexte externe comme un fichier Figma en direct."}, {"kind": "steps", "items": [{"label": "Règles de projet", "body": "Cursor lit des fichiers d’instructions de projet — des règles `.mdc` versionnées sous `.cursor/rules`, et un simple `AGENTS.md` — pour que vous puissiez encoder vos conventions de design là où l’agent les lit à chaque exécution."}, {"label": "Modèles", "body": "Cursor est flexible côté modèles : il est livré avec des modèles de pointe via votre abonnement et prend aussi en charge l’apport de vos propres clés de modèle, vous choisissez donc le moteur derrière le même workflow d’éditeur."}, {"label": "MCP", "body": "Il parle le Model Context Protocol, de sorte que des serveurs externes — le plus pertinent étant le serveur Figma MCP — deviennent un contexte de premier ordre pour l’agent."}]}, {"kind": "ul", "items": ["Éditeur : Anysphere", "Identifiant : compte / abonnement Cursor (Hobby / Pro / Business) ou vos propres clés de modèle (BYOK)", "Forme : éditeur de code IA-first (fork de VS Code) avec un agent et un aperçu intégrés à l’éditeur"]}]}, {"id": "why-design", "heading": "Pourquoi Cursor est bon en design", "blocks": [{"kind": "p", "text": "L’avantage de Cursor en design n’est pas une fonctionnalité unique — c’est la rapidité de la boucle construire-et-voir. Trois choses le font ressembler à un outil de design plutôt qu’à un générateur de code générique."}, {"kind": "steps", "items": [{"label": "Une boucle d’itération serrée", "body": "Vous donnez un prompt, Cursor modifie à travers les fichiers, et l’aperçu intégré à l’éditeur affiche le résultat immédiatement — vous ajustez ainsi l’espacement, la hiérarchie et le mouvement en quelques secondes au lieu de faire des allers-retours entre un terminal et un navigateur séparés."}, {"label": "L’édition visuelle directe", "body": "Au-delà du chat, Cursor vous laisse sélectionner des éléments dans l’aperçu et ajuster les styles, de sorte que les petites corrections visuelles ressemblent à des éditions de design plutôt qu’à de l’archéologie de code."}, {"label": "Règles de projet et contexte MCP", "body": "Avec `.cursor/rules` (ou `AGENTS.md`) et le serveur Figma MCP, l’agent travaille par rapport à vos tokens, composants et vraies specs de design au lieu de deviner."}]}, {"kind": "image", "src": "/agents/cursor-design/cursor-design-taste-triangle.webp", "alt": "Schéma montrant un design system, une skill et une image de référence convergeant vers une bonne sortie de design", "caption": "Le goût vient de trois entrées que vous fournissez : un design system, une skill et de vraies images de référence."}, {"kind": "p", "text": "La leçon est la même que celle que tout agent enseigne : Cursor n’a pas de goût par défaut. Il produit de bons designs quand vous lui donnez des contraintes — un design system, une skill esthétique et des références concrètes. Open Design empaquette précisément ces entrées, et c’est pourquoi les deux s’accordent (plus de détails ci-dessous)."}]}, {"id": "setup", "heading": "Configurer Cursor pour le design, à partir de zéro", "blocks": [{"kind": "p", "text": "Voici le parcours complet, d’une machine vierge à un Cursor capable de construire, prévisualiser et vérifier l’UI par rapport à votre design system."}, {"kind": "ol", "items": ["Installez Cursor depuis cursor.com et connectez-vous avec votre compte Cursor, ou configurez vos propres clés de modèle (BYOK) dans les Réglages.", "Ouvrez votre projet et choisissez un modèle dans le panneau chat / Agent.", "Ajoutez des règles de projet : créez `.cursor/rules/*.mdc` pour des conventions structurées et délimitées par glob, ou un simple `AGENTS.md` pour des instructions simples et lisibles.", "Connectez le serveur Figma MCP (optionnel) pour que l’agent puisse lire le contexte de design en direct.", "Faites tourner votre serveur de dev et utilisez l’aperçu intégré à l’éditeur pour voir et vérifier l’UI au fil de vos itérations."]}, {"kind": "image", "src": "/agents/cursor-design/cursor-design-setup-flow.webp", "alt": "Flux de configuration en cinq étapes : installer, authentifier, configurer les règles, ajouter une skill, vérifier", "caption": "La séquence de configuration : installer → authentifier → configurer les règles de projet → ajouter une skill → activer la vérification par aperçu."}, {"kind": "p", "text": "Un fichier de règles de projet minimal amène l’agent à concevoir pour une marque au lieu de retomber sur un rendu générique. Placez-le là où Cursor le lit à chaque exécution :"}, {"kind": "code", "lang": "markdown", "code": "# .cursor/rules/design.mdc\n---\ndescription: Project design conventions\nalwaysApply: true\n---\n\n- Reuse existing design-system tokens and components; never hardcode hex or spacing.\n- At most two typefaces and one accent color.\n- Brand-first hierarchy; restrained motion. No hero cards, no oversized rounded corners.\n- Build responsive by default; verify desktop and mobile in the preview before finishing."}, {"kind": "steps", "items": [{"label": "Encodez vos règles de design", "body": "Mettez vos tokens, primitives et conventions dans `.cursor/rules` ou `AGENTS.md` et orientez Cursor vers eux, pour que les sorties correspondent à une marque au lieu de retomber sur un rendu générique."}, {"label": "Gardez des prompts courts", "body": "La boucle serrée de Cursor récompense les demandes ciblées — itérez un composant ou un état à la fois et observez l’aperçu entre chaque passe."}]}]}, {"id": "preview-workflow", "heading": "Le workflow aperçu-vers-UI", "blocks": [{"kind": "p", "text": "La boucle de design la plus efficace avec Cursor consiste à transformer une référence en une UI fonctionnelle et responsive, puis à itérer dans l’éditeur jusqu’à ce qu’elle corresponde — en observant l’aperçu en direct tout du long au lieu de deviner."}, {"kind": "ol", "items": ["Partez des références visuelles les plus claires dont vous disposez — et incluez plusieurs états (desktop et mobile, survol, vide, chargement), pas seulement un visuel héros.", "Soyez précis dans le prompt ; des prompts vagues produisent une UI générique.", "Préparez un design system et indiquez à Cursor où se trouvent les tokens et les primitives canoniques.", "Gardez l’aperçu intégré à l’éditeur ouvert et votre serveur de dev en route pour que chaque édition s’affiche immédiatement aux breakpoints qui vous importent.", "Itérez en comparant l’UI rendue avec les références — et utilisez la sélection directe d’éléments dans l’aperçu pour les petites corrections visuelles."]}, {"kind": "p", "text": "Fournissez les références en attachant une image au chat, puis formulez le prompt avec des contraintes concrètes :"}, {"kind": "code", "lang": "text", "code": "Implement this design in React + Vite + Tailwind + TypeScript.\nReuse my existing design-system components and tokens.\nMatch spacing, layout, and hierarchy; make it responsive.\nKeep the preview open — verify desktop and mobile match the\nreferences and iterate until they do."}, {"kind": "p", "text": "Committez les bonnes itérations et annulez les mauvaises (en prévenant Cursor quand vous revenez en arrière) pour que chaque passe parte d’une base propre — la même discipline qui empêche toute boucle d’agent de dériver."}]}, {"id": "figma", "heading": "Cursor + Figma : design ↔ code via MCP", "blocks": [{"kind": "p", "text": "Cursor se connecte à Figma via le serveur Figma MCP officiel, qui donne à l’agent un accès structuré à un fichier Figma en direct au lieu d’une capture à plat. Cela retire le tâtonnement du handoff."}, {"kind": "steps", "items": [{"label": "Design → Code", "body": "Copiez le lien d’une frame dans Figma, collez-le dans Cursor et demandez-lui d’implémenter la maquette. Le serveur MCP expose un vrai contexte de design — composants, variables, données de mise en page, tokens — pour que le code généré corresponde à la source au lieu de l’approximer."}, {"label": "Restez aligné", "body": "Avec des design tokens, des styles et des composants utilisés de manière cohérente dans Figma (et Code Connect là où c’est disponible), les sorties de Cursor restent mappées sur votre vrai design system plutôt que de réinventer des primitives."}]}, {"kind": "p", "text": "Configurez le serveur Figma MCP distant une fois et il est disponible pour Cursor en tant que contexte de premier ordre. Comme MCP est un standard ouvert, le même serveur est réutilisable à travers Cursor, Claude Code, Codex et VS Code — exactement le genre de capacité portable et multi-agent qu’Open Design est conçu pour orchestrer."}]}, {"id": "vs", "heading": "Cursor vs Codex vs Claude Code pour le design", "blocks": [{"kind": "p", "text": "Il n’y a pas de vainqueur unique pour le travail de design — chaque agent a une force différente, et les équipes expérimentées les combinent. Un résumé équilibré :"}, {"kind": "table", "columns": ["Agent", "Force en design", "Idéal pour"], "rows": [["Cursor", "Boucle visuelle construire-et-voir avec aperçu en direct dans l’éditeur et édition directe des éléments", "Le travail d’UI en boucle serrée d’itération au sein d’un IDE"], ["Codex", "Forte finition visuelle avec une skill frontend ; compréhension d’images et exécutions en sandbox", "Les builds async délégués et les règles AGENTS.md portables"], ["Claude Code", "Décisions de design précises (hex, espacement, typographie) et UX consciente de la base de code", "Le raisonnement frontend et les refactors à large contexte"]]}, {"kind": "p", "text": "Le verdict récurrent de la communauté est que le goût vient des humains : les trois retombent sur une esthétique générique sans skills, références et contraintes. C’est le vrai problème à résoudre — et il a la forme d’un outil de design, pas d’un modèle."}]}, {"id": "pitfalls", "heading": "Les pièges, et comment éviter le rendu « AI slop »", "blocks": [{"kind": "p", "text": "La critique la plus fréquente à l’égard du design généré par Cursor est qu’il a l’air générique — dégradés doux, panneaux flottants, coins arrondis surdimensionnés, ombres spectaculaires, une ambiance Inter-et-violet qui « crie qu’une IA a fait ça ». Parmi les autres problèmes signalés : des mises en page qui cassent sur mobile et des instructions qui fuient dans les textes de l’UI."}, {"kind": "steps", "items": [{"label": "Ajoutez une skill de design", "body": "Une skill esthétique organisée force Cursor à s’engager sur une vraie direction au lieu du rendu par défaut."}, {"label": "Utilisez l’aperçu pour vérifier", "body": "Rendez et auto-contrôlez sur les différents breakpoints dans l’aperçu intégré à l’éditeur pour que les mises en page ne cassent pas en silence sur mobile."}, {"label": "Fournissez tokens et références", "body": "De vrais tokens de design et des captures de référence sont le plus grand levier sur la qualité des sorties."}, {"label": "Encodez les règles dans `.cursor/rules`", "body": "Mettez des règles de style comme « pas de hero cards, deux familles typographiques au maximum, hiérarchie qui met la marque d’abord » là où l’agent les lit à chaque exécution."}]}, {"kind": "p", "text": "Remarquez que chaque parade revient à donner à l’agent un contexte de design organisé. Maintenir ce contexte à la main, projet par projet, est le labeur qu’Open Design supprime."}]}, {"id": "open-design", "heading": "Concevoir avec Cursor dans Open Design", "blocks": [{"kind": "p", "text": "Open Design est la couche de design open source que le workflow ci-dessus ne cesse de réclamer. Il traite Cursor comme un adaptateur de première partie et l’entoure d’une bibliothèque organisée de skills et de design systems, d’un pipeline de rendu structuré et d’une UI desktop locale — pour que le contexte de design qui rend Cursor bon soit présent dès la première exécution, et non assemblé à la main à chaque fois."}, {"kind": "ol", "items": ["Installez Open Design et sélectionnez Cursor comme agent.", "Authentifiez-vous avec votre compte Cursor ou vos propres clés de modèle (BYOK) — les identifiants restent sur votre machine et ne transitent jamais par nos serveurs.", "Choisissez un design system et une skill, puis générez des decks, des prototypes et des landing pages avec un goût cohérent.", "Chaque artefact et fichier DESIGN.md vit dans votre propre dépôt, pas dans un cloud hébergé."]}, {"kind": "p", "text": "Le même agent Cursor, la même clé — auxquels s’ajoute un véritable workflow de design open source, portable, autour de lui. C’est local-first et Apache-2.0, donc rien de votre travail ni de vos identifiants ne quitte votre machine."}]}], "faqTitle": "Questions fréquentes", "faq": [{"name": "Cursor peut-il vraiment faire du travail de design ?", "text": "Oui — avec une skill de design, un design system et de vraies images de référence dans le contexte, Cursor produit une UI responsive de qualité production, et son aperçu intégré à l’éditeur vous laisse la vérifier et l’affiner visuellement. Sans ce contexte, il a tendance à retomber sur un rendu générique, et c’est l’écart que comble Open Design."}, {"name": "Est-ce un produit officiel de Cursor ?", "text": "Non. Open Design est un projet open source indépendant qui intègre Cursor comme agent. Il complète Cursor avec une bibliothèque de skills et de design systems ouverte et local-first."}, {"name": "Ai-je besoin d’un abonnement Cursor pour concevoir avec Cursor ?", "text": "Vous pouvez utiliser un compte / abonnement Cursor ou apporter vos propres clés de modèle (BYOK). Open Design ne fait jamais transiter vos identifiants, dans les deux cas — ils sont utilisés directement par votre agent."}, {"name": "Cursor ou Claude Code pour le design frontend ?", "text": "Les deux sont solides. Claude Code est reconnu pour ses décisions de design précises et conscientes de la base de code ; l’avantage de Cursor est sa boucle serrée construire-et-voir avec un aperçu en direct au sein de l’éditeur. Beaucoup d’équipes utilisent les deux — Open Design vous laisse changer d’agent sans changer votre workflow de design."}, {"name": "Comment connecter Cursor à Figma ?", "text": "Ajoutez le serveur Figma MCP officiel dans Cursor, puis collez un lien de frame Figma dans le chat et demandez à Cursor de l’implémenter. Le serveur expose de vrais composants, variables et données de mise en page pour que le code généré corresponde à la maquette source."}, {"name": "Comment éviter l’esthétique générique « AI slop » ?", "text": "Ajoutez une skill de design, fournissez de vrais tokens de design et des captures de référence, encodez les règles de marque dans `.cursor/rules` ou `AGENTS.md`, et vérifiez sur les différents breakpoints dans l’aperçu. Open Design les livre sous forme de bibliothèque organisée pour vous éviter la configuration projet par projet."}, {"name": "Open Design est-il affilié à Cursor ou Anysphere ?", "text": "Non. Cursor est un produit d’Anysphere ; Open Design est un projet open source indépendant qui le prend en charge comme adaptateur de première partie. Cursor et Anysphere sont des marques d’Anysphere, Inc."}, {"name": "Mes fichiers et identifiants sont-ils en sécurité ?", "text": "Oui — Open Design est local-first. Vos fichiers, artefacts et DESIGN.md restent dans votre propre dépôt, et vos identifiants Cursor ou de modèle sont utilisés directement par votre agent, jamais routés via les serveurs d’Open Design."}], "ctaTitle": "Concevez avec Cursor, à la manière ouverte.", "ctaBody": "Apportez votre propre compte Cursor ou vos clés de modèle, gardez chaque fichier en local et obtenez une bibliothèque de design organisée autour de l’agent que vous utilisez déjà.", "ctaActions": [{"label": "Utiliser Cursor dans Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Star sur GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Télécharger l’application desktop", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Voir tous les agents pris en charge"},
      },
      'opencode': {
        ...en['opencode']!,
        title: "OpenCode pour le design — Open Design",
        description: "Comment on utilise OpenCode pour le design d’interfaces et de sites web — les fichiers design.md, les skills UI/UX, le Figma MCP — et comment Open Design en fait un agent de design open source et local-first.",
        breadcrumb: "OpenCode",
        label: "Agent · OpenCode",
        heading: "OpenCode pour le design.",
        lead: "OpenCode est l’agent de code IA en terminal, open source. Les designers lui ajoutent des skills de design et des fichiers DESIGN.md pour générer de vraies UI. Open Design en fait un workflow structuré et open source — apportez vos clés de fournisseur, gardez tout en local.",
        rich: {"heroCtaLead": "Open Design transforme OpenCode en un agent de design open source et local-first — n’importe quel modèle de votre choix avec votre propre clé de fournisseur, vos fichiers, et autour, une bibliothèque organisée de skills et de design systems.", "heroCtaActions": [{"label": "Utiliser OpenCode dans Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Star sur GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Télécharger l’application desktop", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["OpenCode est un agent de code IA open source, pensé d’abord pour le terminal et délibérément agnostique au modèle : vous apportez votre propre clé de fournisseur et exécutez le modèle de votre choix derrière le même workflow. Cette ouverture en fait une base naturelle pour le travail de design — mais, comme tout agent, il ne produit de bonnes UI que si vous lui donnez les bonnes références, les bonnes skills et une boucle de vérification. Voici un guide pratique et complet pour utiliser OpenCode dans un travail d’UI, de frontend et de design system, et pour l’intégrer à un workflow de design structuré avec Open Design.", "Il couvre ce qu’est réellement OpenCode, pourquoi un agent ouvert et agnostique au modèle convient au design, comment le configurer à partir de zéro, la boucle capture-vers-UI, comment AGENTS.md et MCP l’étendent, sa comparaison avec Codex, Claude Code et Cursor, les pièges qui rendent les sorties d’IA génériques, et comment Open Design comble l’écart en tant que couche de design ouverte et local-first — un appariement naturel, puisque les deux projets sont open source et s’exécutent sur votre propre machine."], "heroImage": {"src": "/agents/opencode-design/opencode-design-hero.webp", "alt": "Boucle de rétroaction de design avec OpenCode : un agent TUI en terminal, un navigateur affichant l’UI et un espace de travail, avec une flèche de rétroaction qui boucle", "caption": "La boucle centrale : OpenCode construit l’UI dans le terminal, la rend et la vérifie dans un vrai navigateur, et itère par rapport à vos références — sur le modèle de votre choix."}, "tocLabel": "Sur cette page", "toc": [{"id": "what-is-opencode", "label": "Ce qu’est réellement OpenCode"}, {"id": "why-design", "label": "Pourquoi un agent ouvert et tout-modèle convient au design"}, {"id": "setup", "label": "Configurer OpenCode pour le design (à partir de zéro)"}, {"id": "screenshot-workflow", "label": "Le workflow capture-vers-UI"}, {"id": "extend", "label": "AGENTS.md, MCP et sessions partageables"}, {"id": "vs", "label": "OpenCode vs Codex vs Claude Code vs Cursor"}, {"id": "pitfalls", "label": "Les pièges et le rendu « AI slop »"}, {"id": "open-design", "label": "Concevoir avec OpenCode dans Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-opencode", "heading": "Ce qu’est réellement OpenCode", "blocks": [{"kind": "p", "text": "OpenCode est un agent de code IA open source conçu pour le terminal, maintenu par l’équipe derrière SST (Anomaly Innovations). Il lit votre dépôt, exécute des commandes, modifie des fichiers et dialogue avec un grand modèle de langage — mais, contrairement aux agents liés à un éditeur, il ne fournit pas son propre modèle. Vous le pointez vers le fournisseur et le modèle de votre choix et apportez votre propre clé."}, {"kind": "p", "text": "Il s’exécute comme une UI en terminal (TUI), avec une application desktop et des extensions IDE par-dessus le même moteur. Sous le capot, il utilise une architecture client/serveur, de sorte que l’agent qui fait le travail est découplé de la surface depuis laquelle vous le pilotez. Deux agents intégrés — build et plan — se basculent avec la touche Tab."}, {"kind": "steps", "items": [{"label": "Agnostique au modèle", "body": "Les modèles et fournisseurs proviennent de models.dev, un catalogue ouvert. Vous les configurez dans opencode.json avec une chaîne provider/model-id et pouvez désactiver les fournisseurs que vous ne voulez pas charger — le même workflow de design s’exécute ainsi sur Anthropic, OpenAI, Google, OpenRouter, des modèles locaux et plus encore."}, {"label": "Fichier d’instructions", "body": "OpenCode lit un fichier AGENTS.md dans votre projet (le standard inter-outils, également compatible avec CLAUDE.md) pour les règles de projet — l’endroit naturel pour encoder vos conventions de design. Exécutez /init pour en générer un."}, {"label": "Extensible", "body": "Il prend en charge l’intégration LSP, les serveurs MCP, les thèmes, les raccourcis clavier et les commandes personnalisées, ainsi que des liens de session partageables pour la collaboration."}]}, {"kind": "ul", "items": ["Mainteneur : SST / Anomaly Innovations (projet open source)", "Identifiant : votre/vos propre(s) clé(s) API de fournisseur de modèle — BYOK, sans verrouillage par l’éditeur", "Licence : MIT, open source"]}]}, {"id": "why-design", "heading": "Pourquoi un agent ouvert et tout-modèle convient au travail de design", "blocks": [{"kind": "p", "text": "OpenCode n’a pas un unique « modèle de design » comme en a un agent d’éditeur — et c’est tout l’intérêt. Parce qu’il est agnostique au modèle et ouvert, vous pouvez exécuter le même workflow de design sur le modèle actuellement le meilleur en frontend, en changer plus tard, ou vous rabattre sur un modèle local, le tout sans modifier votre configuration."}, {"kind": "p", "text": "Mais le choix du modèle seul n’achète pas le goût. Comme tout agent de code, OpenCode produit une UI générique tant que vous ne lui donnez pas de contraintes. Une bonne sortie de design provient de trois entrées que vous fournissez."}, {"kind": "steps", "items": [{"label": "Un design system", "body": "De vrais tokens, primitives et conventions que l’agent réutilise, pour que les sorties correspondent à une marque au lieu de retomber sur un rendu générique."}, {"label": "Une skill esthétique", "body": "Une skill organisée qui impose un vrai goût — mouvement sobre, hiérarchie qui met la marque d’abord, deux familles typographiques et une couleur d’accent au maximum — et amène l’agent à s’engager sur une direction avant de construire."}, {"label": "Des références concrètes", "body": "De vraies images de référence et plusieurs états (desktop et mobile, survol, vide, chargement), pas un unique visuel héros."}]}, {"kind": "image", "src": "/agents/opencode-design/opencode-design-taste-triangle.webp", "alt": "Schéma montrant un design system, une skill et une image de référence convergeant vers une bonne sortie de design", "caption": "Le goût vient de trois entrées que vous fournissez : un design system, une skill et de vraies images de référence — indépendamment du modèle que vous exécutez."}, {"kind": "p", "text": "La leçon : OpenCode vous donne la liberté du modèle, mais le goût vient toujours d’un contexte de design organisé. Open Design empaquette précisément ces entrées, et c’est pourquoi les deux s’accordent — tous deux sont open source et local-first (plus de détails ci-dessous)."}]}, {"id": "setup", "heading": "Configurer OpenCode pour le design, à partir de zéro", "blocks": [{"kind": "p", "text": "Voici le parcours complet, d’une machine vierge à un OpenCode capable de construire et de vérifier des UI."}, {"kind": "code", "lang": "bash", "code": "# 1. Install OpenCode\ncurl -fsSL https://opencode.ai/install | bash\n# or: npm i -g opencode-ai@latest\n# or: brew install sst/tap/opencode\n\n# 2. Start the TUI in your project, then authenticate your provider\nopencode          # then run /login and pick your provider + paste your key\n\n# 3. Generate project context\nopencode          # inside your project, run /init to create AGENTS.md\n\n# 4. Pick your model (any provider, via models.dev)\n#    set \"provider/model-id\" in opencode.json or switch in the TUI\n\n# 5. Add an MCP server (optional, e.g. for design handoff)\n#    configure it under the \"mcp\" key in opencode.json"}, {"kind": "image", "src": "/agents/opencode-design/opencode-design-setup-flow.webp", "alt": "Flux de configuration en cinq étapes : installer, authentifier avec votre clé de fournisseur, configurer AGENTS.md, ajouter une skill, vérifier", "caption": "La séquence de configuration : installer → authentifier (votre clé de fournisseur) → configurer AGENTS.md → ajouter une skill → vérifier dans un vrai navigateur."}, {"kind": "steps", "items": [{"label": "Encodez vos règles de design", "body": "Mettez vos tokens, primitives et conventions dans AGENTS.md (ou un DESIGN.md référencé depuis lui) pour que les sorties correspondent à une marque au lieu de retomber sur un rendu générique. L’option instructions dans opencode.json peut pointer vers des fichiers de règles supplémentaires via des globs."}, {"label": "Choisissez un modèle capable", "body": "Parce qu’OpenCode est agnostique au modèle, choisissez le fournisseur/modèle actuellement le plus fort en frontend pour la passe de design — et gardez le reste de votre workflow inchangé."}]}]}, {"id": "screenshot-workflow", "heading": "Le workflow capture-vers-UI", "blocks": [{"kind": "p", "text": "La boucle de design la plus efficace avec n’importe quel agent consiste à transformer une image de référence en une UI fonctionnelle et responsive, puis à itérer jusqu’à ce qu’elle corresponde. La même structure en cinq étapes s’applique dans OpenCode."}, {"kind": "ol", "items": ["Partez des références visuelles les plus claires dont vous disposez — et incluez plusieurs états (desktop et mobile, survol, vide, chargement), pas seulement un visuel héros.", "Soyez précis dans le prompt ; des prompts vagues produisent une UI générique.", "Préparez un design system et indiquez à OpenCode où se trouvent les tokens et les primitives canoniques (dans AGENTS.md).", "Faites tourner un serveur de dev et faites rendre l’agent dans un vrai navigateur, en redimensionnant aux breakpoints pour contrôler le résultat.", "Itérez en faisant comparer à OpenCode son implémentation avec les captures — au lieu de simplement confirmer que ça build."]}, {"kind": "p", "text": "Référencez des fichiers avec @ dans le TUI pour une recherche floue de votre répertoire de travail, exécutez des commandes shell en ligne avec un ! en tête, et déclenchez des actions avec les commandes /. Puis formulez le prompt avec des contraintes concrètes :"}, {"kind": "code", "lang": "bash", "code": "opencode\n# in the TUI:\n> @reference-desktop.png @reference-mobile.png\n  Implement this design in React + Vite + Tailwind + TypeScript.\n  Reuse my existing design-system components and tokens from AGENTS.md.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Run the dev server, open it in a browser, and iterate until the\n  UI matches the references across breakpoints."}, {"kind": "p", "text": "Gardez des prompts courts et ciblés, committez les bonnes itérations et annulez les mauvaises (en prévenant OpenCode quand vous revenez en arrière), pour que chaque passe parte d’une base propre."}]}, {"id": "extend", "heading": "AGENTS.md, MCP et sessions partageables", "blocks": [{"kind": "p", "text": "Trois points d’extension rendent OpenCode pratique pour un travail de design durable, et tous trois se projettent proprement sur un workflow de design ouvert."}, {"kind": "steps", "items": [{"label": "Règles AGENTS.md", "body": "Les règles de projet vivent dans un AGENTS.md à la racine du dépôt (ou des règles globales dans ~/.config/opencode/AGENTS.md). C’est le foyer durable de vos conventions de design, lu à chaque exécution, et il est compatible avec les fichiers CLAUDE.md qu’utilisent d’autres agents."}, {"label": "Serveurs MCP", "body": "OpenCode prend en charge à la fois les serveurs MCP locaux (command) et distants (URL), configurés sous la clé mcp — la façon portable d’apporter du contexte de design et des outils externes qui fonctionnent à travers les agents, pas seulement OpenCode."}, {"label": "Sessions partageables", "body": "La commande /share crée un lien public vers une conversation pour la collaboration ou la revue, et /unshare le révoque — utile pour obtenir des retours sur une passe de design."}]}, {"kind": "p", "text": "Ce sont des capacités portables et multi-agent — exactement le genre de chose qu’Open Design est conçu pour orchestrer, plutôt que de recréer projet par projet."}]}, {"id": "vs", "heading": "OpenCode vs Codex vs Claude Code vs Cursor pour le design", "blocks": [{"kind": "p", "text": "Il n’y a pas de vainqueur unique pour le travail de design — chaque agent a une force différente, et les équipes expérimentées les combinent. Un résumé équilibré :"}, {"kind": "table", "columns": ["Agent", "Force en design", "Idéal pour"], "rows": [["OpenCode", "Open source et agnostique au modèle ; exécutez n’importe quel fournisseur derrière un seul workflow en terminal", "La liberté BYOK, le changement de modèle, les configurations entièrement ouvertes et local-first"], ["Codex", "Forte finition visuelle avec une skill frontend ; compréhension d’images", "L’async délégué, les builds en sandbox, les règles AGENTS.md portables"], ["Claude Code", "Décisions de design précises (hex, espacement, typographie) et UX consciente de la base de code", "Le raisonnement frontend et les refactors à large contexte"], ["Cursor", "Boucle visuelle construire-et-voir avec aperçu en direct et éditions inline", "Le travail d’UI en boucle serrée d’itération au sein d’un IDE"]]}, {"kind": "p", "text": "Le verdict récurrent de la communauté est que le goût vient des humains : tous retombent sur une esthétique générique sans skills, références et contraintes. C’est le vrai problème à résoudre — et il a la forme d’un outil de design, pas d’un modèle, ce qui est précisément pourquoi un agent ouvert comme OpenCode s’accorde si bien avec une couche de design ouverte."}]}, {"id": "pitfalls", "heading": "Les pièges, et comment éviter le rendu « AI slop »", "blocks": [{"kind": "p", "text": "La critique la plus fréquente à l’égard du design généré par IA est qu’il a l’air générique — dégradés doux, panneaux flottants, coins arrondis surdimensionnés, ombres spectaculaires, une ambiance Inter-et-violet qui « crie qu’une IA a fait ça ». Parmi les autres problèmes signalés : des mises en page mobiles cassées et des instructions qui fuient dans les textes de l’UI. Aucun de ces problèmes n’est propre à OpenCode ; c’est ce qui arrive quand un agent, quel qu’il soit, s’exécute sans contexte de design organisé."}, {"kind": "steps", "items": [{"label": "Ajoutez une skill esthétique", "body": "Une skill de design organisée force l’agent à s’engager sur une vraie direction au lieu du rendu par défaut."}, {"label": "Vérifiez dans un vrai navigateur", "body": "Rendez et auto-contrôlez sur les différents breakpoints pour que les mises en page ne cassent pas en silence sur mobile."}, {"label": "Fournissez tokens et références", "body": "De vrais tokens de design et des captures de référence sont le plus grand levier sur la qualité des sorties."}, {"label": "Encodez les règles dans AGENTS.md", "body": "Mettez des règles de style comme « pas de hero cards, deux familles typographiques au maximum, hiérarchie qui met la marque d’abord » là où l’agent les lit à chaque exécution."}]}, {"kind": "p", "text": "Remarquez que chaque parade revient à donner à l’agent un contexte de design organisé — quel que soit le modèle que vous exécutez. Maintenir ce contexte à la main, projet par projet, est le labeur qu’Open Design supprime."}]}, {"id": "open-design", "heading": "Concevoir avec OpenCode dans Open Design", "blocks": [{"kind": "p", "text": "Open Design est la couche de design open source que le workflow ci-dessus ne cesse de réclamer. Il traite OpenCode comme un adaptateur de première partie et l’entoure d’une bibliothèque organisée de skills et de design systems, d’un pipeline de rendu structuré et d’une UI desktop locale — pour que le contexte de design qui rend tout agent bon soit présent dès la première exécution, et non assemblé à la main à chaque fois. Les deux projets sont open source et local-first, ce qui rend l’appariement naturel."}, {"kind": "ol", "items": ["Installez Open Design et sélectionnez OpenCode comme agent.", "Authentifiez-vous avec votre propre clé API de fournisseur de modèle (BYOK) — les identifiants restent sur votre machine et ne transitent jamais par nos serveurs.", "Choisissez n’importe quel fournisseur et modèle, plus un design system et une skill, puis générez des decks, des prototypes et des landing pages avec un goût cohérent.", "Chaque artefact et fichier DESIGN.md vit dans votre propre dépôt, pas dans un cloud hébergé."]}, {"kind": "p", "text": "Le même agent OpenCode, la même liberté de modèle — auxquels s’ajoute un véritable workflow de design open source, portable, autour de lui. C’est local-first et Apache-2.0, donc rien de votre travail ni de vos identifiants ne quitte votre machine."}]}], "faqTitle": "Questions fréquentes", "faq": [{"name": "OpenCode peut-il vraiment faire du travail de design ?", "text": "Oui — avec une skill esthétique, un design system et de vraies images de référence dans le contexte, OpenCode produit une UI responsive de qualité production et peut la vérifier dans un navigateur. Parce qu’il est agnostique au modèle, vous exécutez celui qui est actuellement le meilleur en frontend. Sans ce contexte organisé, il a tendance à retomber sur un rendu générique, et c’est l’écart que comble Open Design."}, {"name": "Quel modèle utiliser avec OpenCode pour le design ?", "text": "Celui que vous voulez — OpenCode est agnostique au fournisseur via models.dev, vous pouvez donc exécuter Anthropic, OpenAI, Google, OpenRouter ou des modèles locaux derrière le même workflow et en changer à tout moment. La qualité de la sortie de design dépend bien plus de votre skill, de votre design system et de vos références que du modèle seul."}, {"name": "Open Design est-il fait par l’équipe OpenCode (SST) ?", "text": "Non. Open Design est un projet open source indépendant qui intègre OpenCode comme agent. Il complète OpenCode avec une bibliothèque de skills et de design systems ouverte et local-first."}, {"name": "Ai-je besoin d’un abonnement spécial pour concevoir avec OpenCode ?", "text": "Non — OpenCode est BYOK. Vous apportez votre propre clé API de fournisseur de modèle, et Open Design ne fait jamais transiter vos identifiants. Il n’y a pas de verrouillage par l’éditeur."}, {"name": "OpenCode, Codex ou Claude Code pour le design frontend ?", "text": "Tous sont solides, et beaucoup d’équipes les combinent. L’avantage d’OpenCode est d’être entièrement open source et agnostique au modèle ; Codex excelle dans les builds délégués en sandbox ; Claude Code est reconnu pour ses décisions de design précises et conscientes de la base de code. Open Design vous laisse changer d’agent sans changer votre workflow de design."}, {"name": "Comment étendre OpenCode pour le contexte de design ?", "text": "Encodez les règles dans AGENTS.md, ajoutez des serveurs MCP sous la clé mcp pour des outils portables et du contexte de design, et utilisez les sessions partageables pour la revue. Open Design fournit une bibliothèque organisée de skills et de design systems pour vous éviter la configuration projet par projet."}, {"name": "Open Design est-il affilié à OpenCode ou SST ?", "text": "Non. OpenCode est un projet open source maintenu par SST (Anomaly Innovations) ; Open Design est un projet open source indépendant qui le prend en charge comme adaptateur de première partie."}, {"name": "Mes fichiers et identifiants sont-ils en sécurité ?", "text": "Oui — Open Design est local-first. Vos fichiers, artefacts et DESIGN.md restent dans votre propre dépôt, et vos identifiants de fournisseur de modèle sont utilisés directement par votre agent, jamais routés via les serveurs d’Open Design."}], "ctaTitle": "Concevez avec OpenCode, à la manière ouverte.", "ctaBody": "Apportez votre propre clé de fournisseur de modèle, gardez chaque fichier en local et obtenez une bibliothèque de design organisée autour de l’agent ouvert que vous utilisez déjà.", "ctaActions": [{"label": "Utiliser OpenCode dans Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Star sur GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Télécharger l’application desktop", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Voir tous les agents pris en charge"},
      },
    },
    'ru': {
      'claude-code': {
        ...en['claude-code']!,
        title: "Claude Code для дизайна — Open Design",
        description: "Как дизайнеры используют Claude Code для UI и веб-дизайна и как Open Design превращает его в полноценного дизайн-агента — local-first, BYOK, с курируемой библиотекой skill и дизайн-систем.",
        breadcrumb: "Claude Code",
        label: "Агент · Claude Code",
        heading: "Claude Code для дизайна.",
        lead: "Claude Code — это терминальный кодинг-агент от Anthropic. Им уже создают интерфейсы, дизайн-системы и лендинги. Open Design встраивает его в настоящий дизайн-процесс — используйте свой ключ Anthropic или подписку Claude и держите каждый файл локально.",
        rich: {"heroCtaLead": "Open Design превращает Claude Code в local-first, open-source дизайн-агента — ваш ключ Anthropic или подписка Claude, ваши файлы и курируемая библиотека skill и дизайн-систем вокруг него.", "heroCtaActions": [{"label": "Использовать Claude Code в Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Поставить звезду на GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Скачать десктопное приложение", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Claude Code широко считается кодинг-агентом с лучшим вкусом во фронтенде — он рассуждает об интерфейсах с необычной точностью, называя конкретные значения hex, отступы и типографические шкалы, и рефакторит UI по большой кодовой базе, не теряя нить. Но «из коробки» он всё равно тяготеет к шаблонному виду, пока вы не дадите ему дизайн-систему, skills и реальные референсы. Это практичное, сквозное руководство по использованию Claude Code для UI, фронтенда и работы с дизайн-системами, а также по встраиванию его в структурированный процесс с Open Design.", "Оно охватывает то, чем на самом деле является Claude Code, почему он силён во фронтенде, как настроить его с нуля, рабочий процесс с CLAUDE.md и Skills, официальный round-trip с Figma, как он сравнивается с Codex и Cursor, какие подводные камни делают вывод ИИ шаблонным и как Open Design закрывает этот разрыв как открытый, local-first дизайн-слой."], "heroImage": {"src": "/agents/claude-code-design/claude-code-design-hero.webp", "alt": "Цикл обратной связи дизайна Claude Code: терминальный агент принимает конкретные дизайн-решения, браузер отрисовывает UI, рабочее пространство и стрелка обратной связи, замыкающая цикл", "caption": "Ключевой цикл: Claude Code обдумывает конкретные UI-решения в терминале, отрисовывает и проверяет их в настоящем браузере и сходится к вашим референсам."}, "tocLabel": "На этой странице", "toc": [{"id": "what-is-claude-code", "label": "Чем на самом деле является Claude Code"}, {"id": "why-design", "label": "Почему Claude Code хорош в дизайне"}, {"id": "setup", "label": "Настройка Claude Code для дизайна (с нуля)"}, {"id": "skills-workflow", "label": "Рабочий процесс с CLAUDE.md и Skills"}, {"id": "figma", "label": "Round-trip Claude Code + Figma"}, {"id": "vs", "label": "Claude Code против Codex против Cursor"}, {"id": "pitfalls", "label": "Подводные камни и вид «AI slop»"}, {"id": "open-design", "label": "Дизайн с Claude Code в Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-claude-code", "heading": "Чем на самом деле является Claude Code", "blocks": [{"kind": "p", "text": "Claude Code — это агентный инструмент для кодинга от Anthropic. Он читает вашу кодовую базу, редактирует файлы, выполняет команды и интегрируется с вашими инструментами разработки — планируя, создавая и проверяя работу по задачам на естественном языке, а не просто дополняя строки."}, {"kind": "p", "text": "Он поставляется в нескольких форматах, которые используют один и тот же движок: терминальный CLI, расширения IDE для VS Code, Cursor и JetBrains, десктопное приложение с визуальным просмотром диффов и веб-версия для долгих задач. Ваши файлы CLAUDE.md, настройки и серверы MCP переносятся между всеми ними."}, {"kind": "steps", "items": [{"label": "Файл инструкций", "body": "Claude Code читает файл CLAUDE.md в корне проекта в начале каждой сессии — естественное место, где можно зафиксировать ваши дизайн-конвенции, tokens и чек-листы ревью."}, {"label": "Skills", "body": "Agent Skills упаковывают повторяемые инструкции, скрипты и ресурсы, которые Claude подгружает по требованию, включая официальный Frontend Design skill от Anthropic для вкуса."}, {"label": "Планирование и субагенты", "body": "Он может планировать перед действием и порождать субагентов, которые работают над разными частями задачи параллельно, что сохраняет целостность крупных UI-рефакторингов."}]}, {"kind": "ul", "items": ["Поставщик: Anthropic", "Учётные данные: API-ключ Anthropic (BYOK, через Console) или подписка Claude (Pro / Max)", "Форматы: терминальный CLI, расширения VS Code / Cursor / JetBrains, десктопное приложение, веб"]}]}, {"id": "why-design", "heading": "Почему Claude Code хорош в дизайне", "blocks": [{"kind": "p", "text": "Среди кодинг-агентов Claude Code заслужил репутацию обладателя вкуса в работе над фронтендом. Это объясняется несколькими причинами."}, {"kind": "steps", "items": [{"label": "Конкретные, а не расплывчатые решения", "body": "Claude Code склонен принимать конкретные решения — точные значения hex, шкалы отступов, типографические шкалы и иерархию компонентов — вместо общих фраз, и именно это отличает настоящий интерфейс от заглушки."}, {"label": "Рассуждение с учётом кодовой базы", "body": "Имея большой рабочий контекст, он рефакторит UI сразу по множеству файлов, переиспользуя ваши существующие компоненты и tokens, а не изобретая разовые стили."}, {"label": "Официальный frontend skill", "body": "Anthropic поставляет Frontend Design skill, который заставляет Claude сначала задавать дизайн-направление и осознанно уходит от шаблонных системных шрифтов и предсказуемых фиолетовых градиентов."}]}, {"kind": "image", "src": "/agents/claude-code-design/claude-code-design-taste-triangle.webp", "alt": "Диаграмма, показывающая, как дизайн-система, skill и референсное изображение сходятся в хороший дизайн-результат", "caption": "Вкус рождается из трёх вводных, которые вы предоставляете: дизайн-системы, skill и реальных референсных изображений."}, {"kind": "p", "text": "Урок тот же, что Anthropic делает о своих моделях: у Claude по умолчанию нет вкуса — предоставленный сам себе, он сходится к статистическому центру веб-дизайна (Inter, фиолетовые градиенты, мягкие тени). Он создаёт хороший дизайн, когда вы даёте ему ограничения. Open Design упаковывает именно эти вводные, поэтому они так хорошо сочетаются (подробнее ниже)."}]}, {"id": "setup", "heading": "Настройка Claude Code для дизайна с нуля", "blocks": [{"kind": "p", "text": "Вот полный путь от чистой машины до Claude Code, способного создавать и проверять UI."}, {"kind": "code", "lang": "bash", "code": "# 1. Install Claude Code (native install, recommended)\ncurl -fsSL https://claude.ai/install.sh | bash\n# or: brew install --cask claude-code\n# Windows PowerShell: irm https://claude.ai/install.ps1 | iex\n\n# 2. Start it in your project and sign in on first run\ncd your-project\nclaude            # sign in with your Claude subscription or API key\n\n# 3. Generate project context\n/init             # creates a CLAUDE.md for this project\n\n# 4. Add the official Frontend Design skill\nclaude plugin install frontend-design@claude-plugins-official\n\n# 5. Wire the Figma MCP server (optional, for design handoff)\nclaude plugin install figma@claude-plugins-official"}, {"kind": "image", "src": "/agents/claude-code-design/claude-code-design-setup-flow.webp", "alt": "Пятишаговый процесс настройки: установка, аутентификация, настройка CLAUDE.md, добавление skill, проверка", "caption": "Последовательность настройки: установка → аутентификация → настройка CLAUDE.md → добавление Frontend Design skill → включение проверки в браузере."}, {"kind": "steps", "items": [{"label": "Зафиксируйте свои дизайн-правила", "body": "Поместите свои tokens, примитивы и конвенции в CLAUDE.md и направьте Claude к ним, чтобы вывод соответствовал бренду, а не сваливался в шаблонный вид."}, {"label": "Добавьте проверку в браузере", "body": "Подключите Playwright или Chrome MCP, чтобы Claude отрисовывал результат в настоящем браузере и проверял его на разных брейкпоинтах, а не просто подтверждал успешную сборку."}]}]}, {"id": "skills-workflow", "heading": "Рабочий процесс с CLAUDE.md и Skills", "blocks": [{"kind": "p", "text": "Самый эффективный дизайн-цикл с Claude Code — это давать ему реальные референсы вместе с вашим дизайн-контекстом, а затем итерировать, пока UI не совпадёт, при этом CLAUDE.md и Skills удерживают ограничения, чтобы не объяснять их заново в каждом промпте."}, {"kind": "ol", "items": ["Начинайте с самых ясных визуальных референсов, что у вас есть, — и включайте несколько состояний (десктоп и мобильный, hover, пустое, загрузка), а не только один hero-кадр.", "Будьте конкретны в промпте; расплывчатые промпты дают шаблонный UI даже с сильным агентом.", "Держите дизайн-систему и конвенции в CLAUDE.md и подсказывайте Claude, где лежат tokens и канонические примитивы.", "Добавьте Frontend Design skill, чтобы Claude задал реальное эстетическое направление до написания кода.", "Подключите проверку в браузере, чтобы Claude отрисовывал, менял размер до брейкпоинтов и сравнивал с референсами, а не просто подтверждал сборку."]}, {"kind": "p", "text": "Добавьте референсное изображение в сессию и задайте промпт с конкретными ограничениями:"}, {"kind": "code", "lang": "bash", "code": "claude \"Implement reference-desktop.png and reference-mobile.png in\n  React + Vite + Tailwind + TypeScript.\n  Reuse the design-system components and tokens described in CLAUDE.md.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Render it in the browser, verify it matches the references across\n  breakpoints, and iterate until it does.\""}, {"kind": "p", "text": "Запускайте рядом dev-сервер, держите промпты короткими и сфокусированными и коммитьте удачные итерации / откатывайте неудачные (сообщая Claude об откате), чтобы каждый проход строился на чистой основе. Используйте режим планирования для крупных рефакторингов, чтобы пересмотреть подход до любых изменений в файлах."}]}, {"id": "figma", "heading": "Claude Code + Figma: round-trip дизайн ↔ код", "blocks": [{"kind": "p", "text": "В феврале 2026 года Anthropic и Figma выпустили первоклассную двунаправленную интеграцию через сервер Figma MCP. Она работает в обе стороны."}, {"kind": "steps", "items": [{"label": "Дизайн → Код", "body": "Выберите фрейм в Figma или вставьте ссылку в Claude Code, подтяните дизайн-контекст и попросите реализовать дизайн с использованием вашей существующей библиотеки компонентов. Code Connect удерживает вывод в соответствии с вашими реальными компонентами."}, {"label": "Код → Дизайн", "body": "Соберите и предпросмотрите фичу в браузере, затем скажите «Send this to Figma», чтобы зафиксировать работающий UI как редактируемые слои Figma — весь экран или выбранный элемент."}]}, {"kind": "p", "text": "Установите её один раз командой claude plugin install figma@claude-plugins-official (Dev Mode MCP требует платного плана Figma). Тот же Figma MCP доступен Claude Code, Codex, Cursor и VS Code — именно такая переносимая, мультиагентная возможность, которую Open Design создан оркестрировать."}]}, {"id": "vs", "heading": "Claude Code против Codex против Cursor для дизайна", "blocks": [{"kind": "p", "text": "Единого победителя в дизайн-работе нет — у каждого агента своя сильная сторона, и опытные команды комбинируют их. Честная сводка:"}, {"kind": "table", "columns": ["Агент", "Сила в дизайне", "Лучше всего для"], "rows": [["Claude Code", "Конкретные дизайн-решения (hex, отступы, типографика) и UX-рассуждение с учётом кодовой базы", "Фронтенд-рассуждения и рефакторинги с большим контекстом"], ["Codex", "Сильная визуальная отточенность и понимание изображений; асинхронные сборки в песочнице", "Делегированные асинхронные сборки и переносимые правила AGENTS.md"], ["Cursor", "Визуальный цикл «собери и посмотри» с живым предпросмотром и инлайн-правками", "Тесная работа над UI «итерируй и наблюдай» внутри IDE"]]}, {"kind": "p", "text": "Повторяющийся вердикт сообщества: вкус исходит от людей — все три по умолчанию сваливаются в шаблонную эстетику без skills, референсов и ограничений. Вот настоящая проблема, которую нужно решить — и она по форме относится к дизайн-инструменту, а не к модели."}]}, {"id": "pitfalls", "heading": "Подводные камни и как избежать вида «AI slop»", "blocks": [{"kind": "p", "text": "Даже при репутации Claude Code как обладателя вкуса самая частая жалоба на дизайн, сгенерированный ИИ, в том, что он выглядит шаблонно — шрифты Inter, фиолетовые градиенты на белом, мягкие тени, чрезмерно скруглённые углы, эстетика, которая «кричит, что это сделал ИИ». Сама Anthropic объясняет это сходимостью распределения: безопасные решения доминируют в обучающих данных веба. Среди других сообщаемых проблем — сломанные мобильные раскладки и инструкции, протекающие в текст UI."}, {"kind": "steps", "items": [{"label": "Установите Frontend Design skill", "body": "Он заставляет Claude задать реальное направление и явно избегает шрифтов и градиентов, чрезмерно используемых ИИ."}, {"label": "Включите проверку в браузере", "body": "Заставьте Claude отрисовывать и самопроверять результат на разных брейкпоинтах, чтобы раскладки не ломались незаметно на мобильном."}, {"label": "Предоставьте tokens и референсы", "body": "Реальные дизайн-tokens и референсные скриншоты — самый сильный рычаг для качества вывода."}, {"label": "Зафиксируйте правила в CLAUDE.md", "body": "Поместите правила вроде «без hero-карточек, максимум два шрифта, иерархия от бренда» туда, где агент читает их при каждом запуске."}]}, {"kind": "p", "text": "Обратите внимание: каждое из этих средств сводится к тому, чтобы дать агенту курируемый дизайн-контекст. Поддержка этого контекста вручную, для каждого проекта, — та рутина, которую устраняет Open Design."}]}, {"id": "open-design", "heading": "Дизайн с Claude Code внутри Open Design", "blocks": [{"kind": "p", "text": "Open Design — это тот open-source дизайн-слой, которого процесс выше постоянно требует. Он рассматривает Claude Code как нативный адаптер и оборачивает его в курируемую библиотеку skill и дизайн-систем, структурированный конвейер рендера и локальный десктопный UI — так что дизайн-контекст, делающий Claude Code хорошим, есть с первого запуска, а не собирается вручную каждый раз."}, {"kind": "ol", "items": ["Установите Open Design и выберите Claude Code как своего агента.", "Аутентифицируйтесь с помощью API-ключа Anthropic (BYOK) или подписки Claude — учётные данные остаются на вашей машине и никогда не проксируются через нас.", "Выберите дизайн-систему и skill, затем генерируйте презентации, прототипы и лендинги с единообразным вкусом.", "Каждый артефакт и файл DESIGN.md живёт в вашем собственном репозитории, а не в хостинговом облаке."]}, {"kind": "p", "text": "Тот же агент Claude Code, тот же ключ — плюс настоящий, переносимый, open-source дизайн-процесс вокруг него. Он local-first и под Apache-2.0, так что ничто из вашей работы или ваших учётных данных не покидает машину."}]}], "faqTitle": "Часто задаваемые вопросы", "faq": [{"name": "Хорош ли Claude Code для дизайн-работы?", "text": "Да — он широко считается кодинг-агентом с лучшим вкусом во фронтенде, принимая конкретные, учитывающие кодовую базу решения о значениях hex, отступах и типографических шкалах. С Frontend Design skill, дизайн-системой и реальными референсными изображениями в контексте он создаёт продакшен-качественный, адаптивный UI и может проверить его в браузере. Без такого контекста он склонен сваливаться в шаблонный вид — и именно этот разрыв закрывает Open Design."}, {"name": "Нужна ли подписка Claude, чтобы заниматься дизайном с Claude Code?", "text": "Вы можете использовать либо API-ключ Anthropic (BYOK, через Console), либо подписку Claude (Pro / Max). В любом случае Open Design никогда не проксирует ваши учётные данные — они используются напрямую вашим агентом на вашей машине."}, {"name": "Claude Code или Codex для фронтенд-дизайна?", "text": "Оба сильны. Claude Code известен конкретными, учитывающими кодовую базу дизайн-решениями и фронтенд-рассуждениями; Codex обладает сильной визуальной отточенностью и блистает в делегированных сборках в песочнице. Многие команды используют оба — Open Design позволяет переключать агентов, не меняя дизайн-процесс."}, {"name": "Как подключить Claude Code к Figma?", "text": "Установите официальный плагин Figma командой claude plugin install figma@claude-plugins-official. После этого вы можете реализовывать фреймы Figma в коде, используя дизайн-контекст, и отправлять работающий UI обратно в редактируемые фреймы Figma через «Send this to Figma». Dev Mode MCP требует платного плана Figma."}, {"name": "Что такое Skills и CLAUDE.md?", "text": "CLAUDE.md — это markdown-файл в корне проекта, который Claude Code читает в начале каждой сессии — место для фиксации ваших дизайн-конвенций. Skills упаковывают повторяемые инструкции и ресурсы, которые Claude подгружает по требованию, включая официальный Frontend Design skill от Anthropic. Open Design поставляет курируемую библиотеку и того, и другого, так что вы пропускаете настройку под каждый проект."}, {"name": "Как избежать шаблонной эстетики «AI slop»?", "text": "Установите Frontend Design skill, предоставьте реальные дизайн-tokens и референсные скриншоты, зафиксируйте правила бренда в CLAUDE.md и включите проверку в браузере. Open Design поставляет это как курируемую библиотеку, так что вы пропускаете настройку под каждый проект."}, {"name": "Связан ли Open Design с Anthropic?", "text": "Нет. Claude Code — продукт Anthropic; Open Design — независимый open-source проект, который поддерживает его как нативный адаптер. Claude и Claude Code являются товарными знаками Anthropic."}, {"name": "В безопасности ли мои файлы и учётные данные?", "text": "Да — Open Design является local-first и под Apache-2.0. Ваши файлы, артефакты и DESIGN.md остаются в вашем собственном репозитории, а ваши учётные данные Anthropic используются напрямую вашим агентом и никогда не маршрутизируются через серверы Open Design."}], "ctaTitle": "Дизайн с Claude Code, по-открытому.", "ctaBody": "Используйте свой ключ Anthropic или подписку Claude, держите каждый файл локально и получите курируемую дизайн-библиотеку вокруг агента, которым вы уже пользуетесь.", "ctaActions": [{"label": "Использовать Claude Code в Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Поставить звезду на GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Скачать десктопное приложение", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Посмотреть всех поддерживаемых агентов"},
      },
      'codex': {
        ...en['codex']!,
        title: "Codex для дизайна — Open Design",
        description: "Как люди используют OpenAI Codex для UI и веб-дизайна — плагин Product Design, интеграция с Figma, фронтенд-skills — и как Open Design превращает Codex в local-first, open-source дизайн-агента.",
        breadcrumb: "Codex",
        label: "Агент · Codex",
        heading: "Codex для дизайна.",
        lead: "Codex — это кодинг-агент от OpenAI. С плагином Product Design и интеграцией Figma он стал серьёзным дизайн-инструментом. Open Design встраивает Codex в open-source дизайн-процесс — ваш ключ OpenAI или подписка ChatGPT, ваши файлы, local-first.",
        rich: {"heroCtaLead": "Open Design превращает Codex в local-first, open-source дизайн-агента — ваш ключ OpenAI, ваши файлы и курируемая библиотека skill и дизайн-систем вокруг него.", "heroCtaActions": [{"label": "Использовать Codex в Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Поставить звезду на GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Скачать десктопное приложение", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["OpenAI Codex начинался как генератор кода, но в 2026 году стал достойным инструментом для проектирования настоящих интерфейсов — стоит дать ему правильные референсы, skills и цикл проверки. Это практичное, сквозное руководство по использованию Codex для UI, фронтенда и работы с дизайн-системами, а также по встраиванию его в структурированный дизайн-процесс с Open Design.", "Оно охватывает то, чем Codex является сегодня, почему он внезапно хорош во фронтенде, как настроить его с нуля, цикл «скриншот в UI», официальный round-trip с Figma, как он сравнивается с Cursor и Claude Code, какие подводные камни делают вывод ИИ шаблонным и как Open Design закрывает этот разрыв как открытый, local-first дизайн-слой."], "heroImage": {"src": "/agents/codex-design/codex-design-workflow-loop.webp", "alt": "Цикл обратной связи дизайна Codex: терминальный агент, браузер отрисовывает UI и рабочее пространство со стрелкой обратной связи, замыкающей цикл", "caption": "Ключевой цикл: Codex собирает UI в терминале, отрисовывает и проверяет его в настоящем браузере и итерирует по вашим референсам."}, "tocLabel": "На этой странице", "toc": [{"id": "what-is-codex", "label": "Чем на самом деле является OpenAI Codex"}, {"id": "why-design", "label": "Почему Codex теперь хорош в дизайне"}, {"id": "setup", "label": "Настройка Codex для дизайна (с нуля)"}, {"id": "screenshot-workflow", "label": "Рабочий процесс «скриншот в UI»"}, {"id": "figma", "label": "Round-trip Codex + Figma"}, {"id": "vs", "label": "Codex против Cursor против Claude Code"}, {"id": "pitfalls", "label": "Подводные камни и вид «AI slop»"}, {"id": "open-design", "label": "Дизайн с Codex в Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-codex", "heading": "Чем на самом деле является OpenAI Codex (и чем он не является)", "blocks": [{"kind": "p", "text": "Сначала уточнение, которое сбивает с толку почти всех, кто ищет «Codex». Изначальный OpenAI Codex был моделью автодополнения кода 2021 года, питавшей ранний GitHub Copilot и устаревшей в 2023 году. Эта страница не о нём. Сегодняшний Codex — это агентный инструмент для кодинга от OpenAI: он планирует, пишет, запускает и проверяет код по задачам на естественном языке."}, {"kind": "p", "text": "Современный Codex поставляется в четырёх форматах: терминальный CLI (переписанный на Rust, под лицензией Apache-2.0), расширение IDE для VS Code, Cursor и Windsurf, облачно-веб-версия для делегированных асинхронных задач и десптопное приложение со встроенным браузером и Computer Use."}, {"kind": "steps", "items": [{"label": "Модель по умолчанию", "body": "По состоянию на середину 2026 года рекомендуемая модель — gpt-5.5, при этом gpt-5.4 — это модель, которую OpenAI явно обучала для фронтенда и computer use."}, {"label": "Файл инструкций", "body": "Codex читает файл AGENTS.md в вашем проекте (кросс-инструментальный стандарт) для правил проекта — естественное место, где можно зафиксировать ваши дизайн-конвенции."}, {"label": "Песочница", "body": "Он работает в песочнице на уровне ядра (по умолчанию workspace-write), так что агент, редактирующий ваш UI, не может выйти за пределы проекта."}]}, {"kind": "ul", "items": ["Поставщик: OpenAI", "Учётные данные: API-ключ OpenAI (BYOK) или подписка ChatGPT (Free / Go / Plus / Pro / Business / Enterprise)", "Лицензия CLI: Apache-2.0, open source"]}]}, {"id": "why-design", "heading": "Почему Codex теперь хорош в дизайне", "blocks": [{"kind": "p", "text": "В начале 2026 года сошлись три вещи, превратившие Codex в настоящий дизайн-инструмент, а не в общий генератор кода."}, {"kind": "steps", "items": [{"label": "Модель, обученная для фронтенда", "body": "OpenAI выпустила GPT-5.4 — свою первую основную модель, обученную для фронтенда и computer use, с гораздо лучшим пониманием изображений во всём дизайн-процессе и более сильной самопроверкой. Она даже умеет генерировать mood-board'ы и визуальные варианты до фиксации финальных ассетов."}, {"label": "Официальный frontend skill", "body": "Каталог openai/skills поставляет курируемый frontend-skill, который навязывает реальный вкус: раскладки без карточек, full-bleed герои, иерархия от бренда, сдержанная анимация, не более двух шрифтов и одного акцентного цвета — и заставляет Codex сформулировать визуальный тезис до сборки."}, {"label": "Проверка в браузере", "body": "С Playwright skill Codex открывает настоящий браузер, меняет размер до брейкпоинтов и сравнивает свой вывод с референсом, а не просто проверяет, что сборка прошла."}]}, {"kind": "image", "src": "/agents/codex-design/codex-design-taste-triangle.webp", "alt": "Диаграмма, показывающая, как дизайн-система, skill и референсное изображение сходятся в хороший дизайн-результат", "caption": "Вкус рождается из трёх вводных, которые вы предоставляете: дизайн-системы, skill и реальных референсных изображений."}, {"kind": "p", "text": "Урок, стоящий за всеми тремя: у Codex по умолчанию нет вкуса. Он создаёт хороший дизайн, когда вы даёте ему ограничения — дизайн-систему, эстетический skill и конкретные референсы. Open Design упаковывает именно эти вводные, поэтому они так хорошо сочетаются (подробнее ниже)."}]}, {"id": "setup", "heading": "Настройка Codex для дизайна с нуля", "blocks": [{"kind": "p", "text": "Вот полный путь от чистой машины до Codex, способного создавать и проверять UI."}, {"kind": "code", "lang": "bash", "code": "# 1. Install the Codex CLI\nnpm install -g @openai/codex\n# or: brew install --cask codex\n# or: curl -fsSL https://chatgpt.com/codex/install.sh | sh\n\n# 2. Authenticate (ChatGPT sign-in recommended for higher limits)\ncodex            # then choose “Sign in with ChatGPT”\n\n# 3. Generate project context\ncodex            # inside your project, run /init to create AGENTS.md\n\n# 4. Add the official frontend skill, then restart Codex\n# (in the Codex app) $skill-installer frontend-skill\n\n# 5. Wire the Figma MCP server (optional, for design handoff)\ncodex mcp add figma --url https://mcp.figma.com/mcp"}, {"kind": "image", "src": "/agents/codex-design/codex-design-setup-flow.webp", "alt": "Пятишаговый процесс настройки: установка, аутентификация, настройка, установка skill, проверка", "caption": "Последовательность настройки: установка → аутентификация → настройка AGENTS.md → установка frontend skill → включение проверки в браузере."}, {"kind": "steps", "items": [{"label": "Зафиксируйте свои дизайн-правила", "body": "Поместите свои tokens, примитивы и конвенции в AGENTS.md или DESIGN.md и направьте Codex к ним, чтобы вывод соответствовал бренду, а не сваливался в шаблонный вид."}, {"label": "Выберите правильный уровень рассуждения", "body": "OpenAI отмечает, что низкий-средний уровни рассуждения часто дают более сильные фронтенд-результаты, чем максимальная настройка."}]}]}, {"id": "screenshot-workflow", "heading": "Рабочий процесс «скриншот в UI»", "blocks": [{"kind": "p", "text": "Самый эффективный дизайн-цикл с Codex — это превращение референсного изображения в работающий, адаптивный UI и итерация до совпадения. Собственное руководство OpenAI сводится к пяти шагам."}, {"kind": "ol", "items": ["Начинайте с самых ясных визуальных референсов, что у вас есть, — и включайте несколько состояний (десктоп и мобильный, hover, пустое, загрузка), а не только один hero-кадр.", "Будьте конкретны в промпте; расплывчатые промпты дают шаблонный UI.", "Подготовьте дизайн-систему и подскажите Codex, где лежат tokens и канонические примитивы.", "Включите интерактивный Playwright skill, чтобы Codex отрисовывал результат в настоящем браузере и менял размер до брейкпоинтов.", "Итерируйте, заставляя Codex сравнивать свою реализацию со скриншотами, а не просто подтверждать сборку."]}, {"kind": "p", "text": "Передавайте изображения, перетаскивая скриншот в терминал или с помощью флага изображения, затем задавайте промпт с конкретными ограничениями:"}, {"kind": "code", "lang": "bash", "code": "codex -i reference-desktop.png -i reference-mobile.png \\\n  \"Implement this design in React + Vite + Tailwind + TypeScript.\n   Reuse my existing design-system components and tokens.\n   Match spacing, layout, and hierarchy; make it responsive.\n   Use the Playwright skill to verify the UI matches the\n   references and iterate until it does.\""}, {"kind": "p", "text": "Запускайте dev-сервер во втором терминале, держите промпты короткими и сфокусированными и коммитьте удачные итерации / откатывайте неудачные (сообщая Codex об откате), чтобы каждый проход строился на чистой основе."}]}, {"id": "figma", "heading": "Codex + Figma: round-trip дизайн ↔ код", "blocks": [{"kind": "p", "text": "В феврале 2026 года OpenAI и Figma объявили об официальном партнёрстве, превратив более раннюю бету Figma MCP в первоклассную двунаправленную интеграцию. Она работает в обе стороны."}, {"kind": "steps", "items": [{"label": "Дизайн → Код", "body": "Скопируйте «link to selection» фрейма в Figma, вставьте его в Codex вместе с get_design_context и попросите реализовать дизайн с использованием вашей существующей библиотеки компонентов."}, {"label": "Код → Дизайн", "body": "Инструмент generate_figma_design («Code to Canvas») превращает живой, работающий UI обратно в редактируемые фреймы Figma — весь экран, выбранный элемент или целый файл."}]}, {"kind": "p", "text": "Figma MCP работает как удалённый сервер и не подпадает под лимиты запросов. Добавьте его один раз — и он доступен Codex, Claude Code, Cursor, VS Code и другим — именно такая переносимая, мультиагентная возможность, которую Open Design создан оркестрировать."}]}, {"id": "vs", "heading": "Codex против Cursor против Claude Code для дизайна", "blocks": [{"kind": "p", "text": "Единого победителя в дизайн-работе нет — у каждого агента своя сильная сторона, и опытные команды комбинируют их. Честная сводка:"}, {"kind": "table", "columns": ["Агент", "Сила в дизайне", "Лучше всего для"], "rows": [["Codex", "Сильная визуальная отточенность после GPT-5.4 + frontend-skill; понимание изображений", "Делегированные асинхронные сборки, запуски в песочнице, переносимые правила AGENTS.md"], ["Cursor", "Визуальный цикл «собери и посмотри» с живым предпросмотром и инлайн-правками", "Тесная работа над UI «итерируй и наблюдай» внутри IDE"], ["Claude Code", "Конкретные дизайн-решения (hex, отступы, типографика) и UX с учётом кодовой базы", "Фронтенд-рассуждения и рефакторинги с большим контекстом"]]}, {"kind": "p", "text": "Повторяющийся вердикт сообщества: вкус исходит от людей — все три по умолчанию сваливаются в шаблонную эстетику без skills, референсов и ограничений. Вот настоящая проблема, которую нужно решить — и она по форме относится к дизайн-инструменту, а не к модели."}]}, {"id": "pitfalls", "heading": "Подводные камни и как избежать вида «AI slop»", "blocks": [{"kind": "p", "text": "Самая частая жалоба на дизайн, сгенерированный Codex, в том, что он выглядит шаблонно — мягкие градиенты, плавающие панели, чрезмерно скруглённые углы, драматичные тени, вайб Inter-и-фиолетового, который «кричит, что это сделал ИИ». Среди других сообщаемых проблем — сломанные мобильные раскладки, инструкции, протекающие в текст UI, и быстрое достижение лимитов использования."}, {"kind": "steps", "items": [{"label": "Установите frontend skill", "body": "Курируемый эстетический skill заставляет Codex задать реальное направление вместо вида по умолчанию."}, {"label": "Включите проверку Playwright", "body": "Заставьте Codex отрисовывать и самопроверять результат на разных брейкпоинтах, чтобы раскладки не ломались незаметно на мобильном."}, {"label": "Предоставьте tokens и референсы", "body": "Реальные дизайн-tokens и референсные скриншоты — самый сильный рычаг для качества вывода."}, {"label": "Зафиксируйте правила в AGENTS.md", "body": "Поместите правила вроде «без hero-карточек, максимум два шрифта, иерархия от бренда» туда, где агент читает их при каждом запуске."}]}, {"kind": "p", "text": "Обратите внимание: каждое из этих средств сводится к тому, чтобы дать агенту курируемый дизайн-контекст. Поддержка этого контекста вручную, для каждого проекта, — та рутина, которую устраняет Open Design."}]}, {"id": "open-design", "heading": "Дизайн с Codex внутри Open Design", "blocks": [{"kind": "p", "text": "Open Design — это тот open-source дизайн-слой, которого процесс выше постоянно требует. Он рассматривает Codex как нативный адаптер и оборачивает его в курируемую библиотеку skill и дизайн-систем, структурированный конвейер рендера и локальный десктопный UI — так что дизайн-контекст, делающий Codex хорошим, есть с первого запуска, а не собирается вручную каждый раз."}, {"kind": "ol", "items": ["Установите Open Design и выберите Codex как своего агента.", "Аутентифицируйтесь с помощью API-ключа OpenAI (BYOK) или подписки ChatGPT — учётные данные остаются на вашей машине и никогда не проксируются через нас.", "Выберите дизайн-систему и skill, затем генерируйте презентации, прототипы и лендинги с единообразным вкусом.", "Каждый артефакт и файл DESIGN.md живёт в вашем собственном репозитории, а не в хостинговом облаке."]}, {"kind": "p", "text": "Тот же агент Codex, тот же ключ — плюс настоящий, переносимый, open-source дизайн-процесс вокруг него. Он local-first и под Apache-2.0, так что ничто из вашей работы или ваших учётных данных не покидает машину."}]}], "faqTitle": "Часто задаваемые вопросы", "faq": [{"name": "Действительно ли OpenAI Codex способен на дизайн-работу?", "text": "Да — с frontend skill, дизайн-системой и реальными референсными изображениями в контексте Codex (особенно на GPT-5.4) создаёт продакшен-качественный, адаптивный UI и может проверить его в браузере. Без такого контекста он склонен сваливаться в шаблонный вид — и именно этот разрыв закрывает Open Design."}, {"name": "Это плагин OpenAI Codex Product Design?", "text": "Нет. Open Design — независимый open-source проект, который интегрирует Codex как агента. Он дополняет собственный инструментарий OpenAI local-first, открытой библиотекой skill и дизайн-систем."}, {"name": "Нужна ли подписка ChatGPT, чтобы заниматься дизайном с Codex?", "text": "Вы можете использовать либо API-ключ OpenAI (BYOK), либо вашу подписку ChatGPT. Вход через ChatGPT обычно даёт более щедрые лимиты; в любом случае Open Design никогда не проксирует ваши учётные данные."}, {"name": "Codex или Claude Code для фронтенд-дизайна?", "text": "Оба сильны. Claude Code известен конкретными, учитывающими кодовую базу дизайн-решениями; Codex обладает сильной визуальной отточенностью после GPT-5.4 и блистает в делегированных сборках в песочнице. Многие команды используют оба — Open Design позволяет переключать агентов, не меняя дизайн-процесс."}, {"name": "Как подключить Codex к Figma?", "text": "Добавьте официальный сервер Figma MCP (codex mcp add figma --url https://mcp.figma.com/mcp). После этого вы можете реализовывать фреймы Figma в коде с помощью get_design_context и отправлять работающий UI обратно в редактируемые фреймы Figma через generate_figma_design."}, {"name": "Как избежать шаблонной эстетики «AI slop»?", "text": "Установите frontend skill, предоставьте реальные дизайн-tokens и референсные скриншоты, зафиксируйте правила бренда в AGENTS.md и включите проверку Playwright. Open Design поставляет это как курируемую библиотеку, так что вы пропускаете настройку под каждый проект."}, {"name": "Связан ли Open Design с OpenAI?", "text": "Нет. Codex — продукт OpenAI; Open Design — независимый open-source проект, который поддерживает его как нативный адаптер. OpenAI и Codex являются товарными знаками OpenAI."}, {"name": "В безопасности ли мои файлы и учётные данные?", "text": "Да — Open Design является local-first. Ваши файлы, артефакты и DESIGN.md остаются в вашем собственном репозитории, а ваши учётные данные OpenAI используются напрямую вашим агентом и никогда не маршрутизируются через серверы Open Design."}], "ctaTitle": "Дизайн с Codex, по-открытому.", "ctaBody": "Используйте свой ключ OpenAI, держите каждый файл локально и получите курируемую дизайн-библиотеку вокруг агента, которым вы уже пользуетесь.", "ctaActions": [{"label": "Использовать Codex в Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Поставить звезду на GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Скачать десктопное приложение", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Посмотреть всех поддерживаемых агентов"},
      },
      'cursor': {
        ...en['cursor']!,
        title: "Cursor для дизайнеров — Open Design",
        description: "Как дизайнеры используют Cursor для UI и веб-дизайна — Design Mode, Figma-в-код, Figma MCP — и как Open Design превращает Cursor в local-first, open-source дизайн-агента.",
        breadcrumb: "Cursor",
        label: "Агент · Cursor",
        heading: "Cursor для дизайнеров.",
        lead: "Cursor — это редактор кода с ИИ, теперь с визуальным Design Mode. Дизайнеры используют его, чтобы редактировать UI наведением и рисованием и превращать Figma в код. Open Design встраивает Cursor Agent в open-source дизайн-процесс, который держит ваши файлы локально.",
        rich: {"heroCtaLead": "Open Design превращает Cursor в local-first, open-source дизайн-агента — ваш аккаунт Cursor или ключи моделей, ваши файлы и курируемая библиотека skill и дизайн-систем вокруг него.", "heroCtaActions": [{"label": "Использовать Cursor в Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Поставить звезду на GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Скачать десктопное приложение", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Cursor — это AI-first редактор кода, сделавший «собери и смотри, как отрисовывается» способом по умолчанию для выпуска UI. С режимом Agent, инлайн-правками, предпросмотром в редакторе и Figma поверх MCP он стал настоящим дизайн-инструментом — стоит дать ему правильные референсы, правила и цикл проверки. Это практичное, сквозное руководство по использованию Cursor для UI, фронтенда и работы с дизайн-системами, а также по встраиванию его в структурированный дизайн-процесс с Open Design.", "Оно охватывает то, чем на самом деле является Cursor, почему его тесный цикл «итерируй и наблюдай» хорош для дизайна, как настроить его с нуля, цикл «скриншот-и-предпросмотр в UI», round-trip с Figma поверх MCP, как он сравнивается с Codex и Claude Code, какие подводные камни делают вывод ИИ шаблонным и как Open Design закрывает этот разрыв как открытый, local-first дизайн-слой."], "heroImage": {"src": "/agents/cursor-design/cursor-design-hero.webp", "alt": "Сходимость дизайна Cursor: редактор слева, курируемый хаб skill и дизайн-систем по центру со знаком Cursor в середине и отрисованный UI справа", "caption": "Ключевая идея: Cursor редактирует и отрисовывает UI в редакторе, а курируемый дизайн-хаб подаёт ему систему, skills и референсы, благодаря которым вывод выглядит осознанным."}, "tocLabel": "На этой странице", "toc": [{"id": "what-is-cursor", "label": "Чем на самом деле является Cursor"}, {"id": "why-design", "label": "Почему Cursor хорош в дизайне"}, {"id": "setup", "label": "Настройка Cursor для дизайна (с нуля)"}, {"id": "preview-workflow", "label": "Рабочий процесс «предпросмотр в UI»"}, {"id": "figma", "label": "Cursor + Figma поверх MCP"}, {"id": "vs", "label": "Cursor против Codex против Claude Code"}, {"id": "pitfalls", "label": "Подводные камни и вид «AI slop»"}, {"id": "open-design", "label": "Дизайн с Cursor в Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-cursor", "heading": "Чем на самом деле является Cursor", "blocks": [{"kind": "p", "text": "Cursor — это AI-first редактор кода, созданный Anysphere. Это форк VS Code, поэтому он сохраняет привычный редактор, расширения и горячие клавиши, но перестраивает рабочий процесс вокруг ИИ-агента, который умеет читать весь ваш проект, редактировать множество файлов, выполнять команды и итерировать вместе с вами в цикле."}, {"kind": "p", "text": "Для дизайн-работы важны режим Agent (вы описываете результат, а Cursor планирует и редактирует по файлам), инлайн-правки и дополнения Tab для быстрых правок, предпросмотр / браузер прямо в редакторе, чтобы видеть работающий UI, не покидая окно, и поддержка MCP, позволяющая подтягивать внешний контекст, например живой файл Figma."}, {"kind": "steps", "items": [{"label": "Правила проекта", "body": "Cursor читает файлы инструкций проекта — версионируемые правила `.mdc` в `.cursor/rules` и обычный `AGENTS.md` — так что вы можете зафиксировать дизайн-конвенции там, где агент читает их при каждом запуске."}, {"label": "Модели", "body": "Cursor гибок по моделям: он поставляется с передовыми моделями через вашу подписку, а также поддерживает использование собственных ключей моделей, так что вы выбираете движок за тем же рабочим процессом редактора."}, {"label": "MCP", "body": "Он говорит на Model Context Protocol, так что внешние серверы — в первую очередь сервер Figma MCP — становятся первоклассным контекстом для агента."}]}, {"kind": "ul", "items": ["Поставщик: Anysphere", "Учётные данные: аккаунт / подписка Cursor (Hobby / Pro / Business) или ваши собственные ключи моделей (BYOK)", "Форма: AI-first редактор кода (форк VS Code) со встроенным агентом и предпросмотром"]}]}, {"id": "why-design", "heading": "Почему Cursor хорош в дизайне", "blocks": [{"kind": "p", "text": "Преимущество Cursor в дизайне — не отдельная фича, а теснота цикла «собери и посмотри». Три вещи делают его похожим на дизайн-инструмент, а не на общий генератор кода."}, {"kind": "steps", "items": [{"label": "Тесный цикл «итерируй и наблюдай»", "body": "Вы задаёте промпт, Cursor редактирует по файлам, а предпросмотр в редакторе отрисовывает результат немедленно — так вы правите отступы, иерархию и анимацию за секунды, вместо того чтобы ходить туда-сюда через отдельный терминал и браузер."}, {"label": "Прямое визуальное редактирование", "body": "Помимо чата, Cursor позволяет выбирать элементы в предпросмотре и подкручивать стили, так что мелкие визуальные правки ощущаются как дизайн-правки, а не как археология кода."}, {"label": "Правила проекта и контекст MCP", "body": "С `.cursor/rules` (или `AGENTS.md`) и сервером Figma MCP агент работает с вашими tokens, компонентами и реальными дизайн-спецификациями, а не угадывает."}]}, {"kind": "image", "src": "/agents/cursor-design/cursor-design-taste-triangle.webp", "alt": "Диаграмма, показывающая, как дизайн-система, skill и референсное изображение сходятся в хороший дизайн-результат", "caption": "Вкус рождается из трёх вводных, которые вы предоставляете: дизайн-системы, skill и реальных референсных изображений."}, {"kind": "p", "text": "Урок тот же, что преподаёт каждый агент: у Cursor по умолчанию нет вкуса. Он создаёт хороший дизайн, когда вы даёте ему ограничения — дизайн-систему, эстетический skill и конкретные референсы. Open Design упаковывает именно эти вводные, поэтому они так хорошо сочетаются (подробнее ниже)."}]}, {"id": "setup", "heading": "Настройка Cursor для дизайна с нуля", "blocks": [{"kind": "p", "text": "Вот полный путь от чистой машины до Cursor, способного собирать, предпросматривать и проверять UI на соответствие вашей дизайн-системе."}, {"kind": "ol", "items": ["Установите Cursor с cursor.com и войдите со своим аккаунтом Cursor либо настройте собственные ключи моделей (BYOK) в Settings.", "Откройте свой проект и выберите модель на панели чата / Agent.", "Добавьте правила проекта: создайте `.cursor/rules/*.mdc` для структурированных конвенций с областью по glob либо обычный `AGENTS.md` для простых, читаемых инструкций.", "Подключите сервер Figma MCP (опционально), чтобы агент мог читать живой дизайн-контекст.", "Запустите dev-сервер и используйте предпросмотр в редакторе, чтобы видеть и проверять UI по мере итерации."]}, {"kind": "image", "src": "/agents/cursor-design/cursor-design-setup-flow.webp", "alt": "Пятишаговый процесс настройки: установка, аутентификация, настройка правил, добавление skill, проверка", "caption": "Последовательность настройки: установка → аутентификация → настройка правил проекта → добавление skill → включение проверки в предпросмотре."}, {"kind": "p", "text": "Минимальный файл правил проекта заставляет агента проектировать под бренд, а не сваливаться в шаблонный вид. Поместите его туда, где Cursor читает его при каждом запуске:"}, {"kind": "code", "lang": "markdown", "code": "# .cursor/rules/design.mdc\n---\ndescription: Project design conventions\nalwaysApply: true\n---\n\n- Reuse existing design-system tokens and components; never hardcode hex or spacing.\n- At most two typefaces and one accent color.\n- Brand-first hierarchy; restrained motion. No hero cards, no oversized rounded corners.\n- Build responsive by default; verify desktop and mobile in the preview before finishing."}, {"kind": "steps", "items": [{"label": "Зафиксируйте свои дизайн-правила", "body": "Поместите свои tokens, примитивы и конвенции в `.cursor/rules` или `AGENTS.md` и направьте Cursor к ним, чтобы вывод соответствовал бренду, а не сваливался в шаблонный вид."}, {"label": "Держите промпты короткими", "body": "Тесный цикл Cursor вознаграждает сфокусированные запросы — итерируйте по одному компоненту или состоянию за раз и смотрите на предпросмотр между проходами."}]}]}, {"id": "preview-workflow", "heading": "Рабочий процесс «предпросмотр в UI»", "blocks": [{"kind": "p", "text": "Самый эффективный дизайн-цикл с Cursor — это превращение референса в работающий, адаптивный UI и итерация в редакторе до совпадения, наблюдая живой предпросмотр всё время, а не угадывая."}, {"kind": "ol", "items": ["Начинайте с самых ясных визуальных референсов, что у вас есть, — и включайте несколько состояний (десктоп и мобильный, hover, пустое, загрузка), а не только один hero-кадр.", "Будьте конкретны в промпте; расплывчатые промпты дают шаблонный UI.", "Подготовьте дизайн-систему и подскажите Cursor, где лежат tokens и канонические примитивы.", "Держите предпросмотр в редакторе открытым, а dev-сервер запущенным, чтобы каждая правка отрисовывалась немедленно на нужных вам брейкпоинтах.", "Итерируйте, сравнивая отрисованный UI с референсами, — и используйте прямой выбор элементов в предпросмотре для мелких визуальных правок."]}, {"kind": "p", "text": "Передавайте референсы, прикрепляя изображение к чату, затем задавайте промпт с конкретными ограничениями:"}, {"kind": "code", "lang": "text", "code": "Implement this design in React + Vite + Tailwind + TypeScript.\nReuse my existing design-system components and tokens.\nMatch spacing, layout, and hierarchy; make it responsive.\nKeep the preview open — verify desktop and mobile match the\nreferences and iterate until they do."}, {"kind": "p", "text": "Коммитьте удачные итерации и откатывайте неудачные (сообщая Cursor об откате), чтобы каждый проход строился на чистой основе — та же дисциплина, что удерживает любой агентный цикл от дрейфа."}]}, {"id": "figma", "heading": "Cursor + Figma: дизайн ↔ код поверх MCP", "blocks": [{"kind": "p", "text": "Cursor подключается к Figma через официальный сервер Figma MCP, дающий агенту структурированный доступ к живому файлу Figma вместо плоского скриншота. Это убирает угадывание из handoff."}, {"kind": "steps", "items": [{"label": "Дизайн → Код", "body": "Скопируйте ссылку фрейма в Figma, вставьте её в Cursor и попросите реализовать дизайн. Сервер MCP раскрывает реальный дизайн-контекст — компоненты, переменные, данные раскладки, tokens — так что сгенерированный код соответствует источнику, а не приближается к нему."}, {"label": "Оставайтесь согласованными", "body": "При согласованном использовании дизайн-tokens, стилей и компонентов в Figma (и Code Connect, где доступен) вывод Cursor остаётся сопоставленным с вашей реальной дизайн-системой, а не переизобретает примитивы."}]}, {"kind": "p", "text": "Настройте удалённый сервер Figma MCP один раз — и он доступен Cursor как первоклассный контекст. Поскольку MCP — открытый стандарт, тот же сервер переиспользуется в Cursor, Claude Code, Codex и VS Code — именно такая переносимая, мультиагентная возможность, которую Open Design создан оркестрировать."}]}, {"id": "vs", "heading": "Cursor против Codex против Claude Code для дизайна", "blocks": [{"kind": "p", "text": "Единого победителя в дизайн-работе нет — у каждого агента своя сильная сторона, и опытные команды комбинируют их. Честная сводка:"}, {"kind": "table", "columns": ["Агент", "Сила в дизайне", "Лучше всего для"], "rows": [["Cursor", "Визуальный цикл «собери и посмотри» с живым предпросмотром в редакторе и прямым редактированием элементов", "Тесная работа над UI «итерируй и наблюдай» внутри IDE"], ["Codex", "Сильная визуальная отточенность с frontend skill; понимание изображений и запуски в песочнице", "Делегированные асинхронные сборки и переносимые правила AGENTS.md"], ["Claude Code", "Конкретные дизайн-решения (hex, отступы, типографика) и UX с учётом кодовой базы", "Фронтенд-рассуждения и рефакторинги с большим контекстом"]]}, {"kind": "p", "text": "Повторяющийся вердикт сообщества: вкус исходит от людей — все три по умолчанию сваливаются в шаблонную эстетику без skills, референсов и ограничений. Вот настоящая проблема, которую нужно решить — и она по форме относится к дизайн-инструменту, а не к модели."}]}, {"id": "pitfalls", "heading": "Подводные камни и как избежать вида «AI slop»", "blocks": [{"kind": "p", "text": "Самая частая жалоба на дизайн, сгенерированный Cursor, в том, что он выглядит шаблонно — мягкие градиенты, плавающие панели, чрезмерно скруглённые углы, драматичные тени, вайб Inter-и-фиолетового, который «кричит, что это сделал ИИ». Среди других сообщаемых проблем — раскладки, ломающиеся на мобильном, и инструкции, протекающие в текст UI."}, {"kind": "steps", "items": [{"label": "Добавьте дизайн-skill", "body": "Курируемый эстетический skill заставляет Cursor задать реальное направление вместо вида по умолчанию."}, {"label": "Используйте предпросмотр для проверки", "body": "Отрисовывайте и самопроверяйте результат на разных брейкпоинтах в предпросмотре редактора, чтобы раскладки не ломались незаметно на мобильном."}, {"label": "Предоставьте tokens и референсы", "body": "Реальные дизайн-tokens и референсные скриншоты — самый сильный рычаг для качества вывода."}, {"label": "Зафиксируйте правила в `.cursor/rules`", "body": "Поместите правила вроде «без hero-карточек, максимум два шрифта, иерархия от бренда» туда, где агент читает их при каждом запуске."}]}, {"kind": "p", "text": "Обратите внимание: каждое из этих средств сводится к тому, чтобы дать агенту курируемый дизайн-контекст. Поддержка этого контекста вручную, для каждого проекта, — та рутина, которую устраняет Open Design."}]}, {"id": "open-design", "heading": "Дизайн с Cursor внутри Open Design", "blocks": [{"kind": "p", "text": "Open Design — это тот open-source дизайн-слой, которого процесс выше постоянно требует. Он рассматривает Cursor как нативный адаптер и оборачивает его в курируемую библиотеку skill и дизайн-систем, структурированный конвейер рендера и локальный десктопный UI — так что дизайн-контекст, делающий Cursor хорошим, есть с первого запуска, а не собирается вручную каждый раз."}, {"kind": "ol", "items": ["Установите Open Design и выберите Cursor как своего агента.", "Аутентифицируйтесь с помощью аккаунта Cursor или собственных ключей моделей (BYOK) — учётные данные остаются на вашей машине и никогда не проксируются через нас.", "Выберите дизайн-систему и skill, затем генерируйте презентации, прототипы и лендинги с единообразным вкусом.", "Каждый артефакт и файл DESIGN.md живёт в вашем собственном репозитории, а не в хостинговом облаке."]}, {"kind": "p", "text": "Тот же агент Cursor, тот же ключ — плюс настоящий, переносимый, open-source дизайн-процесс вокруг него. Он local-first и под Apache-2.0, так что ничто из вашей работы или ваших учётных данных не покидает машину."}]}], "faqTitle": "Часто задаваемые вопросы", "faq": [{"name": "Действительно ли Cursor способен на дизайн-работу?", "text": "Да — с дизайн-skill, дизайн-системой и реальными референсными изображениями в контексте Cursor создаёт продакшен-качественный, адаптивный UI, а его предпросмотр в редакторе позволяет проверять и дорабатывать его визуально. Без такого контекста он склонен сваливаться в шаблонный вид — и именно этот разрыв закрывает Open Design."}, {"name": "Это официальный продукт Cursor?", "text": "Нет. Open Design — независимый open-source проект, который интегрирует Cursor как агента. Он дополняет Cursor local-first, открытой библиотекой skill и дизайн-систем."}, {"name": "Нужна ли подписка Cursor, чтобы заниматься дизайном с Cursor?", "text": "Вы можете использовать аккаунт / подписку Cursor либо собственные ключи моделей (BYOK). В любом случае Open Design никогда не проксирует ваши учётные данные — они используются напрямую вашим агентом."}, {"name": "Cursor или Claude Code для фронтенд-дизайна?", "text": "Оба сильны. Claude Code известен конкретными, учитывающими кодовую базу дизайн-решениями; преимущество Cursor — его тесный цикл «собери и посмотри» с живым предпросмотром внутри редактора. Многие команды используют оба — Open Design позволяет переключать агентов, не меняя дизайн-процесс."}, {"name": "Как подключить Cursor к Figma?", "text": "Добавьте официальный сервер Figma MCP в Cursor, затем вставьте ссылку на фрейм Figma в чат и попросите Cursor реализовать его. Сервер раскрывает реальные компоненты, переменные и данные раскладки, так что сгенерированный код соответствует исходному дизайну."}, {"name": "Как избежать шаблонной эстетики «AI slop»?", "text": "Добавьте дизайн-skill, предоставьте реальные дизайн-tokens и референсные скриншоты, зафиксируйте правила бренда в `.cursor/rules` или `AGENTS.md` и проверяйте на разных брейкпоинтах в предпросмотре. Open Design поставляет это как курируемую библиотеку, так что вы пропускаете настройку под каждый проект."}, {"name": "Связан ли Open Design с Cursor или Anysphere?", "text": "Нет. Cursor — продукт Anysphere; Open Design — независимый open-source проект, который поддерживает его как нативный адаптер. Cursor и Anysphere являются товарными знаками Anysphere, Inc."}, {"name": "В безопасности ли мои файлы и учётные данные?", "text": "Да — Open Design является local-first. Ваши файлы, артефакты и DESIGN.md остаются в вашем собственном репозитории, а ваши учётные данные Cursor или моделей используются напрямую вашим агентом и никогда не маршрутизируются через серверы Open Design."}], "ctaTitle": "Дизайн с Cursor, по-открытому.", "ctaBody": "Используйте свой аккаунт Cursor или ключи моделей, держите каждый файл локально и получите курируемую дизайн-библиотеку вокруг агента, которым вы уже пользуетесь.", "ctaActions": [{"label": "Использовать Cursor в Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Поставить звезду на GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Скачать десктопное приложение", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Посмотреть всех поддерживаемых агентов"},
      },
      'opencode': {
        ...en['opencode']!,
        title: "OpenCode для дизайна — Open Design",
        description: "Как люди используют OpenCode для UI и веб-дизайна — файлы design.md, UI/UX skills, Figma MCP — и как Open Design превращает OpenCode в local-first, open-source дизайн-агента.",
        breadcrumb: "OpenCode",
        label: "Агент · OpenCode",
        heading: "OpenCode для дизайна.",
        lead: "OpenCode — это open-source терминальный ИИ-агент для кодинга. Дизайнеры навешивают на него дизайн-skills и файлы DESIGN.md, чтобы генерировать настоящий UI. Open Design делает это структурированным, open-source процессом — используйте свои ключи провайдеров и держите всё локально.",
        rich: {"heroCtaLead": "Open Design превращает OpenCode в local-first, open-source дизайн-агента — любая модель на ваш выбор с вашим собственным ключом провайдера, ваши файлы и курируемая библиотека skill и дизайн-систем вокруг него.", "heroCtaActions": [{"label": "Использовать OpenCode в Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Поставить звезду на GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Скачать десктопное приложение", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["OpenCode — это open-source, терминальный ИИ-агент для кодинга, намеренно независимый от моделей: вы используете собственный ключ провайдера и запускаете любую модель за тем же рабочим процессом. Эта открытость делает его естественной базой для дизайн-работы — но, как и любой агент, он создаёт хороший UI лишь тогда, когда вы даёте ему правильные референсы, skills и цикл проверки. Это практичное, сквозное руководство по использованию OpenCode для UI, фронтенда и работы с дизайн-системами, а также по встраиванию его в структурированный дизайн-процесс с Open Design.", "Оно охватывает то, чем на самом деле является OpenCode, почему независимый от моделей открытый агент хорошо подходит для дизайна, как настроить его с нуля, цикл «скриншот в UI», как AGENTS.md и MCP расширяют его, как он сравнивается с Codex, Claude Code и Cursor, какие подводные камни делают вывод ИИ шаблонным и как Open Design закрывает этот разрыв как открытый, local-first дизайн-слой — естественное сочетание, ведь оба проекта open-source и работают на вашей собственной машине."], "heroImage": {"src": "/agents/opencode-design/opencode-design-hero.webp", "alt": "Цикл обратной связи дизайна OpenCode: терминальный TUI-агент, браузер отрисовывает UI и рабочее пространство со стрелкой обратной связи, замыкающей цикл", "caption": "Ключевой цикл: OpenCode собирает UI в терминале, отрисовывает и проверяет его в настоящем браузере и итерирует по вашим референсам — на любой модели по вашему выбору."}, "tocLabel": "На этой странице", "toc": [{"id": "what-is-opencode", "label": "Чем на самом деле является OpenCode"}, {"id": "why-design", "label": "Почему открытый агент с любой моделью подходит для дизайна"}, {"id": "setup", "label": "Настройка OpenCode для дизайна (с нуля)"}, {"id": "screenshot-workflow", "label": "Рабочий процесс «скриншот в UI»"}, {"id": "extend", "label": "AGENTS.md, MCP и общие сессии"}, {"id": "vs", "label": "OpenCode против Codex против Claude Code против Cursor"}, {"id": "pitfalls", "label": "Подводные камни и вид «AI slop»"}, {"id": "open-design", "label": "Дизайн с OpenCode в Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-opencode", "heading": "Чем на самом деле является OpenCode", "blocks": [{"kind": "p", "text": "OpenCode — это open-source ИИ-агент для кодинга, созданный для терминала и поддерживаемый командой, стоящей за SST (Anomaly Innovations). Он читает ваш репозиторий, выполняет команды, редактирует файлы и общается с большой языковой моделью — но, в отличие от агентов, привязанных к поставщику, он не поставляет собственную модель. Вы направляете его на любого провайдера и любую модель и используете собственный ключ."}, {"kind": "p", "text": "Он работает как терминальный UI (TUI), с десктопным приложением и расширениями IDE поверх того же движка. Под капотом он использует клиент-серверную архитектуру, так что агент, который делает работу, отделён от поверхности, с которой вы им управляете. Два встроенных агента — build и plan — переключаются клавишей Tab."}, {"kind": "steps", "items": [{"label": "Независимость от моделей", "body": "Модели и провайдеры берутся из models.dev — открытого каталога. Вы настраиваете их в opencode.json строкой provider/model-id и можете отключить нежелательных провайдеров — так что тот же дизайн-процесс работает на Anthropic, OpenAI, Google, OpenRouter, локальных моделях и не только."}, {"label": "Файл инструкций", "body": "OpenCode читает файл AGENTS.md в вашем проекте (кросс-инструментальный стандарт, также совместимый с CLAUDE.md) для правил проекта — естественное место, где можно зафиксировать ваши дизайн-конвенции. Запустите /init, чтобы сгенерировать его."}, {"label": "Расширяемость", "body": "Он поддерживает интеграцию LSP, серверы MCP, темы, горячие клавиши и пользовательские команды, плюс ссылки на общие сессии для совместной работы."}]}, {"kind": "ul", "items": ["Сопровождающий: SST / Anomaly Innovations (open-source проект)", "Учётные данные: ваши собственные API-ключи провайдеров моделей — BYOK, без привязки к поставщику", "Лицензия: MIT, open source"]}]}, {"id": "why-design", "heading": "Почему открытый агент с любой моделью подходит для дизайн-работы", "blocks": [{"kind": "p", "text": "У OpenCode нет единой «дизайн-модели», как у агента, привязанного к поставщику, — и в этом весь смысл. Поскольку он независим от моделей и открыт, вы можете запускать тот же дизайн-процесс на той модели, что сейчас лучшая во фронтенде, позже сменить её или откатиться к локальной модели — и всё это без изменения настройки."}, {"kind": "p", "text": "Но один лишь выбор модели не покупает вкус. Как и любой кодинг-агент, OpenCode создаёт шаблонный UI, пока вы не дадите ему ограничения. Хороший дизайн-результат рождается из трёх вводных, которые вы предоставляете."}, {"kind": "steps", "items": [{"label": "Дизайн-система", "body": "Реальные tokens, примитивы и конвенции, которые агент переиспользует, чтобы вывод соответствовал бренду, а не сваливался в шаблонный вид."}, {"label": "Эстетический skill", "body": "Курируемый skill, навязывающий реальный вкус — сдержанная анимация, иерархия от бренда, не более двух шрифтов и одного акцентного цвета — и заставляющий агента задать направление до сборки."}, {"label": "Конкретные референсы", "body": "Реальные референсные изображения и несколько состояний (десктоп и мобильный, hover, пустое, загрузка), а не один hero-кадр."}]}, {"kind": "image", "src": "/agents/opencode-design/opencode-design-taste-triangle.webp", "alt": "Диаграмма, показывающая, как дизайн-система, skill и референсное изображение сходятся в хороший дизайн-результат", "caption": "Вкус рождается из трёх вводных, которые вы предоставляете: дизайн-системы, skill и реальных референсных изображений — независимо от того, какую модель вы запускаете."}, {"kind": "p", "text": "Урок: OpenCode даёт вам свободу выбора модели, но вкус по-прежнему рождается из курируемого дизайн-контекста. Open Design упаковывает именно эти вводные, поэтому они так хорошо сочетаются — оба open-source и local-first (подробнее ниже)."}]}, {"id": "setup", "heading": "Настройка OpenCode для дизайна с нуля", "blocks": [{"kind": "p", "text": "Вот полный путь от чистой машины до OpenCode, способного создавать и проверять UI."}, {"kind": "code", "lang": "bash", "code": "# 1. Install OpenCode\ncurl -fsSL https://opencode.ai/install | bash\n# or: npm i -g opencode-ai@latest\n# or: brew install sst/tap/opencode\n\n# 2. Start the TUI in your project, then authenticate your provider\nopencode          # then run /login and pick your provider + paste your key\n\n# 3. Generate project context\nopencode          # inside your project, run /init to create AGENTS.md\n\n# 4. Pick your model (any provider, via models.dev)\n#    set \"provider/model-id\" in opencode.json or switch in the TUI\n\n# 5. Add an MCP server (optional, e.g. for design handoff)\n#    configure it under the \"mcp\" key in opencode.json"}, {"kind": "image", "src": "/agents/opencode-design/opencode-design-setup-flow.webp", "alt": "Пятишаговый процесс настройки: установка, аутентификация с ключом провайдера, настройка AGENTS.md, добавление skill, проверка", "caption": "Последовательность настройки: установка → аутентификация (ваш ключ провайдера) → настройка AGENTS.md → добавление skill → проверка в настоящем браузере."}, {"kind": "steps", "items": [{"label": "Зафиксируйте свои дизайн-правила", "body": "Поместите свои tokens, примитивы и конвенции в AGENTS.md (или DESIGN.md, на который он ссылается), чтобы вывод соответствовал бренду, а не сваливался в шаблонный вид. Опция instructions в opencode.json может указывать на дополнительные файлы правил через globs."}, {"label": "Выберите способную модель", "body": "Поскольку OpenCode независим от моделей, выберите для дизайн-прохода тот provider/model, что сейчас сильнее всего во фронтенде, — и оставьте остальной процесс без изменений."}]}]}, {"id": "screenshot-workflow", "heading": "Рабочий процесс «скриншот в UI»", "blocks": [{"kind": "p", "text": "Самый эффективный дизайн-цикл с любым агентом — это превращение референсного изображения в работающий, адаптивный UI и итерация до совпадения. Та же пятишаговая форма применима в OpenCode."}, {"kind": "ol", "items": ["Начинайте с самых ясных визуальных референсов, что у вас есть, — и включайте несколько состояний (десктоп и мобильный, hover, пустое, загрузка), а не только один hero-кадр.", "Будьте конкретны в промпте; расплывчатые промпты дают шаблонный UI.", "Подготовьте дизайн-систему и подскажите OpenCode, где лежат tokens и канонические примитивы (в AGENTS.md).", "Запустите dev-сервер и заставьте агента отрисовывать результат в настоящем браузере, меняя размер до брейкпоинтов, чтобы проверить результат.", "Итерируйте, заставляя OpenCode сравнивать свою реализацию со скриншотами, а не просто подтверждать сборку."]}, {"kind": "p", "text": "Ссылайтесь на файлы через @ в TUI для нечёткого поиска по рабочей директории, выполняйте shell-команды инлайн с ведущим !, и управляйте действиями через команды /. Затем задавайте промпт с конкретными ограничениями:"}, {"kind": "code", "lang": "bash", "code": "opencode\n# in the TUI:\n> @reference-desktop.png @reference-mobile.png\n  Implement this design in React + Vite + Tailwind + TypeScript.\n  Reuse my existing design-system components and tokens from AGENTS.md.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Run the dev server, open it in a browser, and iterate until the\n  UI matches the references across breakpoints."}, {"kind": "p", "text": "Держите промпты короткими и сфокусированными, коммитьте удачные итерации и откатывайте неудачные (сообщая OpenCode об откате), чтобы каждый проход строился на чистой основе."}]}, {"id": "extend", "heading": "AGENTS.md, MCP и общие сессии", "blocks": [{"kind": "p", "text": "Три точки расширения делают OpenCode практичным для длительной дизайн-работы, и все три аккуратно ложатся на открытый дизайн-процесс."}, {"kind": "steps", "items": [{"label": "Правила AGENTS.md", "body": "Правила проекта живут в AGENTS.md в корне репозитория (или глобальные правила в ~/.config/opencode/AGENTS.md). Это устойчивый дом для ваших дизайн-конвенций, читаемый при каждом запуске, и он совместим с файлами CLAUDE.md, которые используют другие агенты."}, {"label": "Серверы MCP", "body": "OpenCode поддерживает как локальные (command), так и удалённые (URL) серверы MCP, настраиваемые под ключом mcp — переносимый способ подтянуть дизайн-контекст и внешние инструменты, работающие в разных агентах, а не только в OpenCode."}, {"label": "Общие сессии", "body": "Команда /share создаёт публичную ссылку на диалог для совместной работы или ревью, а /unshare отзывает её — полезно для получения обратной связи по дизайн-проходу."}]}, {"kind": "p", "text": "Это переносимые, мультиагентные возможности — именно то, что Open Design создан оркестрировать, а не пересоздавать в каждом проекте."}]}, {"id": "vs", "heading": "OpenCode против Codex против Claude Code против Cursor для дизайна", "blocks": [{"kind": "p", "text": "Единого победителя в дизайн-работе нет — у каждого агента своя сильная сторона, и опытные команды комбинируют их. Честная сводка:"}, {"kind": "table", "columns": ["Агент", "Сила в дизайне", "Лучше всего для"], "rows": [["OpenCode", "Open-source и независимость от моделей; запуск любого провайдера за одним терминальным процессом", "Свобода BYOK, переключение моделей, полностью открытые и local-first сетапы"], ["Codex", "Сильная визуальная отточенность с frontend skill; понимание изображений", "Делегированные асинхронные сборки в песочнице, переносимые правила AGENTS.md"], ["Claude Code", "Конкретные дизайн-решения (hex, отступы, типографика) и UX с учётом кодовой базы", "Фронтенд-рассуждения и рефакторинги с большим контекстом"], ["Cursor", "Визуальный цикл «собери и посмотри» с живым предпросмотром и инлайн-правками", "Тесная работа над UI «итерируй и наблюдай» внутри IDE"]]}, {"kind": "p", "text": "Повторяющийся вердикт сообщества: вкус исходит от людей — все они по умолчанию сваливаются в шаблонную эстетику без skills, референсов и ограничений. Вот настоящая проблема, которую нужно решить — и она по форме относится к дизайн-инструменту, а не к модели, и именно поэтому открытый агент вроде OpenCode так хорошо сочетается с открытым дизайн-слоем."}]}, {"id": "pitfalls", "heading": "Подводные камни и как избежать вида «AI slop»", "blocks": [{"kind": "p", "text": "Самая частая жалоба на дизайн, сгенерированный ИИ, в том, что он выглядит шаблонно — мягкие градиенты, плавающие панели, чрезмерно скруглённые углы, драматичные тени, вайб Inter-и-фиолетового, который «кричит, что это сделал ИИ». Среди других сообщаемых проблем — сломанные мобильные раскладки и инструкции, протекающие в текст UI. Ничто из этого не уникально для OpenCode; это то, что происходит, когда любой агент работает без курируемого дизайн-контекста."}, {"kind": "steps", "items": [{"label": "Добавьте эстетический skill", "body": "Курируемый дизайн-skill заставляет агента задать реальное направление вместо вида по умолчанию."}, {"label": "Проверяйте в настоящем браузере", "body": "Отрисовывайте и самопроверяйте результат на разных брейкпоинтах, чтобы раскладки не ломались незаметно на мобильном."}, {"label": "Предоставьте tokens и референсы", "body": "Реальные дизайн-tokens и референсные скриншоты — самый сильный рычаг для качества вывода."}, {"label": "Зафиксируйте правила в AGENTS.md", "body": "Поместите правила вроде «без hero-карточек, максимум два шрифта, иерархия от бренда» туда, где агент читает их при каждом запуске."}]}, {"kind": "p", "text": "Обратите внимание: каждое из этих средств сводится к тому, чтобы дать агенту курируемый дизайн-контекст — независимо от того, какую модель вы запускаете. Поддержка этого контекста вручную, для каждого проекта, — та рутина, которую устраняет Open Design."}]}, {"id": "open-design", "heading": "Дизайн с OpenCode внутри Open Design", "blocks": [{"kind": "p", "text": "Open Design — это тот open-source дизайн-слой, которого процесс выше постоянно требует. Он рассматривает OpenCode как нативный адаптер и оборачивает его в курируемую библиотеку skill и дизайн-систем, структурированный конвейер рендера и локальный десктопный UI — так что дизайн-контекст, делающий любого агента хорошим, есть с первого запуска, а не собирается вручную каждый раз. Оба проекта open-source и local-first, что делает их сочетание естественным."}, {"kind": "ol", "items": ["Установите Open Design и выберите OpenCode как своего агента.", "Аутентифицируйтесь с помощью собственного API-ключа провайдера моделей (BYOK) — учётные данные остаются на вашей машине и никогда не проксируются через нас.", "Выберите любого провайдера и модель, плюс дизайн-систему и skill, затем генерируйте презентации, прототипы и лендинги с единообразным вкусом.", "Каждый артефакт и файл DESIGN.md живёт в вашем собственном репозитории, а не в хостинговом облаке."]}, {"kind": "p", "text": "Тот же агент OpenCode, та же свобода выбора модели — плюс настоящий, переносимый, open-source дизайн-процесс вокруг него. Он local-first и под Apache-2.0, так что ничто из вашей работы или ваших учётных данных не покидает машину."}]}], "faqTitle": "Часто задаваемые вопросы", "faq": [{"name": "Действительно ли OpenCode способен на дизайн-работу?", "text": "Да — с эстетическим skill, дизайн-системой и реальными референсными изображениями в контексте OpenCode создаёт продакшен-качественный, адаптивный UI и может проверить его в браузере. Поскольку он независим от моделей, вы запускаете ту модель, что сейчас лучшая во фронтенде. Без такого курируемого контекста он склонен сваливаться в шаблонный вид — и именно этот разрыв закрывает Open Design."}, {"name": "Какую модель использовать с OpenCode для дизайна?", "text": "Любую на ваш вкус — OpenCode независим от провайдера через models.dev, так что вы можете запускать Anthropic, OpenAI, Google, OpenRouter или локальные модели за тем же рабочим процессом и переключаться в любой момент. Качество дизайн-вывода зависит куда больше от вашего skill, дизайн-системы и референсов, чем от одной только модели."}, {"name": "Сделан ли Open Design командой OpenCode (SST)?", "text": "Нет. Open Design — независимый open-source проект, который интегрирует OpenCode как агента. Он дополняет OpenCode local-first, открытой библиотекой skill и дизайн-систем."}, {"name": "Нужна ли специальная подписка, чтобы заниматься дизайном с OpenCode?", "text": "Нет — OpenCode работает по BYOK. Вы используете собственный API-ключ провайдера моделей, и Open Design никогда не проксирует ваши учётные данные. Привязки к поставщику нет."}, {"name": "OpenCode, Codex или Claude Code для фронтенд-дизайна?", "text": "Все сильны, и многие команды комбинируют их. Преимущество OpenCode — полная открытость и независимость от моделей; Codex блистает в делегированных сборках в песочнице; Claude Code известен конкретными, учитывающими кодовую базу дизайн-решениями. Open Design позволяет переключать агентов, не меняя дизайн-процесс."}, {"name": "Как расширить OpenCode для дизайн-контекста?", "text": "Зафиксируйте правила в AGENTS.md, добавьте серверы MCP под ключом mcp для переносимых инструментов и дизайн-контекста и используйте общие сессии для ревью. Open Design поставляет курируемую библиотеку skill и дизайн-систем, так что вы пропускаете настройку под каждый проект."}, {"name": "Связан ли Open Design с OpenCode или SST?", "text": "Нет. OpenCode — open-source проект, поддерживаемый SST (Anomaly Innovations); Open Design — независимый open-source проект, который поддерживает его как нативный адаптер."}, {"name": "В безопасности ли мои файлы и учётные данные?", "text": "Да — Open Design является local-first. Ваши файлы, артефакты и DESIGN.md остаются в вашем собственном репозитории, а ваши учётные данные провайдера моделей используются напрямую вашим агентом и никогда не маршрутизируются через серверы Open Design."}], "ctaTitle": "Дизайн с OpenCode, по-открытому.", "ctaBody": "Используйте свой ключ провайдера моделей, держите каждый файл локально и получите курируемую дизайн-библиотеку вокруг открытого агента, которым вы уже пользуетесь.", "ctaActions": [{"label": "Использовать OpenCode в Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Поставить звезду на GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Скачать десктопное приложение", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Посмотреть всех поддерживаемых агентов"},
      },
    },
    'es': {
      'claude-code': {
        ...en['claude-code']!,
        title: "Claude Code para diseño — Open Design",
        description: "Cómo los diseñadores usan Claude Code para diseño de UI y web, y cómo Open Design lo convierte en un verdadero agente de diseño — local-first, BYOK, con una biblioteca curada de skills y sistemas de diseño.",
        breadcrumb: "Claude Code",
        label: "Agente · Claude Code",
        heading: "Claude Code para diseño.",
        lead: "Claude Code es el agente de codificación de terminal de Anthropic. La gente ya lo usa para construir interfaces, sistemas de diseño y landing pages. Open Design lo conecta a un flujo de trabajo de diseño real — usa tu clave de Anthropic o tu suscripción a Claude y mantén cada archivo en local.",
        rich: {"heroCtaLead": "Open Design convierte Claude Code en un agente de diseño open-source y local-first — tu clave de Anthropic o tu suscripción a Claude, tus archivos y una biblioteca curada de skills y sistemas de diseño a su alrededor.", "heroCtaActions": [{"label": "Usa Claude Code dentro de Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Dale una estrella en GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Descarga la aplicación de escritorio", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Claude Code es ampliamente considerado el agente de codificación con mejor gusto para el frontend — razona sobre las interfaces con una especificidad inusual, nombrando valores hex exactos, espaciados y escalas tipográficas, y refactoriza la UI a lo largo de una base de código grande sin perder el hilo. Pero, listo para usar, sigue derivando hacia un aspecto genérico a menos que le entregues un sistema de diseño, skills y referencias reales. Esta es una guía práctica y de extremo a extremo para usar Claude Code en trabajo de UI, frontend y sistemas de diseño, y para integrarlo en un flujo de trabajo estructurado con Open Design.", "Cubre qué es realmente Claude Code, por qué es fuerte en frontend, cómo configurarlo desde cero, el flujo de trabajo de CLAUDE.md y Skills, el round-trip oficial con Figma, cómo se compara con Codex y Cursor, los escollos que hacen que el resultado de la IA parezca genérico y cómo Open Design cierra esa brecha como una capa de diseño abierta y local-first."], "heroImage": {"src": "/agents/claude-code-design/claude-code-design-hero.webp", "alt": "Bucle de retroalimentación de diseño de Claude Code: un agente de terminal tomando decisiones de diseño específicas, un navegador renderizando la UI y un espacio de trabajo, con una flecha de retroalimentación que regresa en bucle", "caption": "El bucle central: Claude Code razona decisiones de UI específicas en la terminal, las renderiza y verifica en un navegador real, y converge contra tus referencias."}, "tocLabel": "En esta página", "toc": [{"id": "what-is-claude-code", "label": "Qué es realmente Claude Code"}, {"id": "why-design", "label": "Por qué Claude Code es bueno en diseño"}, {"id": "setup", "label": "Configura Claude Code para diseño (desde cero)"}, {"id": "skills-workflow", "label": "El flujo de trabajo de CLAUDE.md y Skills"}, {"id": "figma", "label": "Round-trip de Claude Code + Figma"}, {"id": "vs", "label": "Claude Code vs Codex vs Cursor"}, {"id": "pitfalls", "label": "Escollos y el aspecto de “bazofia de IA”"}, {"id": "open-design", "label": "Diseñar con Claude Code en Open Design"}, {"id": "faq", "label": "Preguntas frecuentes"}], "sections": [{"id": "what-is-claude-code", "heading": "Qué es realmente Claude Code", "blocks": [{"kind": "p", "text": "Claude Code es la herramienta de codificación agéntica de Anthropic. Lee tu base de código, edita archivos, ejecuta comandos y se integra con tus herramientas de desarrollo — planifica, escribe y verifica el trabajo a partir de tareas en lenguaje natural, en lugar de limitarse a autocompletar líneas."}, {"kind": "p", "text": "Se distribuye en varias superficies que comparten el mismo motor: una CLI de terminal, extensiones de IDE para VS Code, Cursor y JetBrains, una aplicación de escritorio con revisión visual de diferencias, y una experiencia web para tareas de larga duración. Tus archivos CLAUDE.md, ajustes y servidores MCP se trasladan a todas ellas."}, {"kind": "steps", "items": [{"label": "Archivo de instrucciones", "body": "Claude Code lee un archivo CLAUDE.md en la raíz de tu proyecto al inicio de cada sesión — el lugar natural para codificar tus convenciones de diseño, tokens y listas de verificación de revisión."}, {"label": "Skills", "body": "Las Agent Skills empaquetan instrucciones, scripts y recursos reutilizables que Claude carga bajo demanda, incluida la skill oficial de Frontend Design de Anthropic para el gusto."}, {"label": "Planificación y subagentes", "body": "Puede planificar antes de actuar y generar subagentes que trabajan en distintas partes de una tarea en paralelo, lo que mantiene coherentes las refactorizaciones grandes de UI."}]}, {"kind": "ul", "items": ["Proveedor: Anthropic", "Credencial: clave de API de Anthropic (BYOK, a través de la Console) o una suscripción a Claude (Pro / Max)", "Superficies: CLI de terminal, extensiones de VS Code / Cursor / JetBrains, aplicación de escritorio, web"]}]}, {"id": "why-design", "heading": "Por qué Claude Code es bueno en diseño", "blocks": [{"kind": "p", "text": "Entre los agentes de codificación, Claude Code tiene reputación de buen gusto en el trabajo de frontend. Hay varias razones que lo explican."}, {"kind": "steps", "items": [{"label": "Decisiones específicas, no vagas", "body": "Claude Code tiende a comprometerse con opciones concretas — valores hex exactos, escalas de espaciado, rampas tipográficas y jerarquía de componentes — en lugar de andar con rodeos, que es lo que separa una interfaz real de un marcador de posición."}, {"label": "Razonamiento consciente de la base de código", "body": "Con un contexto de trabajo amplio, refactoriza la UI a través de muchos archivos a la vez, reutilizando tus componentes y tokens existentes en lugar de reinventar estilos puntuales."}, {"label": "Una skill de frontend oficial", "body": "Anthropic ofrece una skill de Frontend Design que hace que Claude escriba primero una dirección de diseño y se aleje deliberadamente de las fuentes de sistema genéricas y los predecibles degradados morados."}]}, {"kind": "image", "src": "/agents/claude-code-design/claude-code-design-taste-triangle.webp", "alt": "Diagrama que muestra el sistema de diseño, la skill y la imagen de referencia convergiendo en un buen resultado de diseño", "caption": "El gusto proviene de tres insumos que tú aportas: un sistema de diseño, una skill e imágenes de referencia reales."}, {"kind": "p", "text": "La lección es la misma que Anthropic plantea sobre sus propios modelos: Claude no tiene gusto por defecto — librado a su suerte, converge hacia el centro estadístico del diseño web (Inter, degradados morados, sombras suaves). Produce buen diseño cuando le das restricciones. Open Design empaqueta exactamente esos insumos, y por eso ambos encajan (más abajo)."}]}, {"id": "setup", "heading": "Configura Claude Code para trabajo de diseño, desde cero", "blocks": [{"kind": "p", "text": "Este es el camino completo desde una máquina limpia hasta un Claude Code capaz de construir y verificar UI."}, {"kind": "code", "lang": "bash", "code": "# 1. Install Claude Code (native install, recommended)\ncurl -fsSL https://claude.ai/install.sh | bash\n# or: brew install --cask claude-code\n# Windows PowerShell: irm https://claude.ai/install.ps1 | iex\n\n# 2. Start it in your project and sign in on first run\ncd your-project\nclaude            # sign in with your Claude subscription or API key\n\n# 3. Generate project context\n/init             # creates a CLAUDE.md for this project\n\n# 4. Add the official Frontend Design skill\nclaude plugin install frontend-design@claude-plugins-official\n\n# 5. Wire the Figma MCP server (optional, for design handoff)\nclaude plugin install figma@claude-plugins-official"}, {"kind": "image", "src": "/agents/claude-code-design/claude-code-design-setup-flow.webp", "alt": "Flujo de configuración de cinco pasos: instalar, autenticar, configurar CLAUDE.md, añadir skill, verificar", "caption": "La secuencia de configuración: instalar → autenticar → configurar CLAUDE.md → añadir la skill de Frontend Design → habilitar la verificación en el navegador."}, {"kind": "steps", "items": [{"label": "Codifica tus reglas de diseño", "body": "Coloca tus tokens, primitivas y convenciones en CLAUDE.md y dirige a Claude hacia ellas, para que el resultado coincida con una marca en lugar de recaer en un aspecto genérico."}, {"label": "Añade verificación en el navegador", "body": "Conecta un MCP de Playwright o Chrome para que Claude renderice en un navegador real y compruebe su resultado en distintos breakpoints, en lugar de solo confirmar que la compilación pasa."}]}]}, {"id": "skills-workflow", "heading": "El flujo de trabajo de CLAUDE.md y Skills", "blocks": [{"kind": "p", "text": "El bucle de diseño de mayor apalancamiento con Claude Code es alimentarlo con referencias reales más tu contexto de diseño, y luego iterar hasta que la UI coincida — con CLAUDE.md y Skills llevando las restricciones, para que no las vuelvas a explicar en cada prompt."}, {"kind": "ol", "items": ["Parte de las referencias visuales más claras que tengas — e incluye varios estados (escritorio y móvil, hover, vacío, cargando), no solo una única toma principal.", "Sé específico en el prompt; los prompts vagos producen UI genérica incluso con un agente potente.", "Mantén tu sistema de diseño y tus convenciones en CLAUDE.md, e indícale a Claude dónde viven los tokens y las primitivas canónicas.", "Añade la skill de Frontend Design para que Claude se comprometa con una dirección estética real antes de escribir código.", "Conecta la verificación en el navegador para que Claude renderice, redimensione a los breakpoints y compare con las referencias — no solo confirme que compila."]}, {"kind": "p", "text": "Arrastra una imagen de referencia a la sesión y formula el prompt con restricciones concretas:"}, {"kind": "code", "lang": "bash", "code": "claude \"Implement reference-desktop.png and reference-mobile.png in\n  React + Vite + Tailwind + TypeScript.\n  Reuse the design-system components and tokens described in CLAUDE.md.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Render it in the browser, verify it matches the references across\n  breakpoints, and iterate until it does.\""}, {"kind": "p", "text": "Ejecuta un servidor de desarrollo en paralelo, mantén los prompts pequeños y enfocados, y confirma las buenas iteraciones / revierte las malas (diciéndole a Claude cuándo reviertes) para que cada pasada parta de una base limpia. Usa el modo de planificación para refactorizaciones más grandes, de modo que puedas revisar el enfoque antes de que se modifique cualquier archivo."}]}, {"id": "figma", "heading": "Claude Code + Figma: round-trip diseño ↔ código", "blocks": [{"kind": "p", "text": "En febrero de 2026, Anthropic y Figma lanzaron una integración bidireccional de primera clase a través del servidor MCP de Figma. Funciona en ambas direcciones."}, {"kind": "steps", "items": [{"label": "Diseño → Código", "body": "Selecciona un frame en Figma o pega un enlace en Claude Code, extrae el contexto de diseño y pídele que implemente el diseño usando tu biblioteca de componentes existente. Code Connect mantiene el resultado alineado con tus componentes reales."}, {"label": "Código → Diseño", "body": "Construye y previsualiza una funcionalidad en el navegador, y luego di “Send this to Figma” para capturar la UI en ejecución como capas editables de Figma — pantalla completa o un elemento seleccionado."}]}, {"kind": "p", "text": "Instálalo una vez con claude plugin install figma@claude-plugins-official (el MCP de Dev Mode requiere un plan de pago de Figma). El mismo MCP de Figma está disponible para Claude Code, Codex, Cursor y VS Code — exactamente el tipo de capacidad portátil y multiagente que Open Design está hecho para orquestar."}]}, {"id": "vs", "heading": "Claude Code vs Codex vs Cursor para diseño", "blocks": [{"kind": "p", "text": "No hay un único ganador para el trabajo de diseño — cada agente tiene una fortaleza distinta, y los equipos con experiencia los combinan. Un resumen justo:"}, {"kind": "table", "columns": ["Agente", "Fortaleza de diseño", "Mejor para"], "rows": [["Claude Code", "Decisiones de diseño específicas (hex, espaciado, tipografía) y razonamiento de UX consciente de la base de código", "Razonamiento de frontend y refactorizaciones de gran contexto"], ["Codex", "Fuerte pulido visual y comprensión de imágenes; compilaciones asíncronas en sandbox", "Compilaciones asíncronas delegadas y reglas portátiles de AGENTS.md"], ["Cursor", "Bucle visual de construir y ver con vista previa en vivo y ediciones en línea", "Trabajo de UI ajustado de iterar y observar dentro de un IDE"]]}, {"kind": "p", "text": "El veredicto recurrente de la comunidad es que el gusto proviene de las personas: los tres recaen en una estética genérica sin skills, referencias y restricciones. Ese es el verdadero problema a resolver — y tiene forma de herramienta de diseño, no de modelo."}]}, {"id": "pitfalls", "heading": "Escollos y cómo evitar el aspecto de “bazofia de IA”", "blocks": [{"kind": "p", "text": "Incluso con la reputación de buen gusto de Claude Code, la queja más común sobre el diseño generado por IA es que parece genérico — fuentes Inter, degradados morados sobre blanco, sombras suaves, esquinas redondeadas excesivas, una estética que “grita que esto lo hizo una IA”. La propia Anthropic lo atribuye a la convergencia distribucional: las opciones seguras dominan los datos de entrenamiento web. Otros problemas reportados incluyen diseños móviles rotos e instrucciones que se filtran en el texto de la UI."}, {"kind": "steps", "items": [{"label": "Instala la skill de Frontend Design", "body": "Obliga a Claude a comprometerse con una dirección real y evita explícitamente las fuentes y degradados sobreutilizados por la IA."}, {"label": "Habilita la verificación en el navegador", "body": "Haz que Claude renderice y se autoverifique en distintos breakpoints para que los diseños no se rompan en silencio en móvil."}, {"label": "Aporta tokens y referencias", "body": "Los tokens de diseño reales y las capturas de referencia son la mayor palanca sobre la calidad del resultado."}, {"label": "Codifica reglas en CLAUDE.md", "body": "Pon reglas de estilo como “sin tarjetas hero, máximo dos tipografías, jerarquía centrada en la marca” donde el agente las lea en cada ejecución."}]}, {"kind": "p", "text": "Observa que cada mitigación consiste en dar al agente un contexto de diseño curado. Mantener ese contexto a mano, proyecto a proyecto, es el trabajo pesado que Open Design elimina."}]}, {"id": "open-design", "heading": "Diseñar con Claude Code dentro de Open Design", "blocks": [{"kind": "p", "text": "Open Design es la capa de diseño open-source que el flujo de trabajo anterior no deja de pedir. Trata a Claude Code como un adaptador de primera parte y lo envuelve en una biblioteca curada de skills y sistemas de diseño, una canalización de render estructurada y una UI de escritorio local — para que el contexto de diseño que hace bueno a Claude Code esté ahí desde la primera ejecución, no se ensamble a mano cada vez."}, {"kind": "ol", "items": ["Instala Open Design y selecciona Claude Code como tu agente.", "Autentícate con tu clave de API de Anthropic (BYOK) o tu suscripción a Claude — las credenciales permanecen en tu máquina y nunca pasan por nuestros servidores.", "Elige un sistema de diseño y una skill, y luego genera presentaciones, prototipos y landing pages con un gusto consistente.", "Cada artefacto y archivo DESIGN.md vive en tu propio repositorio, no en una nube alojada."]}, {"kind": "p", "text": "El mismo agente Claude Code, la misma clave — más un flujo de trabajo de diseño real, portátil y open-source a su alrededor. Es local-first y Apache-2.0, así que nada de tu trabajo ni de tus credenciales sale de tu máquina."}]}], "faqTitle": "Preguntas frecuentes", "faq": [{"name": "¿Es Claude Code bueno para el trabajo de diseño?", "text": "Sí — es ampliamente considerado el agente de codificación con mejor gusto para el frontend, tomando decisiones específicas y conscientes de la base de código sobre valores hex, espaciado y escalas tipográficas. Con la skill de Frontend Design, un sistema de diseño e imágenes de referencia reales en contexto, produce UI responsive de calidad de producción y puede verificarla en un navegador. Sin ese contexto tiende a recaer en un aspecto genérico, que es la brecha que Open Design cubre."}, {"name": "¿Necesito una suscripción a Claude para diseñar con Claude Code?", "text": "Puedes usar una clave de API de Anthropic (BYOK, a través de la Console) o una suscripción a Claude (Pro / Max). En cualquier caso, Open Design nunca actúa como proxy de tus credenciales — las usa directamente tu agente en tu máquina."}, {"name": "¿Claude Code o Codex para diseño de frontend?", "text": "Ambos son fuertes. Claude Code es conocido por decisiones de diseño específicas y conscientes de la base de código y por su razonamiento de frontend; Codex tiene un fuerte pulido visual y destaca en compilaciones delegadas en sandbox. Muchos equipos usan ambos — Open Design te permite cambiar de agente sin cambiar tu flujo de trabajo de diseño."}, {"name": "¿Cómo conecto Claude Code con Figma?", "text": "Instala el plugin oficial de Figma con claude plugin install figma@claude-plugins-official. Después podrás implementar frames de Figma en código usando el contexto de diseño, y enviar una UI en ejecución de vuelta a frames editables de Figma con “Send this to Figma”. El MCP de Dev Mode requiere un plan de pago de Figma."}, {"name": "¿Qué son las Skills y CLAUDE.md?", "text": "CLAUDE.md es un archivo markdown en la raíz de tu proyecto que Claude Code lee al inicio de cada sesión — el lugar para codificar tus convenciones de diseño. Las Skills empaquetan instrucciones y recursos reutilizables que Claude carga bajo demanda, incluida la skill oficial de Frontend Design de Anthropic. Open Design incluye una biblioteca curada de ambos para que te saltes la configuración por proyecto."}, {"name": "¿Cómo evito la estética genérica de “bazofia de IA”?", "text": "Instala la skill de Frontend Design, aporta tokens de diseño reales y capturas de referencia, codifica las reglas de marca en CLAUDE.md y habilita la verificación en el navegador. Open Design incluye todo esto como una biblioteca curada para que te saltes la configuración por proyecto."}, {"name": "¿Está Open Design afiliado a Anthropic?", "text": "No. Claude Code es un producto de Anthropic; Open Design es un proyecto open-source independiente que lo soporta como adaptador de primera parte. Claude y Claude Code son marcas comerciales de Anthropic."}, {"name": "¿Están seguros mis archivos y credenciales?", "text": "Sí — Open Design es local-first y Apache-2.0. Tus archivos, artefactos y DESIGN.md permanecen en tu propio repositorio, y tus credenciales de Anthropic las usa directamente tu agente, sin enrutarse nunca a través de los servidores de Open Design."}], "ctaTitle": "Diseña con Claude Code, a la manera abierta.", "ctaBody": "Usa tu propia clave de Anthropic o tu suscripción a Claude, mantén cada archivo en local y obtén una biblioteca de diseño curada alrededor del agente que ya usas.", "ctaActions": [{"label": "Usa Claude Code dentro de Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Dale una estrella en GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Descarga la aplicación de escritorio", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Ver todos los agentes compatibles"},
      },
      'codex': {
        ...en['codex']!,
        title: "Codex para diseño — Open Design",
        description: "Cómo la gente usa OpenAI Codex para diseño de UI y web — el plugin de Product Design, la integración con Figma, las skills de frontend — y cómo Open Design convierte a Codex en un agente de diseño open-source y local-first.",
        breadcrumb: "Codex",
        label: "Agente · Codex",
        heading: "Codex para diseño.",
        lead: "Codex es el agente de codificación de OpenAI. Con su plugin de Product Design y su integración con Figma se ha convertido en una herramienta de diseño seria. Open Design conecta a Codex con un flujo de trabajo de diseño open-source — tu clave de OpenAI o tu suscripción a ChatGPT, tus archivos, local-first.",
        rich: {"heroCtaLead": "Open Design convierte a Codex en un agente de diseño open-source y local-first — tu clave de OpenAI, tus archivos y una biblioteca curada de skills y sistemas de diseño a su alrededor.", "heroCtaActions": [{"label": "Usa Codex dentro de Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Dale una estrella en GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Descarga la aplicación de escritorio", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["OpenAI Codex empezó como un generador de código, pero en 2026 se convirtió en una herramienta creíble para diseñar interfaces reales — una vez que le das las referencias, skills y el bucle de verificación adecuados. Esta es una guía práctica y de extremo a extremo para usar Codex en trabajo de UI, frontend y sistemas de diseño, y para integrarlo en un flujo de trabajo de diseño estructurado con Open Design.", "Cubre qué es Codex hoy, por qué de repente es bueno en frontend, cómo configurarlo desde cero, el bucle de captura a UI, el round-trip oficial con Figma, cómo se compara con Cursor y Claude Code, los escollos que hacen que el resultado de la IA parezca genérico y cómo Open Design cierra esa brecha como una capa de diseño abierta y local-first."], "heroImage": {"src": "/agents/codex-design/codex-design-workflow-loop.webp", "alt": "Bucle de retroalimentación de diseño de Codex: un agente de terminal, un navegador renderizando la UI y un espacio de trabajo, con una flecha de retroalimentación que regresa en bucle", "caption": "El bucle central: Codex construye la UI en la terminal, la renderiza y verifica en un navegador real, e itera contra tus referencias."}, "tocLabel": "En esta página", "toc": [{"id": "what-is-codex", "label": "Qué es realmente OpenAI Codex"}, {"id": "why-design", "label": "Por qué Codex es bueno en diseño ahora"}, {"id": "setup", "label": "Configura Codex para diseño (desde cero)"}, {"id": "screenshot-workflow", "label": "El flujo de trabajo de captura a UI"}, {"id": "figma", "label": "Round-trip de Codex + Figma"}, {"id": "vs", "label": "Codex vs Cursor vs Claude Code"}, {"id": "pitfalls", "label": "Escollos y el aspecto de “bazofia de IA”"}, {"id": "open-design", "label": "Diseñar con Codex en Open Design"}, {"id": "faq", "label": "Preguntas frecuentes"}], "sections": [{"id": "what-is-codex", "heading": "Qué es realmente OpenAI Codex (y qué no es)", "blocks": [{"kind": "p", "text": "Primero, una aclaración que confunde a casi todos los que buscan “Codex”. El Codex original de OpenAI era un modelo de autocompletado de código de 2021 que impulsaba los primeros GitHub Copilot y fue descontinuado en 2023. No es de eso de lo que trata esta página. El Codex de hoy es la herramienta de codificación agéntica de OpenAI — planifica, escribe, ejecuta y verifica código a partir de tareas en lenguaje natural."}, {"kind": "p", "text": "El Codex moderno se distribuye en cuatro superficies: una CLI de terminal (reescrita en Rust, con licencia Apache-2.0), una extensión de IDE para VS Code, Cursor y Windsurf, una experiencia cloud/web para tareas asíncronas delegadas, y una aplicación de escritorio con un navegador integrado y Computer Use."}, {"kind": "steps", "items": [{"label": "Modelo por defecto", "body": "A mediados de 2026, el modelo recomendado es gpt-5.5, siendo gpt-5.4 el modelo que OpenAI entrenó explícitamente para frontend y computer use."}, {"label": "Archivo de instrucciones", "body": "Codex lee un archivo AGENTS.md en tu proyecto (un estándar entre herramientas) para las reglas del proyecto — el lugar natural para codificar tus convenciones de diseño."}, {"label": "Sandbox", "body": "Se ejecuta en un sandbox a nivel de kernel (workspace-write por defecto), de modo que un agente que edita tu UI no puede salirse del proyecto."}]}, {"kind": "ul", "items": ["Proveedor: OpenAI", "Credencial: clave de API de OpenAI (BYOK) o suscripción a ChatGPT (Free / Go / Plus / Pro / Business / Enterprise)", "Licencia de la CLI: Apache-2.0, open source"]}]}, {"id": "why-design", "heading": "Por qué Codex es bueno en diseño ahora", "blocks": [{"kind": "p", "text": "Tres cosas convergieron a principios de 2026 para convertir a Codex en una verdadera herramienta de diseño en lugar de un generador de código genérico."}, {"kind": "steps", "items": [{"label": "Un modelo entrenado para frontend", "body": "OpenAI lanzó GPT-5.4, su primer modelo principal entrenado para frontend y computer use, con una comprensión de imágenes mucho mejor en todo el flujo de diseño y una autoverificación más sólida. Incluso puede generar mood boards y opciones visuales antes de comprometerse con los assets finales."}, {"label": "Una skill de frontend oficial", "body": "El catálogo openai/skills incluye una skill de frontend curada que impone gusto real: diseños sin tarjetas, heroes a sangre completa, jerarquía centrada en la marca, movimiento contenido, como máximo dos tipografías y un color de acento — y hace que Codex escriba una tesis visual antes de construir."}, {"label": "Verificación en el navegador", "body": "Con la skill de Playwright, Codex abre un navegador real, redimensiona a los breakpoints y compara su resultado con la referencia en lugar de solo comprobar que la compilación pasa."}]}, {"kind": "image", "src": "/agents/codex-design/codex-design-taste-triangle.webp", "alt": "Diagrama que muestra el sistema de diseño, la skill y la imagen de referencia convergiendo en un buen resultado de diseño", "caption": "El gusto proviene de tres insumos que tú aportas: un sistema de diseño, una skill e imágenes de referencia reales."}, {"kind": "p", "text": "La lección detrás de las tres: Codex no tiene gusto por defecto. Produce buen diseño cuando le das restricciones — un sistema de diseño, una skill estética y referencias concretas. Open Design empaqueta exactamente esos insumos, y por eso ambos encajan (más abajo)."}]}, {"id": "setup", "heading": "Configura Codex para trabajo de diseño, desde cero", "blocks": [{"kind": "p", "text": "Este es el camino completo desde una máquina limpia hasta un Codex capaz de construir y verificar UI."}, {"kind": "code", "lang": "bash", "code": "# 1. Install the Codex CLI\nnpm install -g @openai/codex\n# or: brew install --cask codex\n# or: curl -fsSL https://chatgpt.com/codex/install.sh | sh\n\n# 2. Authenticate (ChatGPT sign-in recommended for higher limits)\ncodex            # then choose “Sign in with ChatGPT”\n\n# 3. Generate project context\ncodex            # inside your project, run /init to create AGENTS.md\n\n# 4. Add the official frontend skill, then restart Codex\n# (in the Codex app) $skill-installer frontend-skill\n\n# 5. Wire the Figma MCP server (optional, for design handoff)\ncodex mcp add figma --url https://mcp.figma.com/mcp"}, {"kind": "image", "src": "/agents/codex-design/codex-design-setup-flow.webp", "alt": "Flujo de configuración de cinco pasos: instalar, autenticar, configurar, instalar skill, verificar", "caption": "La secuencia de configuración: instalar → autenticar → configurar AGENTS.md → instalar la skill de frontend → habilitar la verificación en el navegador."}, {"kind": "steps", "items": [{"label": "Codifica tus reglas de diseño", "body": "Coloca tus tokens, primitivas y convenciones en AGENTS.md o en un DESIGN.md y dirige a Codex hacia ellas, para que el resultado coincida con una marca en lugar de recaer en un aspecto genérico."}, {"label": "Elige el nivel de razonamiento adecuado", "body": "OpenAI señala que los niveles de razonamiento de bajo a medio suelen producir mejores resultados de frontend que el ajuste más alto."}]}]}, {"id": "screenshot-workflow", "heading": "El flujo de trabajo de captura a UI", "blocks": [{"kind": "p", "text": "El bucle de diseño de mayor apalancamiento con Codex es convertir una imagen de referencia en una UI funcional y responsive e iterar hasta que coincida. La propia guía de OpenAI se reduce a cinco pasos."}, {"kind": "ol", "items": ["Parte de las referencias visuales más claras que tengas — e incluye varios estados (escritorio y móvil, hover, vacío, cargando), no solo una única toma principal.", "Sé específico en el prompt; los prompts vagos producen UI genérica.", "Prepara un sistema de diseño e indícale a Codex dónde viven los tokens y las primitivas canónicas.", "Habilita la skill interactiva de Playwright para que Codex renderice en un navegador real y redimensione a los breakpoints.", "Itera haciendo que Codex compare su implementación con las capturas — no solo que confirme que compila."]}, {"kind": "p", "text": "Alimenta las imágenes arrastrando una captura a la terminal o con el flag de imagen, y luego formula el prompt con restricciones concretas:"}, {"kind": "code", "lang": "bash", "code": "codex -i reference-desktop.png -i reference-mobile.png \\\n  \"Implement this design in React + Vite + Tailwind + TypeScript.\n   Reuse my existing design-system components and tokens.\n   Match spacing, layout, and hierarchy; make it responsive.\n   Use the Playwright skill to verify the UI matches the\n   references and iterate until it does.\""}, {"kind": "p", "text": "Ejecuta un servidor de desarrollo en una segunda terminal, mantén los prompts pequeños y enfocados, y confirma las buenas iteraciones / revierte las malas (diciéndole a Codex cuándo reviertes) para que cada pasada parta de una base limpia."}]}, {"id": "figma", "heading": "Codex + Figma: round-trip diseño ↔ código", "blocks": [{"kind": "p", "text": "En febrero de 2026, OpenAI y Figma anunciaron una asociación oficial, convirtiendo la beta anterior del MCP de Figma en una integración bidireccional de primera clase. Funciona en ambas direcciones."}, {"kind": "steps", "items": [{"label": "Diseño → Código", "body": "Copia el “link to selection” de un frame en Figma, pégalo en Codex con get_design_context y pídele que implemente el diseño usando tu biblioteca de componentes existente."}, {"label": "Código → Diseño", "body": "La herramienta generate_figma_design (“Code to Canvas”) convierte una UI en vivo y en ejecución de vuelta en frames editables de Figma — pantalla completa, un elemento seleccionado o un archivo entero."}]}, {"kind": "p", "text": "El MCP de Figma se ejecuta como un servidor remoto y está exento de límites de tasa. Añádelo una vez y estará disponible para Codex, Claude Code, Cursor, VS Code y más — exactamente el tipo de capacidad portátil y multiagente que Open Design está hecho para orquestar."}]}, {"id": "vs", "heading": "Codex vs Cursor vs Claude Code para diseño", "blocks": [{"kind": "p", "text": "No hay un único ganador para el trabajo de diseño — cada agente tiene una fortaleza distinta, y los equipos con experiencia los combinan. Un resumen justo:"}, {"kind": "table", "columns": ["Agente", "Fortaleza de diseño", "Mejor para"], "rows": [["Codex", "Fuerte pulido visual tras GPT-5.4 + skill de frontend; comprensión de imágenes", "Compilaciones asíncronas delegadas, ejecuciones en sandbox, reglas portátiles de AGENTS.md"], ["Cursor", "Bucle visual de construir y ver con vista previa en vivo y ediciones en línea", "Trabajo de UI ajustado de iterar y observar dentro de un IDE"], ["Claude Code", "Decisiones de diseño específicas (hex, espaciado, tipografía) y UX consciente de la base de código", "Razonamiento de frontend y refactorizaciones de gran contexto"]]}, {"kind": "p", "text": "El veredicto recurrente de la comunidad es que el gusto proviene de las personas: los tres recaen en una estética genérica sin skills, referencias y restricciones. Ese es el verdadero problema a resolver — y tiene forma de herramienta de diseño, no de modelo."}]}, {"id": "pitfalls", "heading": "Escollos y cómo evitar el aspecto de “bazofia de IA”", "blocks": [{"kind": "p", "text": "La queja más común sobre el diseño generado por Codex es que parece genérico — degradados suaves, paneles flotantes, esquinas redondeadas excesivas, sombras dramáticas, un aire de Inter-y-morado que “grita que esto lo hizo una IA”. Otros problemas reportados incluyen diseños móviles rotos, instrucciones que se filtran en el texto de la UI y alcanzar rápidamente los límites de uso."}, {"kind": "steps", "items": [{"label": "Instala una skill de frontend", "body": "Una skill estética curada obliga a Codex a comprometerse con una dirección real en lugar del aspecto por defecto."}, {"label": "Habilita la verificación con Playwright", "body": "Haz que Codex renderice y se autoverifique en distintos breakpoints para que los diseños no se rompan en silencio en móvil."}, {"label": "Aporta tokens y referencias", "body": "Los tokens de diseño reales y las capturas de referencia son la mayor palanca sobre la calidad del resultado."}, {"label": "Codifica reglas en AGENTS.md", "body": "Pon reglas de estilo como “sin tarjetas hero, máximo dos tipografías, jerarquía centrada en la marca” donde el agente las lea en cada ejecución."}]}, {"kind": "p", "text": "Observa que cada mitigación consiste en dar al agente un contexto de diseño curado. Mantener ese contexto a mano, proyecto a proyecto, es el trabajo pesado que Open Design elimina."}]}, {"id": "open-design", "heading": "Diseñar con Codex dentro de Open Design", "blocks": [{"kind": "p", "text": "Open Design es la capa de diseño open-source que el flujo de trabajo anterior no deja de pedir. Trata a Codex como un adaptador de primera parte y lo envuelve en una biblioteca curada de skills y sistemas de diseño, una canalización de render estructurada y una UI de escritorio local — para que el contexto de diseño que hace bueno a Codex esté ahí desde la primera ejecución, no se ensamble a mano cada vez."}, {"kind": "ol", "items": ["Instala Open Design y selecciona Codex como tu agente.", "Autentícate con tu clave de API de OpenAI (BYOK) o tu suscripción a ChatGPT — las credenciales permanecen en tu máquina y nunca pasan por nuestros servidores.", "Elige un sistema de diseño y una skill, y luego genera presentaciones, prototipos y landing pages con un gusto consistente.", "Cada artefacto y archivo DESIGN.md vive en tu propio repositorio, no en una nube alojada."]}, {"kind": "p", "text": "El mismo agente Codex, la misma clave — más un flujo de trabajo de diseño real, portátil y open-source a su alrededor. Es local-first y Apache-2.0, así que nada de tu trabajo ni de tus credenciales sale de tu máquina."}]}], "faqTitle": "Preguntas frecuentes", "faq": [{"name": "¿Puede OpenAI Codex realmente hacer trabajo de diseño?", "text": "Sí — con una skill de frontend, un sistema de diseño e imágenes de referencia reales en contexto, Codex (especialmente con GPT-5.4) produce UI responsive de calidad de producción y puede verificarla en un navegador. Sin ese contexto tiende a recaer en un aspecto genérico, que es la brecha que Open Design cubre."}, {"name": "¿Es este el plugin de Product Design de OpenAI Codex?", "text": "No. Open Design es un proyecto open-source independiente que integra a Codex como agente. Complementa las propias herramientas de OpenAI con una biblioteca de skills y sistemas de diseño abierta y local-first."}, {"name": "¿Necesito una suscripción a ChatGPT para diseñar con Codex?", "text": "Puedes usar una clave de API de OpenAI (BYOK) o tu suscripción a ChatGPT. El inicio de sesión con ChatGPT suele dar límites más generosos; en cualquier caso, Open Design nunca actúa como proxy de tus credenciales."}, {"name": "¿Codex o Claude Code para diseño de frontend?", "text": "Ambos son fuertes. Claude Code es conocido por decisiones de diseño específicas y conscientes de la base de código; Codex tiene un fuerte pulido visual tras GPT-5.4 y destaca en compilaciones delegadas en sandbox. Muchos equipos usan ambos — Open Design te permite cambiar de agente sin cambiar tu flujo de trabajo de diseño."}, {"name": "¿Cómo conecto Codex con Figma?", "text": "Añade el servidor MCP oficial de Figma (codex mcp add figma --url https://mcp.figma.com/mcp). Después podrás implementar frames de Figma en código con get_design_context y enviar una UI en ejecución de vuelta a frames editables de Figma con generate_figma_design."}, {"name": "¿Cómo evito la estética genérica de “bazofia de IA”?", "text": "Instala una skill de frontend, aporta tokens de diseño reales y capturas de referencia, codifica las reglas de marca en AGENTS.md y habilita la verificación con Playwright. Open Design incluye todo esto como una biblioteca curada para que te saltes la configuración por proyecto."}, {"name": "¿Está Open Design afiliado a OpenAI?", "text": "No. Codex es un producto de OpenAI; Open Design es un proyecto open-source independiente que lo soporta como adaptador de primera parte. OpenAI y Codex son marcas comerciales de OpenAI."}, {"name": "¿Están seguros mis archivos y credenciales?", "text": "Sí — Open Design es local-first. Tus archivos, artefactos y DESIGN.md permanecen en tu propio repositorio, y tus credenciales de OpenAI las usa directamente tu agente, sin enrutarse nunca a través de los servidores de Open Design."}], "ctaTitle": "Diseña con Codex, a la manera abierta.", "ctaBody": "Usa tu propia clave de OpenAI, mantén cada archivo en local y obtén una biblioteca de diseño curada alrededor del agente que ya usas.", "ctaActions": [{"label": "Usa Codex dentro de Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Dale una estrella en GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Descarga la aplicación de escritorio", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Ver todos los agentes compatibles"},
      },
      'cursor': {
        ...en['cursor']!,
        title: "Cursor para diseñadores — Open Design",
        description: "Cómo los diseñadores usan Cursor para diseño de UI y web — Design Mode, Figma a código, el MCP de Figma — y cómo Open Design convierte a Cursor en un agente de diseño open-source y local-first.",
        breadcrumb: "Cursor",
        label: "Agente · Cursor",
        heading: "Cursor para diseñadores.",
        lead: "Cursor es el editor de código con IA, ahora con un Design Mode visual. Los diseñadores lo usan para editar la UI señalando y dibujando, y para convertir Figma en código. Open Design conecta a Cursor Agent con un flujo de trabajo de diseño open-source que mantiene tus archivos en local.",
        rich: {"heroCtaLead": "Open Design convierte a Cursor en un agente de diseño open-source y local-first — tu cuenta de Cursor o tus claves de modelo, tus archivos y una biblioteca curada de skills y sistemas de diseño a su alrededor.", "heroCtaActions": [{"label": "Usa Cursor dentro de Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Dale una estrella en GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Descarga la aplicación de escritorio", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Cursor es el editor de código con IA primero que convirtió el “constrúyelo y míralo renderizar” en la forma por defecto de entregar UI. Con el modo Agent, ediciones en línea, una vista previa dentro del editor y Figma sobre MCP, se ha convertido en una verdadera herramienta de diseño — una vez que le das las referencias, reglas y un bucle de verificación adecuados. Esta es una guía práctica y de extremo a extremo para usar Cursor en trabajo de UI, frontend y sistemas de diseño, y para integrarlo en un flujo de trabajo de diseño estructurado con Open Design.", "Cubre qué es realmente Cursor, por qué su ajustado bucle de iterar y observar es bueno para el diseño, cómo configurarlo desde cero, el bucle de captura y vista previa a UI, el round-trip con Figma sobre MCP, cómo se compara con Codex y Claude Code, los escollos que hacen que el resultado de la IA parezca genérico y cómo Open Design cierra esa brecha como una capa de diseño abierta y local-first."], "heroImage": {"src": "/agents/cursor-design/cursor-design-hero.webp", "alt": "Convergencia de diseño de Cursor: el editor a la izquierda, un hub curado de skills y sistema de diseño en el centro con la marca de Cursor al medio, y una UI renderizada a la derecha", "caption": "La idea central: Cursor edita y renderiza la UI en el editor, mientras un hub de diseño curado le aporta el sistema, las skills y las referencias que hacen que el resultado parezca intencional."}, "tocLabel": "En esta página", "toc": [{"id": "what-is-cursor", "label": "Qué es realmente Cursor"}, {"id": "why-design", "label": "Por qué Cursor es bueno en diseño"}, {"id": "setup", "label": "Configura Cursor para diseño (desde cero)"}, {"id": "preview-workflow", "label": "El flujo de trabajo de vista previa a UI"}, {"id": "figma", "label": "Cursor + Figma sobre MCP"}, {"id": "vs", "label": "Cursor vs Codex vs Claude Code"}, {"id": "pitfalls", "label": "Escollos y el aspecto de “bazofia de IA”"}, {"id": "open-design", "label": "Diseñar con Cursor en Open Design"}, {"id": "faq", "label": "Preguntas frecuentes"}], "sections": [{"id": "what-is-cursor", "heading": "Qué es realmente Cursor", "blocks": [{"kind": "p", "text": "Cursor es un editor de código con IA primero construido por Anysphere. Es un fork de VS Code, por lo que conserva el editor, las extensiones y los atajos de teclado familiares, pero reconstruye el flujo de trabajo en torno a un agente de IA que puede leer todo tu proyecto, editar varios archivos, ejecutar comandos e iterar contigo en el bucle."}, {"kind": "p", "text": "Para el trabajo de diseño, las superficies importantes son el modo Agent (describes un resultado y Cursor planifica y edita a través de los archivos), las ediciones en línea y las completaciones con Tab para ajustes rápidos, una vista previa / navegador dentro del editor para que veas la UI en ejecución sin salir de la ventana, y el soporte de MCP que le permite incorporar contexto externo como un archivo de Figma en vivo."}, {"kind": "steps", "items": [{"label": "Reglas del proyecto", "body": "Cursor lee archivos de instrucciones del proyecto — reglas `.mdc` versionadas bajo `.cursor/rules`, y un `AGENTS.md` simple — para que puedas codificar tus convenciones de diseño donde el agente las lee en cada ejecución."}, {"label": "Modelos", "body": "Cursor es flexible en cuanto a modelos: viene con modelos de frontera a través de tu suscripción y también admite traer tus propias claves de modelo, así que eliges el motor detrás del mismo flujo de trabajo del editor."}, {"label": "MCP", "body": "Habla el Model Context Protocol, así que los servidores externos — el más relevante, el servidor MCP de Figma — se convierten en contexto de primera clase para el agente."}]}, {"kind": "ul", "items": ["Proveedor: Anysphere", "Credencial: cuenta / suscripción de Cursor (Hobby / Pro / Business) o tus propias claves de modelo (BYOK)", "Forma: editor de código con IA primero (fork de VS Code) con un agente y una vista previa dentro del editor"]}]}, {"id": "why-design", "heading": "Por qué Cursor es bueno en diseño", "blocks": [{"kind": "p", "text": "La ventaja de diseño de Cursor no es una sola característica — es lo ajustado del bucle de construir y ver. Tres cosas hacen que se sienta como una herramienta de diseño en lugar de un generador de código genérico."}, {"kind": "steps", "items": [{"label": "Un bucle ajustado de iterar y observar", "body": "Tú formulas el prompt, Cursor edita a través de los archivos, y la vista previa dentro del editor renderiza el resultado de inmediato — así ajustas espaciado, jerarquía y movimiento en segundos en lugar de ir y volver entre una terminal y un navegador separados."}, {"label": "Edición visual directa", "body": "Más allá del chat, Cursor te permite seleccionar elementos en la vista previa y retocar estilos, así que las pequeñas correcciones visuales se sienten como ediciones de diseño en lugar de arqueología de código."}, {"label": "Reglas del proyecto y contexto MCP", "body": "Con `.cursor/rules` (o `AGENTS.md`) y el servidor MCP de Figma, el agente trabaja contra tus tokens, componentes y especificaciones de diseño reales en lugar de adivinar."}]}, {"kind": "image", "src": "/agents/cursor-design/cursor-design-taste-triangle.webp", "alt": "Diagrama que muestra el sistema de diseño, la skill y la imagen de referencia convergiendo en un buen resultado de diseño", "caption": "El gusto proviene de tres insumos que tú aportas: un sistema de diseño, una skill e imágenes de referencia reales."}, {"kind": "p", "text": "La lección es la misma que enseña cada agente: Cursor no tiene gusto por defecto. Produce buen diseño cuando le das restricciones — un sistema de diseño, una skill estética y referencias concretas. Open Design empaqueta exactamente esos insumos, y por eso ambos encajan (más abajo)."}]}, {"id": "setup", "heading": "Configura Cursor para trabajo de diseño, desde cero", "blocks": [{"kind": "p", "text": "Este es el camino completo desde una máquina limpia hasta un Cursor capaz de construir, previsualizar y verificar UI contra tu sistema de diseño."}, {"kind": "ol", "items": ["Instala Cursor desde cursor.com e inicia sesión con tu cuenta de Cursor, o configura tus propias claves de modelo (BYOK) en Settings.", "Abre tu proyecto y elige un modelo en el panel de chat / Agent.", "Añade reglas del proyecto: crea `.cursor/rules/*.mdc` para convenciones estructuradas y delimitadas por globs, o un `AGENTS.md` simple para instrucciones sencillas y legibles.", "Conecta el servidor MCP de Figma (opcional) para que el agente pueda leer el contexto de diseño en vivo.", "Ejecuta tu servidor de desarrollo y usa la vista previa dentro del editor para ver y verificar la UI a medida que iteras."]}, {"kind": "image", "src": "/agents/cursor-design/cursor-design-setup-flow.webp", "alt": "Flujo de configuración de cinco pasos: instalar, autenticar, configurar reglas, añadir skill, verificar", "caption": "La secuencia de configuración: instalar → autenticar → configurar las reglas del proyecto → añadir una skill → habilitar la verificación con vista previa."}, {"kind": "p", "text": "Un archivo mínimo de reglas del proyecto hace que el agente diseñe para una marca en lugar de recaer en un aspecto genérico. Ponlo donde Cursor lo lea en cada ejecución:"}, {"kind": "code", "lang": "markdown", "code": "# .cursor/rules/design.mdc\n---\ndescription: Project design conventions\nalwaysApply: true\n---\n\n- Reuse existing design-system tokens and components; never hardcode hex or spacing.\n- At most two typefaces and one accent color.\n- Brand-first hierarchy; restrained motion. No hero cards, no oversized rounded corners.\n- Build responsive by default; verify desktop and mobile in the preview before finishing."}, {"kind": "steps", "items": [{"label": "Codifica tus reglas de diseño", "body": "Coloca tus tokens, primitivas y convenciones en `.cursor/rules` o `AGENTS.md` y dirige a Cursor hacia ellas, para que el resultado coincida con una marca en lugar de recaer en un aspecto genérico."}, {"label": "Mantén los prompts pequeños", "body": "El bucle ajustado de Cursor recompensa las peticiones enfocadas — itera un componente o estado a la vez y observa la vista previa entre pasadas."}]}]}, {"id": "preview-workflow", "heading": "El flujo de trabajo de vista previa a UI", "blocks": [{"kind": "p", "text": "El bucle de diseño de mayor apalancamiento con Cursor es convertir una referencia en una UI funcional y responsive e iterar en el editor hasta que coincida — observando la vista previa en vivo todo el tiempo en lugar de adivinar."}, {"kind": "ol", "items": ["Parte de las referencias visuales más claras que tengas — e incluye varios estados (escritorio y móvil, hover, vacío, cargando), no solo una única toma principal.", "Sé específico en el prompt; los prompts vagos producen UI genérica.", "Prepara un sistema de diseño e indícale a Cursor dónde viven los tokens y las primitivas canónicas.", "Mantén abierta la vista previa dentro del editor y tu servidor de desarrollo en marcha para que cada edición renderice de inmediato en los breakpoints que te importan.", "Itera comparando la UI renderizada con las referencias — y usa la selección directa de elementos en la vista previa para pequeñas correcciones visuales."]}, {"kind": "p", "text": "Alimenta las referencias adjuntando una imagen al chat, y luego formula el prompt con restricciones concretas:"}, {"kind": "code", "lang": "text", "code": "Implement this design in React + Vite + Tailwind + TypeScript.\nReuse my existing design-system components and tokens.\nMatch spacing, layout, and hierarchy; make it responsive.\nKeep the preview open — verify desktop and mobile match the\nreferences and iterate until they do."}, {"kind": "p", "text": "Confirma las buenas iteraciones y revierte las malas (diciéndole a Cursor cuándo reviertes) para que cada pasada parta de una base limpia — la misma disciplina que evita que cualquier bucle de agente derive."}]}, {"id": "figma", "heading": "Cursor + Figma: diseño ↔ código sobre MCP", "blocks": [{"kind": "p", "text": "Cursor se conecta a Figma a través del servidor MCP oficial de Figma, que da al agente acceso estructurado a un archivo de Figma en vivo en lugar de una captura plana. Eso elimina las conjeturas del handoff."}, {"kind": "steps", "items": [{"label": "Diseño → Código", "body": "Copia el enlace de un frame en Figma, pégalo en Cursor y pídele que implemente el diseño. El servidor MCP expone contexto de diseño real — componentes, variables, datos de layout, tokens — para que el código generado coincida con la fuente en lugar de aproximarla."}, {"label": "Mantente alineado", "body": "Con los tokens de diseño, estilos y componentes usados de forma consistente en Figma (y Code Connect donde esté disponible), el resultado de Cursor permanece mapeado a tu sistema de diseño real en lugar de reinventar primitivas."}]}, {"kind": "p", "text": "Configura una vez el servidor MCP remoto de Figma y estará disponible para Cursor como contexto de primera clase. Como MCP es un estándar abierto, el mismo servidor es reutilizable en Cursor, Claude Code, Codex y VS Code — exactamente el tipo de capacidad portátil y multiagente que Open Design está hecho para orquestar."}]}, {"id": "vs", "heading": "Cursor vs Codex vs Claude Code para diseño", "blocks": [{"kind": "p", "text": "No hay un único ganador para el trabajo de diseño — cada agente tiene una fortaleza distinta, y los equipos con experiencia los combinan. Un resumen justo:"}, {"kind": "table", "columns": ["Agente", "Fortaleza de diseño", "Mejor para"], "rows": [["Cursor", "Bucle visual de construir y ver con vista previa en vivo dentro del editor y edición directa de elementos", "Trabajo de UI ajustado de iterar y observar dentro de un IDE"], ["Codex", "Fuerte pulido visual con una skill de frontend; comprensión de imágenes y ejecuciones en sandbox", "Compilaciones asíncronas delegadas y reglas portátiles de AGENTS.md"], ["Claude Code", "Decisiones de diseño específicas (hex, espaciado, tipografía) y UX consciente de la base de código", "Razonamiento de frontend y refactorizaciones de gran contexto"]]}, {"kind": "p", "text": "El veredicto recurrente de la comunidad es que el gusto proviene de las personas: los tres recaen en una estética genérica sin skills, referencias y restricciones. Ese es el verdadero problema a resolver — y tiene forma de herramienta de diseño, no de modelo."}]}, {"id": "pitfalls", "heading": "Escollos y cómo evitar el aspecto de “bazofia de IA”", "blocks": [{"kind": "p", "text": "La queja más común sobre el diseño generado por Cursor es que parece genérico — degradados suaves, paneles flotantes, esquinas redondeadas excesivas, sombras dramáticas, un aire de Inter-y-morado que “grita que esto lo hizo una IA”. Otros problemas reportados incluyen diseños que se rompen en móvil e instrucciones que se filtran en el texto de la UI."}, {"kind": "steps", "items": [{"label": "Añade una skill de diseño", "body": "Una skill estética curada obliga a Cursor a comprometerse con una dirección real en lugar del aspecto por defecto."}, {"label": "Usa la vista previa para verificar", "body": "Renderiza y autoverifica en distintos breakpoints en la vista previa dentro del editor para que los diseños no se rompan en silencio en móvil."}, {"label": "Aporta tokens y referencias", "body": "Los tokens de diseño reales y las capturas de referencia son la mayor palanca sobre la calidad del resultado."}, {"label": "Codifica reglas en `.cursor/rules`", "body": "Pon reglas de estilo como “sin tarjetas hero, máximo dos tipografías, jerarquía centrada en la marca” donde el agente las lea en cada ejecución."}]}, {"kind": "p", "text": "Observa que cada mitigación consiste en dar al agente un contexto de diseño curado. Mantener ese contexto a mano, proyecto a proyecto, es el trabajo pesado que Open Design elimina."}]}, {"id": "open-design", "heading": "Diseñar con Cursor dentro de Open Design", "blocks": [{"kind": "p", "text": "Open Design es la capa de diseño open-source que el flujo de trabajo anterior no deja de pedir. Trata a Cursor como un adaptador de primera parte y lo envuelve en una biblioteca curada de skills y sistemas de diseño, una canalización de render estructurada y una UI de escritorio local — para que el contexto de diseño que hace bueno a Cursor esté ahí desde la primera ejecución, no se ensamble a mano cada vez."}, {"kind": "ol", "items": ["Instala Open Design y selecciona Cursor como tu agente.", "Autentícate con tu cuenta de Cursor o tus propias claves de modelo (BYOK) — las credenciales permanecen en tu máquina y nunca pasan por nuestros servidores.", "Elige un sistema de diseño y una skill, y luego genera presentaciones, prototipos y landing pages con un gusto consistente.", "Cada artefacto y archivo DESIGN.md vive en tu propio repositorio, no en una nube alojada."]}, {"kind": "p", "text": "El mismo agente Cursor, la misma clave — más un flujo de trabajo de diseño real, portátil y open-source a su alrededor. Es local-first y Apache-2.0, así que nada de tu trabajo ni de tus credenciales sale de tu máquina."}]}], "faqTitle": "Preguntas frecuentes", "faq": [{"name": "¿Puede Cursor realmente hacer trabajo de diseño?", "text": "Sí — con una skill de diseño, un sistema de diseño e imágenes de referencia reales en contexto, Cursor produce UI responsive de calidad de producción, y su vista previa dentro del editor te permite verificarla y refinarla visualmente. Sin ese contexto tiende a recaer en un aspecto genérico, que es la brecha que Open Design cubre."}, {"name": "¿Es este un producto oficial de Cursor?", "text": "No. Open Design es un proyecto open-source independiente que integra a Cursor como agente. Complementa a Cursor con una biblioteca de skills y sistemas de diseño abierta y local-first."}, {"name": "¿Necesito una suscripción a Cursor para diseñar con Cursor?", "text": "Puedes usar una cuenta / suscripción de Cursor o traer tus propias claves de modelo (BYOK). Open Design nunca actúa como proxy de tus credenciales en ningún caso — las usa directamente tu agente."}, {"name": "¿Cursor o Claude Code para diseño de frontend?", "text": "Ambos son fuertes. Claude Code es conocido por decisiones de diseño específicas y conscientes de la base de código; la ventaja de Cursor es su ajustado bucle de construir y ver con una vista previa en vivo dentro del editor. Muchos equipos usan ambos — Open Design te permite cambiar de agente sin cambiar tu flujo de trabajo de diseño."}, {"name": "¿Cómo conecto Cursor con Figma?", "text": "Añade el servidor MCP oficial de Figma en Cursor, luego pega un enlace de un frame de Figma en el chat y pídele a Cursor que lo implemente. El servidor expone componentes, variables y datos de layout reales para que el código generado coincida con el diseño fuente."}, {"name": "¿Cómo evito la estética genérica de “bazofia de IA”?", "text": "Añade una skill de diseño, aporta tokens de diseño reales y capturas de referencia, codifica las reglas de marca en `.cursor/rules` o `AGENTS.md`, y verifica en distintos breakpoints en la vista previa. Open Design incluye todo esto como una biblioteca curada para que te saltes la configuración por proyecto."}, {"name": "¿Está Open Design afiliado a Cursor o Anysphere?", "text": "No. Cursor es un producto de Anysphere; Open Design es un proyecto open-source independiente que lo soporta como adaptador de primera parte. Cursor y Anysphere son marcas comerciales de Anysphere, Inc."}, {"name": "¿Están seguros mis archivos y credenciales?", "text": "Sí — Open Design es local-first. Tus archivos, artefactos y DESIGN.md permanecen en tu propio repositorio, y tus credenciales de Cursor o de modelo las usa directamente tu agente, sin enrutarse nunca a través de los servidores de Open Design."}], "ctaTitle": "Diseña con Cursor, a la manera abierta.", "ctaBody": "Usa tu propia cuenta de Cursor o claves de modelo, mantén cada archivo en local y obtén una biblioteca de diseño curada alrededor del agente que ya usas.", "ctaActions": [{"label": "Usa Cursor dentro de Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Dale una estrella en GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Descarga la aplicación de escritorio", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Ver todos los agentes compatibles"},
      },
      'opencode': {
        ...en['opencode']!,
        title: "OpenCode para diseño — Open Design",
        description: "Cómo la gente usa OpenCode para diseño de UI y web — archivos design.md, skills de UI/UX, MCP de Figma — y cómo Open Design convierte a OpenCode en un agente de diseño open-source y local-first.",
        breadcrumb: "OpenCode",
        label: "Agente · OpenCode",
        heading: "OpenCode para diseño.",
        lead: "OpenCode es el agente de codificación con IA de terminal y open-source. Los diseñadores le acoplan skills de diseño y archivos DESIGN.md para generar UI real. Open Design lo convierte en un flujo de trabajo estructurado y open-source — usa tus claves de proveedor y mantén todo en local.",
        rich: {"heroCtaLead": "Open Design convierte a OpenCode en un agente de diseño open-source y local-first — cualquier modelo que elijas con tu propia clave de proveedor, tus archivos y una biblioteca curada de skills y sistemas de diseño a su alrededor.", "heroCtaActions": [{"label": "Usa OpenCode dentro de Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Dale una estrella en GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Descarga la aplicación de escritorio", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["OpenCode es un agente de codificación con IA, open-source y orientado a la terminal, que es deliberadamente agnóstico respecto al modelo: traes tu propia clave de proveedor y ejecutas el modelo que quieras detrás del mismo flujo de trabajo. Esa apertura lo convierte en una base natural para el trabajo de diseño — pero, como todo agente, solo produce buena UI cuando le das las referencias, skills y un bucle de verificación adecuados. Esta es una guía práctica y de extremo a extremo para usar OpenCode en trabajo de UI, frontend y sistemas de diseño, y para integrarlo en un flujo de trabajo de diseño estructurado con Open Design.", "Cubre qué es realmente OpenCode, por qué un agente abierto y agnóstico respecto al modelo encaja bien con el diseño, cómo configurarlo desde cero, el bucle de captura a UI, cómo AGENTS.md y MCP lo extienden, cómo se compara con Codex, Claude Code y Cursor, los escollos que hacen que el resultado de la IA parezca genérico y cómo Open Design cierra esa brecha como una capa de diseño abierta y local-first — un emparejamiento natural, ya que ambos proyectos son open-source y se ejecutan en tu propia máquina."], "heroImage": {"src": "/agents/opencode-design/opencode-design-hero.webp", "alt": "Bucle de retroalimentación de diseño de OpenCode: un agente TUI de terminal, un navegador renderizando la UI y un espacio de trabajo, con una flecha de retroalimentación que regresa en bucle", "caption": "El bucle central: OpenCode construye la UI en la terminal, la renderiza y verifica en un navegador real, e itera contra tus referencias — con el modelo que elijas."}, "tocLabel": "En esta página", "toc": [{"id": "what-is-opencode", "label": "Qué es realmente OpenCode"}, {"id": "why-design", "label": "Por qué un agente abierto y de cualquier modelo encaja con el diseño"}, {"id": "setup", "label": "Configura OpenCode para diseño (desde cero)"}, {"id": "screenshot-workflow", "label": "El flujo de trabajo de captura a UI"}, {"id": "extend", "label": "AGENTS.md, MCP y sesiones compartibles"}, {"id": "vs", "label": "OpenCode vs Codex vs Claude Code vs Cursor"}, {"id": "pitfalls", "label": "Escollos y el aspecto de “bazofia de IA”"}, {"id": "open-design", "label": "Diseñar con OpenCode en Open Design"}, {"id": "faq", "label": "Preguntas frecuentes"}], "sections": [{"id": "what-is-opencode", "heading": "Qué es realmente OpenCode", "blocks": [{"kind": "p", "text": "OpenCode es un agente de codificación con IA open-source construido para la terminal, mantenido por el equipo detrás de SST (Anomaly Innovations). Lee tu repositorio, ejecuta comandos, edita archivos y se comunica con un modelo de lenguaje grande — pero, a diferencia de los agentes atados a un proveedor, no incluye su propio modelo. Lo apuntas a cualquier proveedor y modelo que quieras y traes tu propia clave."}, {"kind": "p", "text": "Se ejecuta como una UI de terminal (TUI), con una aplicación de escritorio y extensiones de IDE sobre el mismo motor. Por debajo usa una arquitectura cliente/servidor, así que el agente que hace el trabajo está desacoplado de la superficie desde la que lo controlas. Dos agentes integrados — build y plan — se alternan con la tecla Tab."}, {"kind": "steps", "items": [{"label": "Agnóstico respecto al modelo", "body": "Los modelos y proveedores provienen de models.dev, un catálogo abierto. Los configuras en opencode.json con una cadena provider/model-id y puedes deshabilitar los proveedores que no quieras cargar — así el mismo flujo de trabajo de diseño se ejecuta sobre Anthropic, OpenAI, Google, OpenRouter, modelos locales y más."}, {"label": "Archivo de instrucciones", "body": "OpenCode lee un archivo AGENTS.md en tu proyecto (el estándar entre herramientas, también compatible con CLAUDE.md) para las reglas del proyecto — el lugar natural para codificar tus convenciones de diseño. Ejecuta /init para generar uno."}, {"label": "Extensible", "body": "Admite integración con LSP, servidores MCP, temas, atajos de teclado y comandos personalizados, además de enlaces de sesión compartibles para la colaboración."}]}, {"kind": "ul", "items": ["Mantenedor: SST / Anomaly Innovations (proyecto open-source)", "Credencial: tu(s) propia(s) clave(s) de API de proveedor de modelos — BYOK, sin atadura a un proveedor", "Licencia: MIT, open source"]}]}, {"id": "why-design", "heading": "Por qué un agente abierto y de cualquier modelo encaja con el trabajo de diseño", "blocks": [{"kind": "p", "text": "OpenCode no tiene un único “modelo de diseño” como sí lo tiene un agente de proveedor — y ese es el punto. Como es agnóstico respecto al modelo y abierto, puedes ejecutar el mismo flujo de trabajo de diseño sobre el modelo que actualmente sea mejor en frontend, cambiarlo después o recurrir a un modelo local, todo sin cambiar tu configuración."}, {"kind": "p", "text": "Pero la elección del modelo por sí sola no compra gusto. Como todo agente de codificación, OpenCode produce UI genérica a menos que le des restricciones. El buen resultado de diseño proviene de tres insumos que tú aportas."}, {"kind": "steps", "items": [{"label": "Un sistema de diseño", "body": "Tokens, primitivas y convenciones reales que el agente reutiliza, para que el resultado coincida con una marca en lugar de recaer en un aspecto genérico."}, {"label": "Una skill estética", "body": "Una skill curada que impone gusto real — movimiento contenido, jerarquía centrada en la marca, como máximo dos tipografías y un color de acento — y hace que el agente se comprometa con una dirección antes de construir."}, {"label": "Referencias concretas", "body": "Imágenes de referencia reales y varios estados (escritorio y móvil, hover, vacío, cargando), no una única toma principal."}]}, {"kind": "image", "src": "/agents/opencode-design/opencode-design-taste-triangle.webp", "alt": "Diagrama que muestra el sistema de diseño, la skill y la imagen de referencia convergiendo en un buen resultado de diseño", "caption": "El gusto proviene de tres insumos que tú aportas: un sistema de diseño, una skill e imágenes de referencia reales — con independencia del modelo que ejecutes."}, {"kind": "p", "text": "La lección: OpenCode te da libertad de modelo, pero el gusto sigue proviniendo de un contexto de diseño curado. Open Design empaqueta exactamente esos insumos, y por eso ambos encajan — los dos son open-source y local-first (más abajo)."}]}, {"id": "setup", "heading": "Configura OpenCode para trabajo de diseño, desde cero", "blocks": [{"kind": "p", "text": "Este es el camino completo desde una máquina limpia hasta un OpenCode capaz de construir y verificar UI."}, {"kind": "code", "lang": "bash", "code": "# 1. Install OpenCode\ncurl -fsSL https://opencode.ai/install | bash\n# or: npm i -g opencode-ai@latest\n# or: brew install sst/tap/opencode\n\n# 2. Start the TUI in your project, then authenticate your provider\nopencode          # then run /login and pick your provider + paste your key\n\n# 3. Generate project context\nopencode          # inside your project, run /init to create AGENTS.md\n\n# 4. Pick your model (any provider, via models.dev)\n#    set \"provider/model-id\" in opencode.json or switch in the TUI\n\n# 5. Add an MCP server (optional, e.g. for design handoff)\n#    configure it under the \"mcp\" key in opencode.json"}, {"kind": "image", "src": "/agents/opencode-design/opencode-design-setup-flow.webp", "alt": "Flujo de configuración de cinco pasos: instalar, autenticar con tu clave de proveedor, configurar AGENTS.md, añadir una skill, verificar", "caption": "La secuencia de configuración: instalar → autenticar (tu clave de proveedor) → configurar AGENTS.md → añadir una skill → verificar en un navegador real."}, {"kind": "steps", "items": [{"label": "Codifica tus reglas de diseño", "body": "Coloca tus tokens, primitivas y convenciones en AGENTS.md (o en un DESIGN.md referenciado desde él) para que el resultado coincida con una marca en lugar de recaer en un aspecto genérico. La opción instructions de opencode.json puede apuntar a archivos de reglas adicionales mediante globs."}, {"label": "Elige un modelo capaz", "body": "Como OpenCode es agnóstico respecto al modelo, elige el proveedor/modelo que actualmente sea más fuerte en frontend para la pasada de diseño — y mantén el resto de tu flujo de trabajo sin cambios."}]}]}, {"id": "screenshot-workflow", "heading": "El flujo de trabajo de captura a UI", "blocks": [{"kind": "p", "text": "El bucle de diseño de mayor apalancamiento con cualquier agente es convertir una imagen de referencia en una UI funcional y responsive e iterar hasta que coincida. La misma forma de cinco pasos aplica en OpenCode."}, {"kind": "ol", "items": ["Parte de las referencias visuales más claras que tengas — e incluye varios estados (escritorio y móvil, hover, vacío, cargando), no solo una única toma principal.", "Sé específico en el prompt; los prompts vagos producen UI genérica.", "Prepara un sistema de diseño e indícale a OpenCode dónde viven los tokens y las primitivas canónicas (en AGENTS.md).", "Ejecuta un servidor de desarrollo y haz que el agente renderice en un navegador real, redimensionando a los breakpoints para comprobar el resultado.", "Itera haciendo que OpenCode compare su implementación con las capturas — no solo que confirme que compila."]}, {"kind": "p", "text": "Referencia archivos con @ en la TUI para una búsqueda difusa de tu directorio de trabajo, ejecuta comandos de shell en línea con un ! inicial, y dirige las acciones con comandos /. Luego formula el prompt con restricciones concretas:"}, {"kind": "code", "lang": "bash", "code": "opencode\n# in the TUI:\n> @reference-desktop.png @reference-mobile.png\n  Implement this design in React + Vite + Tailwind + TypeScript.\n  Reuse my existing design-system components and tokens from AGENTS.md.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Run the dev server, open it in a browser, and iterate until the\n  UI matches the references across breakpoints."}, {"kind": "p", "text": "Mantén los prompts pequeños y enfocados, confirma las buenas iteraciones y revierte las malas (diciéndole a OpenCode cuándo reviertes), para que cada pasada parta de una base limpia."}]}, {"id": "extend", "heading": "AGENTS.md, MCP y sesiones compartibles", "blocks": [{"kind": "p", "text": "Tres puntos de extensión hacen a OpenCode práctico para el trabajo de diseño sostenido, y los tres se mapean limpiamente sobre un flujo de trabajo de diseño abierto."}, {"kind": "steps", "items": [{"label": "Reglas de AGENTS.md", "body": "Las reglas del proyecto viven en un AGENTS.md en la raíz del repositorio (o reglas globales en ~/.config/opencode/AGENTS.md). Es el hogar duradero de tus convenciones de diseño, leído en cada ejecución, y es compatible con los archivos CLAUDE.md que usan otros agentes."}, {"label": "Servidores MCP", "body": "OpenCode admite servidores MCP tanto locales (command) como remotos (URL), configurados bajo la clave mcp — la forma portátil de incorporar contexto de diseño y herramientas externas que funcionan en todos los agentes, no solo en OpenCode."}, {"label": "Sesiones compartibles", "body": "El comando /share crea un enlace público a una conversación para colaboración o revisión, y /unshare lo revoca — útil para obtener feedback sobre una pasada de diseño."}]}, {"kind": "p", "text": "Estas son capacidades portátiles y multiagente — exactamente el tipo de cosa que Open Design está hecho para orquestar, en lugar de recrear en cada proyecto."}]}, {"id": "vs", "heading": "OpenCode vs Codex vs Claude Code vs Cursor para diseño", "blocks": [{"kind": "p", "text": "No hay un único ganador para el trabajo de diseño — cada agente tiene una fortaleza distinta, y los equipos con experiencia los combinan. Un resumen justo:"}, {"kind": "table", "columns": ["Agente", "Fortaleza de diseño", "Mejor para"], "rows": [["OpenCode", "Open-source y agnóstico respecto al modelo; ejecuta cualquier proveedor detrás de un único flujo de trabajo de terminal", "Libertad BYOK, cambio de modelo, configuraciones totalmente abiertas y local-first"], ["Codex", "Fuerte pulido visual con una skill de frontend; comprensión de imágenes", "Async delegado, compilaciones en sandbox, reglas portátiles de AGENTS.md"], ["Claude Code", "Decisiones de diseño específicas (hex, espaciado, tipografía) y UX consciente de la base de código", "Razonamiento de frontend y refactorizaciones de gran contexto"], ["Cursor", "Bucle visual de construir y ver con vista previa en vivo y ediciones en línea", "Trabajo de UI ajustado de iterar y observar dentro de un IDE"]]}, {"kind": "p", "text": "El veredicto recurrente de la comunidad es que el gusto proviene de las personas: todos recaen en una estética genérica sin skills, referencias y restricciones. Ese es el verdadero problema a resolver — y tiene forma de herramienta de diseño, no de modelo, que es precisamente por lo que un agente abierto como OpenCode encaja tan bien con una capa de diseño abierta."}]}, {"id": "pitfalls", "heading": "Escollos y cómo evitar el aspecto de “bazofia de IA”", "blocks": [{"kind": "p", "text": "La queja más común sobre el diseño generado por IA es que parece genérico — degradados suaves, paneles flotantes, esquinas redondeadas excesivas, sombras dramáticas, un aire de Inter-y-morado que “grita que esto lo hizo una IA”. Otros problemas reportados incluyen diseños móviles rotos e instrucciones que se filtran en el texto de la UI. Ninguno de estos es exclusivo de OpenCode; son lo que ocurre cuando cualquier agente se ejecuta sin un contexto de diseño curado."}, {"kind": "steps", "items": [{"label": "Añade una skill estética", "body": "Una skill de diseño curada obliga al agente a comprometerse con una dirección real en lugar del aspecto por defecto."}, {"label": "Verifica en un navegador real", "body": "Renderiza y autoverifica en distintos breakpoints para que los diseños no se rompan en silencio en móvil."}, {"label": "Aporta tokens y referencias", "body": "Los tokens de diseño reales y las capturas de referencia son la mayor palanca sobre la calidad del resultado."}, {"label": "Codifica reglas en AGENTS.md", "body": "Pon reglas de estilo como “sin tarjetas hero, máximo dos tipografías, jerarquía centrada en la marca” donde el agente las lea en cada ejecución."}]}, {"kind": "p", "text": "Observa que cada mitigación consiste en dar al agente un contexto de diseño curado — sin importar qué modelo ejecutes. Mantener ese contexto a mano, proyecto a proyecto, es el trabajo pesado que Open Design elimina."}]}, {"id": "open-design", "heading": "Diseñar con OpenCode dentro de Open Design", "blocks": [{"kind": "p", "text": "Open Design es la capa de diseño open-source que el flujo de trabajo anterior no deja de pedir. Trata a OpenCode como un adaptador de primera parte y lo envuelve en una biblioteca curada de skills y sistemas de diseño, una canalización de render estructurada y una UI de escritorio local — para que el contexto de diseño que hace bueno a cualquier agente esté ahí desde la primera ejecución, no se ensamble a mano cada vez. Ambos proyectos son open-source y local-first, lo que hace que el emparejamiento sea un encaje natural."}, {"kind": "ol", "items": ["Instala Open Design y selecciona OpenCode como tu agente.", "Autentícate con tu propia clave de API de proveedor de modelos (BYOK) — las credenciales permanecen en tu máquina y nunca pasan por nuestros servidores.", "Elige cualquier proveedor y modelo, además de un sistema de diseño y una skill, y luego genera presentaciones, prototipos y landing pages con un gusto consistente.", "Cada artefacto y archivo DESIGN.md vive en tu propio repositorio, no en una nube alojada."]}, {"kind": "p", "text": "El mismo agente OpenCode, la misma libertad de modelo — más un flujo de trabajo de diseño real, portátil y open-source a su alrededor. Es local-first y Apache-2.0, así que nada de tu trabajo ni de tus credenciales sale de tu máquina."}]}], "faqTitle": "Preguntas frecuentes", "faq": [{"name": "¿Puede OpenCode realmente hacer trabajo de diseño?", "text": "Sí — con una skill estética, un sistema de diseño e imágenes de referencia reales en contexto, OpenCode produce UI responsive de calidad de producción y puede verificarla en un navegador. Como es agnóstico respecto al modelo, ejecutas el modelo que actualmente sea mejor en frontend. Sin ese contexto curado tiende a recaer en un aspecto genérico, que es la brecha que Open Design cubre."}, {"name": "¿Qué modelo debería usar con OpenCode para diseño?", "text": "El que prefieras — OpenCode es agnóstico respecto al proveedor a través de models.dev, así que puedes ejecutar Anthropic, OpenAI, Google, OpenRouter o modelos locales detrás del mismo flujo de trabajo y cambiar en cualquier momento. La calidad del resultado de diseño depende mucho más de tu skill, tu sistema de diseño y tus referencias que del modelo por sí solo."}, {"name": "¿Open Design está hecho por el equipo de OpenCode (SST)?", "text": "No. Open Design es un proyecto open-source independiente que integra a OpenCode como agente. Complementa a OpenCode con una biblioteca de skills y sistemas de diseño abierta y local-first."}, {"name": "¿Necesito una suscripción especial para diseñar con OpenCode?", "text": "No — OpenCode es BYOK. Traes tu propia clave de API de proveedor de modelos, y Open Design nunca actúa como proxy de tus credenciales. No hay atadura a un proveedor."}, {"name": "¿OpenCode, Codex o Claude Code para diseño de frontend?", "text": "Todos son fuertes, y muchos equipos los combinan. La ventaja de OpenCode es ser totalmente open-source y agnóstico respecto al modelo; Codex destaca en compilaciones delegadas en sandbox; Claude Code es conocido por decisiones de diseño específicas y conscientes de la base de código. Open Design te permite cambiar de agente sin cambiar tu flujo de trabajo de diseño."}, {"name": "¿Cómo extiendo OpenCode para el contexto de diseño?", "text": "Codifica reglas en AGENTS.md, añade servidores MCP bajo la clave mcp para herramientas portátiles y contexto de diseño, y usa sesiones compartibles para la revisión. Open Design incluye una biblioteca curada de skills y sistemas de diseño para que te saltes la configuración por proyecto."}, {"name": "¿Está Open Design afiliado a OpenCode o SST?", "text": "No. OpenCode es un proyecto open-source mantenido por SST (Anomaly Innovations); Open Design es un proyecto open-source independiente que lo soporta como adaptador de primera parte."}, {"name": "¿Están seguros mis archivos y credenciales?", "text": "Sí — Open Design es local-first. Tus archivos, artefactos y DESIGN.md permanecen en tu propio repositorio, y tus credenciales de proveedor de modelos las usa directamente tu agente, sin enrutarse nunca a través de los servidores de Open Design."}], "ctaTitle": "Diseña con OpenCode, a la manera abierta.", "ctaBody": "Usa tu propia clave de proveedor de modelos, mantén cada archivo en local y obtén una biblioteca de diseño curada alrededor del agente abierto que ya usas.", "ctaActions": [{"label": "Usa OpenCode dentro de Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Dale una estrella en GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Descarga la aplicación de escritorio", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Ver todos los agentes compatibles"},
      },
    },
    'pt-br': {
      'claude-code': {
        ...en['claude-code']!,
        title: "Claude Code para design — Open Design",
        description: "Como designers usam o Claude Code para design de UI e web, e como o Open Design o transforma em um verdadeiro agente de design — local-first, BYOK, com uma biblioteca curada de skills e design systems.",
        breadcrumb: "Claude Code",
        label: "Agente · Claude Code",
        heading: "Claude Code para design.",
        lead: "O Claude Code é o agente de programação no terminal da Anthropic. As pessoas já o usam para criar UIs, design systems e landing pages. O Open Design o conecta a um fluxo de design real — traga sua chave da Anthropic ou sua assinatura do Claude e mantenha cada arquivo local.",
        rich: {"heroCtaLead": "O Open Design transforma o Claude Code em um agente de design local-first e open-source — sua chave da Anthropic ou assinatura do Claude, seus arquivos, com uma biblioteca curada de skills e design systems ao redor.", "heroCtaActions": [{"label": "Use o Claude Code dentro do Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Dê uma estrela no GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Baixe o aplicativo desktop", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["O Claude Code é amplamente considerado o agente de programação com o melhor bom gosto em frontend — ele raciocina sobre interfaces com uma especificidade incomum, nomeando valores hex exatos, espaçamentos e escalas tipográficas, e refatora UI em uma base de código grande sem perder o fio da meada. Mas, de saída, ele ainda tende a derivar para uma aparência genérica, a menos que você lhe forneça um design system, skills e referências reais. Este é um guia prático e completo para usar o Claude Code em trabalho de UI, frontend e design system, e para conectá-lo a um fluxo estruturado com o Open Design.", "Ele cobre o que o Claude Code realmente é, por que ele é forte em frontend, como configurá-lo do zero, o fluxo de CLAUDE.md e Skills, a integração oficial de ida e volta com o Figma, como ele se compara ao Codex e ao Cursor, as armadilhas que fazem a saída de IA parecer genérica e como o Open Design fecha essa lacuna como uma camada de design aberta e local-first."], "heroImage": {"src": "/agents/claude-code-design/claude-code-design-hero.webp", "alt": "Loop de feedback de design do Claude Code: o agente no terminal tomando decisões de design específicas, um navegador renderizando a UI e um espaço de trabalho, com uma seta de feedback voltando ao início", "caption": "O loop central: o Claude Code raciocina sobre decisões de UI específicas no terminal, renderiza e as verifica em um navegador real e converge em direção às suas referências."}, "tocLabel": "Nesta página", "toc": [{"id": "what-is-claude-code", "label": "O que o Claude Code realmente é"}, {"id": "why-design", "label": "Por que o Claude Code é bom em design"}, {"id": "setup", "label": "Configure o Claude Code para design (do zero)"}, {"id": "skills-workflow", "label": "O fluxo de CLAUDE.md e Skills"}, {"id": "figma", "label": "Integração de ida e volta Claude Code + Figma"}, {"id": "vs", "label": "Claude Code vs Codex vs Cursor"}, {"id": "pitfalls", "label": "Armadilhas e a aparência de “lixo de IA”"}, {"id": "open-design", "label": "Projetando com o Claude Code no Open Design"}, {"id": "faq", "label": "Perguntas frequentes"}], "sections": [{"id": "what-is-claude-code", "heading": "O que o Claude Code realmente é", "blocks": [{"kind": "p", "text": "O Claude Code é a ferramenta de programação agêntica da Anthropic. Ele lê sua base de código, edita arquivos, executa comandos e se integra às suas ferramentas de desenvolvimento — planejando, escrevendo e verificando o trabalho a partir de tarefas em linguagem natural, em vez de apenas autocompletar linhas."}, {"kind": "p", "text": "Ele está disponível em várias superfícies que compartilham o mesmo motor: uma CLI de terminal, extensões para IDE no VS Code, Cursor e JetBrains, um aplicativo desktop com revisão visual de diff e uma experiência web para tarefas de longa duração. Seus arquivos CLAUDE.md, configurações e servidores MCP acompanham todas elas."}, {"kind": "steps", "items": [{"label": "Arquivo de instruções", "body": "O Claude Code lê um arquivo CLAUDE.md na raiz do seu projeto no início de cada sessão — o lugar natural para codificar suas convenções de design, tokens e checklists de revisão."}, {"label": "Skills", "body": "As Agent Skills empacotam instruções, scripts e recursos reutilizáveis que o Claude carrega sob demanda, incluindo a skill oficial de Frontend Design da Anthropic, voltada ao bom gosto."}, {"label": "Plano e subagentes", "body": "Ele pode planejar antes de agir e criar subagentes que trabalham em diferentes partes de uma tarefa em paralelo, o que mantém grandes refatorações de UI coerentes."}]}, {"kind": "ul", "items": ["Fornecedor: Anthropic", "Credencial: chave de API da Anthropic (BYOK, via Console) ou assinatura do Claude (Pro / Max)", "Superfícies: CLI de terminal, extensões para VS Code / Cursor / JetBrains, aplicativo desktop, web"]}]}, {"id": "why-design", "heading": "Por que o Claude Code é bom em design", "blocks": [{"kind": "p", "text": "Entre os agentes de programação, o Claude Code tem reputação de bom gosto em trabalho de frontend. Algumas coisas explicam isso."}, {"kind": "steps", "items": [{"label": "Decisões específicas, não vagas", "body": "O Claude Code tende a se comprometer com escolhas concretas — valores hex exatos, escalas de espaçamento, rampas tipográficas e hierarquia de componentes — em vez de generalizar, e é isso que separa uma interface de verdade de um placeholder."}, {"label": "Raciocínio ciente da base de código", "body": "Com um amplo contexto de trabalho, ele refatora a UI em muitos arquivos de uma vez, reutilizando seus componentes e tokens existentes em vez de reinventar estilos avulsos."}, {"label": "Uma skill oficial de frontend", "body": "A Anthropic disponibiliza uma skill de Frontend Design que faz o Claude escrever primeiro uma direção de design e o afasta deliberadamente de fontes de sistema genéricas e dos previsíveis gradientes roxos."}]}, {"kind": "image", "src": "/agents/claude-code-design/claude-code-design-taste-triangle.webp", "alt": "Diagrama mostrando design system, skill e imagem de referência convergindo para um bom resultado de design", "caption": "O bom gosto vem de três insumos que você fornece: um design system, uma skill e imagens de referência reais."}, {"kind": "p", "text": "A lição é a mesma que a Anthropic faz sobre seus próprios modelos: o Claude não tem bom gosto por padrão — deixado por conta própria, ele converge para o centro estatístico do web design (Inter, gradientes roxos, sombras suaves). Ele produz bom design quando você lhe dá restrições. O Open Design empacota exatamente esses insumos, e é por isso que os dois se encaixam (mais sobre isso abaixo)."}]}, {"id": "setup", "heading": "Configure o Claude Code para trabalho de design, do zero", "blocks": [{"kind": "p", "text": "Aqui está o caminho completo, de uma máquina limpa até um Claude Code capaz de criar e verificar UI."}, {"kind": "code", "lang": "bash", "code": "# 1. Install Claude Code (native install, recommended)\ncurl -fsSL https://claude.ai/install.sh | bash\n# or: brew install --cask claude-code\n# Windows PowerShell: irm https://claude.ai/install.ps1 | iex\n\n# 2. Start it in your project and sign in on first run\ncd your-project\nclaude            # sign in with your Claude subscription or API key\n\n# 3. Generate project context\n/init             # creates a CLAUDE.md for this project\n\n# 4. Add the official Frontend Design skill\nclaude plugin install frontend-design@claude-plugins-official\n\n# 5. Wire the Figma MCP server (optional, for design handoff)\nclaude plugin install figma@claude-plugins-official"}, {"kind": "image", "src": "/agents/claude-code-design/claude-code-design-setup-flow.webp", "alt": "Fluxo de configuração em cinco passos: instalar, autenticar, configurar o CLAUDE.md, adicionar a skill, verificar", "caption": "A sequência de configuração: instalar → autenticar → configurar o CLAUDE.md → adicionar a skill de Frontend Design → habilitar a verificação no navegador."}, {"kind": "steps", "items": [{"label": "Codifique suas regras de design", "body": "Coloque seus tokens, primitivos e convenções no CLAUDE.md e aponte o Claude para eles, para que a saída combine com uma marca em vez de cair em uma aparência genérica."}, {"label": "Adicione verificação no navegador", "body": "Conecte um MCP do Playwright ou do Chrome para que o Claude renderize em um navegador real e verifique sua saída em diferentes breakpoints, em vez de apenas confirmar que o build passou."}]}]}, {"id": "skills-workflow", "heading": "O fluxo de CLAUDE.md e Skills", "blocks": [{"kind": "p", "text": "O loop de design de maior alavancagem com o Claude Code é alimentá-lo com referências reais mais o seu contexto de design e então iterar até que a UI corresponda — com o CLAUDE.md e as Skills carregando as restrições, para que você não precise reexplicá-las a cada prompt."}, {"kind": "ol", "items": ["Comece pelas referências visuais mais claras que você tiver — e inclua múltiplos estados (desktop e mobile, hover, vazio, carregando), não apenas uma única imagem de destaque.", "Seja específico no prompt; prompts vagos produzem UI genérica mesmo com um agente forte.", "Mantenha seu design system e suas convenções no CLAUDE.md e diga ao Claude onde ficam os tokens e os primitivos canônicos.", "Adicione a skill de Frontend Design para que o Claude se comprometa com uma direção estética real antes de escrever o código.", "Conecte a verificação no navegador para que o Claude renderize, redimensione para os breakpoints e compare de volta com as referências — em vez de apenas confirmar que o build funciona."]}, {"kind": "p", "text": "Solte uma imagem de referência na sessão e escreva o prompt com restrições concretas:"}, {"kind": "code", "lang": "bash", "code": "claude \"Implement reference-desktop.png and reference-mobile.png in\n  React + Vite + Tailwind + TypeScript.\n  Reuse the design-system components and tokens described in CLAUDE.md.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Render it in the browser, verify it matches the references across\n  breakpoints, and iterate until it does.\""}, {"kind": "p", "text": "Mantenha um servidor de desenvolvimento rodando ao lado, mantenha os prompts pequenos e focados, e faça commit das boas iterações / reverta as ruins (avisando o Claude quando reverter), para que cada passada parta de uma base limpa. Use o modo de plano para refatorações maiores, de modo a poder revisar a abordagem antes de qualquer alteração nos arquivos."}]}, {"id": "figma", "heading": "Claude Code + Figma: ida e volta entre design ↔ código", "blocks": [{"kind": "p", "text": "Em fevereiro de 2026, a Anthropic e a Figma lançaram uma integração bidirecional de primeira classe via servidor MCP do Figma. Ela funciona nas duas direções."}, {"kind": "steps", "items": [{"label": "Design → Código", "body": "Selecione um frame no Figma ou cole um link no Claude Code, traga o contexto de design e peça que ele implemente o design usando sua biblioteca de componentes existente. O Code Connect mantém a saída alinhada com seus componentes reais."}, {"label": "Código → Design", "body": "Crie e visualize um recurso no navegador e então diga “Send this to Figma” para capturar a UI em execução como camadas editáveis do Figma — a tela inteira ou um elemento selecionado."}]}, {"kind": "p", "text": "Instale uma vez com claude plugin install figma@claude-plugins-official (o MCP do Dev Mode exige um plano pago do Figma). O mesmo MCP do Figma está disponível para Claude Code, Codex, Cursor e VS Code — exatamente o tipo de capacidade portátil e multiagente que o Open Design foi feito para orquestrar."}]}, {"id": "vs", "heading": "Claude Code vs Codex vs Cursor para design", "blocks": [{"kind": "p", "text": "Não há um único vencedor para o trabalho de design — cada agente tem uma força diferente, e times experientes os combinam. Um resumo justo:"}, {"kind": "table", "columns": ["Agente", "Força em design", "Melhor para"], "rows": [["Claude Code", "Decisões de design específicas (hex, espaçamento, tipografia) e raciocínio de UX ciente da base de código", "Raciocínio de frontend e refatorações com contexto amplo"], ["Codex", "Forte refinamento visual e compreensão de imagens; builds assíncronos em sandbox", "Builds assíncronos delegados e regras portáteis em AGENTS.md"], ["Cursor", "Loop visual de criar e ver com preview ao vivo e edições inline", "Trabalho de UI em iteração rápida e observação dentro de uma IDE"]]}, {"kind": "p", "text": "O veredito recorrente da comunidade é que o bom gosto vem dos humanos: todos os três caem em uma estética genérica sem skills, referências e restrições. Esse é o problema real a resolver — e ele tem forma de ferramenta de design, não de modelo."}]}, {"id": "pitfalls", "heading": "Armadilhas e como evitar a aparência de “lixo de IA”", "blocks": [{"kind": "p", "text": "Mesmo com a reputação de bom gosto do Claude Code, a reclamação mais comum sobre design gerado por IA é que ele parece genérico — fontes Inter, gradientes roxos sobre branco, sombras suaves, cantos arredondados exagerados, uma estética que “grita que uma IA fez isso”. A própria Anthropic atribui isso à convergência distribucional: escolhas seguras dominam os dados de treinamento da web. Outros problemas relatados incluem layouts mobile quebrados e instruções vazando para o texto da UI."}, {"kind": "steps", "items": [{"label": "Instale a skill de Frontend Design", "body": "Ela força o Claude a se comprometer com uma direção real e evita explicitamente fontes e gradientes usados em excesso por IA."}, {"label": "Habilite a verificação no navegador", "body": "Faça o Claude renderizar e verificar a si mesmo nos diferentes breakpoints para que os layouts não quebrem silenciosamente no mobile."}, {"label": "Forneça tokens e referências", "body": "Tokens de design reais e capturas de tela de referência são a maior alavanca isolada sobre a qualidade da saída."}, {"label": "Codifique regras no CLAUDE.md", "body": "Coloque regras de estilo como “sem hero cards, no máximo dois tipos de fonte, hierarquia que prioriza a marca” onde o agente as lê a cada execução."}]}, {"kind": "p", "text": "Note que toda mitigação tem a ver com dar ao agente um contexto de design curado. Manter esse contexto na mão, projeto a projeto, é o trabalho braçal que o Open Design elimina."}]}, {"id": "open-design", "heading": "Projetando com o Claude Code dentro do Open Design", "blocks": [{"kind": "p", "text": "O Open Design é a camada de design open-source que o fluxo acima fica pedindo. Ele trata o Claude Code como um adaptador de primeira parte e o envolve em uma biblioteca curada de skills e design systems, um pipeline de renderização estruturado e uma UI desktop local — para que o contexto de design que torna o Claude Code bom esteja presente desde a primeira execução, e não montado à mão a cada vez."}, {"kind": "ol", "items": ["Instale o Open Design e selecione o Claude Code como seu agente.", "Autentique-se com sua chave de API da Anthropic (BYOK) ou sua assinatura do Claude — as credenciais permanecem na sua máquina e nunca passam por um proxy nosso.", "Escolha um design system e uma skill, e então gere decks, protótipos e landing pages com bom gosto consistente.", "Cada artefato e arquivo DESIGN.md vive no seu próprio repositório, não em uma nuvem hospedada."]}, {"kind": "p", "text": "O mesmo agente Claude Code, a mesma chave — mais um fluxo de design real, portátil e open-source ao redor. É local-first e Apache-2.0, então nada do seu trabalho ou das suas credenciais sai da sua máquina."}]}], "faqTitle": "Perguntas frequentes", "faq": [{"name": "O Claude Code é bom para trabalho de design?", "text": "Sim — ele é amplamente considerado o agente de programação com o melhor bom gosto em frontend, tomando decisões específicas e cientes da base de código sobre valores hex, espaçamento e escalas tipográficas. Com a skill de Frontend Design, um design system e imagens de referência reais no contexto, ele produz UI responsiva e de qualidade de produção e pode verificá-la em um navegador. Sem esse contexto, ele tende a cair em uma aparência genérica, e é essa a lacuna que o Open Design preenche."}, {"name": "Preciso de uma assinatura do Claude para projetar com o Claude Code?", "text": "Você pode usar uma chave de API da Anthropic (BYOK, via Console) ou uma assinatura do Claude (Pro / Max). De qualquer forma, o Open Design nunca usa um proxy para suas credenciais — elas são usadas diretamente pelo seu agente na sua máquina."}, {"name": "Claude Code ou Codex para design de frontend?", "text": "Ambos são fortes. O Claude Code é conhecido por decisões de design específicas e cientes da base de código e por raciocínio de frontend; o Codex tem forte refinamento visual e se destaca em builds delegados e em sandbox. Muitos times usam os dois — o Open Design permite trocar de agente sem mudar o seu fluxo de design."}, {"name": "Como conecto o Claude Code ao Figma?", "text": "Instale o plugin oficial do Figma com claude plugin install figma@claude-plugins-official. Você pode então implementar frames do Figma em código usando o contexto de design e enviar uma UI em execução de volta para frames editáveis do Figma com “Send this to Figma”. O MCP do Dev Mode exige um plano pago do Figma."}, {"name": "O que são Skills e CLAUDE.md?", "text": "O CLAUDE.md é um arquivo markdown na raiz do seu projeto que o Claude Code lê no início de cada sessão — o lugar para codificar suas convenções de design. As Skills empacotam instruções e recursos reutilizáveis que o Claude carrega sob demanda, incluindo a skill oficial de Frontend Design da Anthropic. O Open Design oferece uma biblioteca curada de ambos para que você pule a configuração projeto a projeto."}, {"name": "Como evito a estética genérica de “lixo de IA”?", "text": "Instale a skill de Frontend Design, forneça tokens de design reais e capturas de tela de referência, codifique as regras da marca no CLAUDE.md e habilite a verificação no navegador. O Open Design entrega tudo isso como uma biblioteca curada para que você pule a configuração projeto a projeto."}, {"name": "O Open Design é afiliado à Anthropic?", "text": "Não. O Claude Code é um produto da Anthropic; o Open Design é um projeto open-source independente que o suporta como um adaptador de primeira parte. Claude e Claude Code são marcas registradas da Anthropic."}, {"name": "Meus arquivos e credenciais estão seguros?", "text": "Sim — o Open Design é local-first e Apache-2.0. Seus arquivos, artefatos e DESIGN.md permanecem no seu próprio repositório, e suas credenciais da Anthropic são usadas diretamente pelo seu agente, nunca roteadas por servidores do Open Design."}], "ctaTitle": "Projete com o Claude Code, do jeito aberto.", "ctaBody": "Traga sua própria chave da Anthropic ou assinatura do Claude, mantenha cada arquivo local e tenha uma biblioteca de design curada ao redor do agente que você já usa.", "ctaActions": [{"label": "Use o Claude Code dentro do Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Dê uma estrela no GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Baixe o aplicativo desktop", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Veja todos os agentes suportados"},
      },
      'codex': {
        ...en['codex']!,
        title: "Codex para design — Open Design",
        description: "Como as pessoas usam o OpenAI Codex para design de UI e web — o plugin Product Design, a integração com o Figma, skills de frontend — e como o Open Design transforma o Codex em um agente de design local-first e open-source.",
        breadcrumb: "Codex",
        label: "Agente · Codex",
        heading: "Codex para design.",
        lead: "O Codex é o agente de programação da OpenAI. Com seu plugin Product Design e sua integração com o Figma, ele se tornou uma ferramenta de design séria. O Open Design conecta o Codex a um fluxo de design open-source — sua chave da OpenAI ou assinatura do ChatGPT, seus arquivos, local-first.",
        rich: {"heroCtaLead": "O Open Design transforma o Codex em um agente de design local-first e open-source — sua chave da OpenAI, seus arquivos, com uma biblioteca curada de skills e design systems ao redor.", "heroCtaActions": [{"label": "Use o Codex dentro do Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Dê uma estrela no GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Baixe o aplicativo desktop", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["O OpenAI Codex começou como um gerador de código, mas em 2026 se tornou uma ferramenta confiável para projetar interfaces de verdade — desde que você lhe dê as referências, skills e o loop de verificação certos. Este é um guia prático e completo para usar o Codex em trabalho de UI, frontend e design system, e para conectá-lo a um fluxo de design estruturado com o Open Design.", "Ele cobre o que o Codex é hoje, por que ele de repente ficou bom em frontend, como configurá-lo do zero, o loop de screenshot para UI, a integração oficial de ida e volta com o Figma, como ele se compara ao Cursor e ao Claude Code, as armadilhas que fazem a saída de IA parecer genérica e como o Open Design fecha essa lacuna como uma camada de design aberta e local-first."], "heroImage": {"src": "/agents/codex-design/codex-design-workflow-loop.webp", "alt": "Loop de feedback de design do Codex: o agente no terminal, o navegador renderizando a UI e um espaço de trabalho, com uma seta de feedback voltando ao início", "caption": "O loop central: o Codex cria a UI no terminal, renderiza e a verifica em um navegador real e itera em direção às suas referências."}, "tocLabel": "Nesta página", "toc": [{"id": "what-is-codex", "label": "O que o OpenAI Codex realmente é"}, {"id": "why-design", "label": "Por que o Codex é bom em design agora"}, {"id": "setup", "label": "Configure o Codex para design (do zero)"}, {"id": "screenshot-workflow", "label": "O fluxo de screenshot para UI"}, {"id": "figma", "label": "Integração de ida e volta Codex + Figma"}, {"id": "vs", "label": "Codex vs Cursor vs Claude Code"}, {"id": "pitfalls", "label": "Armadilhas e a aparência de “lixo de IA”"}, {"id": "open-design", "label": "Projetando com o Codex no Open Design"}, {"id": "faq", "label": "Perguntas frequentes"}], "sections": [{"id": "what-is-codex", "heading": "O que o OpenAI Codex realmente é (e o que não é)", "blocks": [{"kind": "p", "text": "Primeiro, uma desambiguação que confunde quase todo mundo que busca por “Codex”. O OpenAI Codex original era um modelo de autocompletar código de 2021 que alimentava as primeiras versões do GitHub Copilot e foi descontinuado em 2023. Não é disso que esta página trata. O Codex de hoje é a ferramenta de programação agêntica da OpenAI — ele planeja, escreve, executa e verifica código a partir de tarefas em linguagem natural."}, {"kind": "p", "text": "O Codex moderno está disponível em quatro superfícies: uma CLI de terminal (reescrita em Rust, licenciada sob Apache-2.0), uma extensão para IDE no VS Code, Cursor e Windsurf, uma experiência em nuvem/web para tarefas assíncronas delegadas e um aplicativo desktop com um navegador embutido e Computer Use."}, {"kind": "steps", "items": [{"label": "Modelo padrão", "body": "Em meados de 2026, o modelo recomendado é o gpt-5.5, sendo o gpt-5.4 o modelo que a OpenAI treinou explicitamente para frontend e computer use."}, {"label": "Arquivo de instruções", "body": "O Codex lê um arquivo AGENTS.md no seu projeto (um padrão entre ferramentas) para as regras do projeto — o lugar natural para codificar suas convenções de design."}, {"label": "Sandbox", "body": "Ele roda em um sandbox a nível de kernel (workspace-write por padrão), então um agente editando sua UI não consegue sair dos limites do projeto."}]}, {"kind": "ul", "items": ["Fornecedor: OpenAI", "Credencial: chave de API da OpenAI (BYOK) ou assinatura do ChatGPT (Free / Go / Plus / Pro / Business / Enterprise)", "Licença da CLI: Apache-2.0, open source"]}]}, {"id": "why-design", "heading": "Por que o Codex é bom em design agora", "blocks": [{"kind": "p", "text": "Três coisas convergiram no início de 2026 para tornar o Codex uma ferramenta de design de verdade, em vez de um gerador de código genérico."}, {"kind": "steps", "items": [{"label": "Um modelo treinado para frontend", "body": "A OpenAI lançou o GPT-5.4, seu primeiro modelo de linha principal treinado para frontend e computer use, com compreensão de imagens muito melhor ao longo do fluxo de design e autoverificação mais forte. Ele consegue até gerar mood boards e opções visuais antes de se comprometer com os assets finais."}, {"label": "Uma skill oficial de frontend", "body": "O catálogo openai/skills traz uma frontend-skill curada que impõe bom gosto de verdade: layouts sem cards, heros full-bleed, hierarquia que prioriza a marca, movimento contido, no máximo dois tipos de fonte e uma cor de destaque — e faz o Codex escrever uma tese visual antes de construir."}, {"label": "Verificação no navegador", "body": "Com a skill do Playwright, o Codex abre um navegador real, redimensiona para os breakpoints e compara sua saída de volta com a referência, em vez de apenas verificar que o build passou."}]}, {"kind": "image", "src": "/agents/codex-design/codex-design-taste-triangle.webp", "alt": "Diagrama mostrando design system, skill e imagem de referência convergindo para um bom resultado de design", "caption": "O bom gosto vem de três insumos que você fornece: um design system, uma skill e imagens de referência reais."}, {"kind": "p", "text": "A lição por trás das três: o Codex não tem bom gosto por padrão. Ele produz bom design quando você lhe dá restrições — um design system, uma skill estética e referências concretas. O Open Design empacota exatamente esses insumos, e é por isso que os dois se encaixam (mais sobre isso abaixo)."}]}, {"id": "setup", "heading": "Configure o Codex para trabalho de design, do zero", "blocks": [{"kind": "p", "text": "Aqui está o caminho completo, de uma máquina limpa até um Codex capaz de criar e verificar UI."}, {"kind": "code", "lang": "bash", "code": "# 1. Install the Codex CLI\nnpm install -g @openai/codex\n# or: brew install --cask codex\n# or: curl -fsSL https://chatgpt.com/codex/install.sh | sh\n\n# 2. Authenticate (ChatGPT sign-in recommended for higher limits)\ncodex            # then choose “Sign in with ChatGPT”\n\n# 3. Generate project context\ncodex            # inside your project, run /init to create AGENTS.md\n\n# 4. Add the official frontend skill, then restart Codex\n# (in the Codex app) $skill-installer frontend-skill\n\n# 5. Wire the Figma MCP server (optional, for design handoff)\ncodex mcp add figma --url https://mcp.figma.com/mcp"}, {"kind": "image", "src": "/agents/codex-design/codex-design-setup-flow.webp", "alt": "Fluxo de configuração em cinco passos: instalar, autenticar, configurar, instalar a skill, verificar", "caption": "A sequência de configuração: instalar → autenticar → configurar o AGENTS.md → instalar a skill de frontend → habilitar a verificação no navegador."}, {"kind": "steps", "items": [{"label": "Codifique suas regras de design", "body": "Coloque seus tokens, primitivos e convenções no AGENTS.md ou em um DESIGN.md e aponte o Codex para eles, para que a saída combine com uma marca em vez de cair em uma aparência genérica."}, {"label": "Escolha o nível de raciocínio certo", "body": "A OpenAI observa que níveis de raciocínio de baixo a médio costumam produzir resultados de frontend mais fortes do que o nível mais alto."}]}]}, {"id": "screenshot-workflow", "heading": "O fluxo de screenshot para UI", "blocks": [{"kind": "p", "text": "O loop de design de maior alavancagem com o Codex é transformar uma imagem de referência em uma UI funcional e responsiva e iterar até que ela corresponda. A própria orientação da OpenAI se resume a cinco passos."}, {"kind": "ol", "items": ["Comece pelas referências visuais mais claras que você tiver — e inclua múltiplos estados (desktop e mobile, hover, vazio, carregando), não apenas uma única imagem de destaque.", "Seja específico no prompt; prompts vagos produzem UI genérica.", "Prepare um design system e diga ao Codex onde ficam os tokens e os primitivos canônicos.", "Habilite a skill interativa do Playwright para que o Codex renderize em um navegador real e redimensione para os breakpoints.", "Itere fazendo o Codex comparar sua implementação de volta com as capturas de tela — em vez de apenas confirmar que o build funciona."]}, {"kind": "p", "text": "Alimente as imagens arrastando uma captura de tela para o terminal ou usando a flag de imagem, e então escreva o prompt com restrições concretas:"}, {"kind": "code", "lang": "bash", "code": "codex -i reference-desktop.png -i reference-mobile.png \\\n  \"Implement this design in React + Vite + Tailwind + TypeScript.\n   Reuse my existing design-system components and tokens.\n   Match spacing, layout, and hierarchy; make it responsive.\n   Use the Playwright skill to verify the UI matches the\n   references and iterate until it does.\""}, {"kind": "p", "text": "Rode um servidor de desenvolvimento em um segundo terminal, mantenha os prompts pequenos e focados, e faça commit das boas iterações / reverta as ruins (avisando o Codex quando reverter), para que cada passada parta de uma base limpa."}]}, {"id": "figma", "heading": "Codex + Figma: ida e volta entre design ↔ código", "blocks": [{"kind": "p", "text": "Em fevereiro de 2026, a OpenAI e a Figma anunciaram uma parceria oficial, transformando o beta anterior do MCP do Figma em uma integração bidirecional de primeira classe. Ela funciona nas duas direções."}, {"kind": "steps", "items": [{"label": "Design → Código", "body": "Copie o “link to selection” de um frame no Figma, cole-o no Codex com get_design_context e peça que ele implemente o design usando sua biblioteca de componentes existente."}, {"label": "Código → Design", "body": "A ferramenta generate_figma_design (“Code to Canvas”) transforma uma UI viva e em execução de volta em frames editáveis do Figma — a tela inteira, um elemento selecionado ou um arquivo completo."}]}, {"kind": "p", "text": "O MCP do Figma roda como um servidor remoto e está isento de limites de taxa. Adicione-o uma vez e ele fica disponível para Codex, Claude Code, Cursor, VS Code e mais — exatamente o tipo de capacidade portátil e multiagente que o Open Design foi feito para orquestrar."}]}, {"id": "vs", "heading": "Codex vs Cursor vs Claude Code para design", "blocks": [{"kind": "p", "text": "Não há um único vencedor para o trabalho de design — cada agente tem uma força diferente, e times experientes os combinam. Um resumo justo:"}, {"kind": "table", "columns": ["Agente", "Força em design", "Melhor para"], "rows": [["Codex", "Forte refinamento visual após o GPT-5.4 + frontend-skill; compreensão de imagens", "Builds assíncronos delegados, execuções em sandbox, regras portáteis em AGENTS.md"], ["Cursor", "Loop visual de criar e ver com preview ao vivo e edições inline", "Trabalho de UI em iteração rápida e observação dentro de uma IDE"], ["Claude Code", "Decisões de design específicas (hex, espaçamento, tipografia) e UX ciente da base de código", "Raciocínio de frontend e refatorações com contexto amplo"]]}, {"kind": "p", "text": "O veredito recorrente da comunidade é que o bom gosto vem dos humanos: todos os três caem em uma estética genérica sem skills, referências e restrições. Esse é o problema real a resolver — e ele tem forma de ferramenta de design, não de modelo."}]}, {"id": "pitfalls", "heading": "Armadilhas e como evitar a aparência de “lixo de IA”", "blocks": [{"kind": "p", "text": "A reclamação mais comum sobre o design gerado pelo Codex é que ele parece genérico — gradientes suaves, painéis flutuantes, cantos arredondados exagerados, sombras dramáticas, uma vibe de Inter-e-roxo que “grita que uma IA fez isso”. Outros problemas relatados incluem layouts mobile quebrados, instruções vazando para o texto da UI e atingir os limites de uso rapidamente."}, {"kind": "steps", "items": [{"label": "Instale uma skill de frontend", "body": "Uma skill estética curada força o Codex a se comprometer com uma direção real em vez da aparência padrão."}, {"label": "Habilite a verificação com Playwright", "body": "Faça o Codex renderizar e verificar a si mesmo nos diferentes breakpoints para que os layouts não quebrem silenciosamente no mobile."}, {"label": "Forneça tokens e referências", "body": "Tokens de design reais e capturas de tela de referência são a maior alavanca isolada sobre a qualidade da saída."}, {"label": "Codifique regras no AGENTS.md", "body": "Coloque regras de estilo como “sem hero cards, no máximo dois tipos de fonte, hierarquia que prioriza a marca” onde o agente as lê a cada execução."}]}, {"kind": "p", "text": "Note que toda mitigação tem a ver com dar ao agente um contexto de design curado. Manter esse contexto na mão, projeto a projeto, é o trabalho braçal que o Open Design elimina."}]}, {"id": "open-design", "heading": "Projetando com o Codex dentro do Open Design", "blocks": [{"kind": "p", "text": "O Open Design é a camada de design open-source que o fluxo acima fica pedindo. Ele trata o Codex como um adaptador de primeira parte e o envolve em uma biblioteca curada de skills e design systems, um pipeline de renderização estruturado e uma UI desktop local — para que o contexto de design que torna o Codex bom esteja presente desde a primeira execução, e não montado à mão a cada vez."}, {"kind": "ol", "items": ["Instale o Open Design e selecione o Codex como seu agente.", "Autentique-se com sua chave de API da OpenAI (BYOK) ou sua assinatura do ChatGPT — as credenciais permanecem na sua máquina e nunca passam por um proxy nosso.", "Escolha um design system e uma skill, e então gere decks, protótipos e landing pages com bom gosto consistente.", "Cada artefato e arquivo DESIGN.md vive no seu próprio repositório, não em uma nuvem hospedada."]}, {"kind": "p", "text": "O mesmo agente Codex, a mesma chave — mais um fluxo de design real, portátil e open-source ao redor. É local-first e Apache-2.0, então nada do seu trabalho ou das suas credenciais sai da sua máquina."}]}], "faqTitle": "Perguntas frequentes", "faq": [{"name": "O OpenAI Codex realmente consegue fazer trabalho de design?", "text": "Sim — com uma skill de frontend, um design system e imagens de referência reais no contexto, o Codex (especialmente no GPT-5.4) produz UI responsiva e de qualidade de produção e pode verificá-la em um navegador. Sem esse contexto, ele tende a cair em uma aparência genérica, e é essa a lacuna que o Open Design preenche."}, {"name": "Isto é o plugin Product Design do OpenAI Codex?", "text": "Não. O Open Design é um projeto open-source independente que integra o Codex como um agente. Ele complementa as próprias ferramentas da OpenAI com uma biblioteca aberta e local-first de skills e design systems."}, {"name": "Preciso de uma assinatura do ChatGPT para projetar com o Codex?", "text": "Você pode usar uma chave de API da OpenAI (BYOK) ou sua assinatura do ChatGPT. O login com o ChatGPT geralmente oferece limites mais generosos; de qualquer forma, o Open Design nunca usa um proxy para suas credenciais."}, {"name": "Codex ou Claude Code para design de frontend?", "text": "Ambos são fortes. O Claude Code é conhecido por decisões de design específicas e cientes da base de código; o Codex tem forte refinamento visual após o GPT-5.4 e se destaca em builds delegados e em sandbox. Muitos times usam os dois — o Open Design permite trocar de agente sem mudar o seu fluxo de design."}, {"name": "Como conecto o Codex ao Figma?", "text": "Adicione o servidor MCP oficial do Figma (codex mcp add figma --url https://mcp.figma.com/mcp). Você pode então implementar frames do Figma em código com get_design_context e enviar uma UI em execução de volta para frames editáveis do Figma com generate_figma_design."}, {"name": "Como evito a estética genérica de “lixo de IA”?", "text": "Instale uma skill de frontend, forneça tokens de design reais e capturas de tela de referência, codifique as regras da marca no AGENTS.md e habilite a verificação com Playwright. O Open Design entrega tudo isso como uma biblioteca curada para que você pule a configuração projeto a projeto."}, {"name": "O Open Design é afiliado à OpenAI?", "text": "Não. O Codex é um produto da OpenAI; o Open Design é um projeto open-source independente que o suporta como um adaptador de primeira parte. OpenAI e Codex são marcas registradas da OpenAI."}, {"name": "Meus arquivos e credenciais estão seguros?", "text": "Sim — o Open Design é local-first. Seus arquivos, artefatos e DESIGN.md permanecem no seu próprio repositório, e suas credenciais da OpenAI são usadas diretamente pelo seu agente, nunca roteadas por servidores do Open Design."}], "ctaTitle": "Projete com o Codex, do jeito aberto.", "ctaBody": "Traga sua própria chave da OpenAI, mantenha cada arquivo local e tenha uma biblioteca de design curada ao redor do agente que você já usa.", "ctaActions": [{"label": "Use o Codex dentro do Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Dê uma estrela no GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Baixe o aplicativo desktop", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Veja todos os agentes suportados"},
      },
      'cursor': {
        ...en['cursor']!,
        title: "Cursor para designers — Open Design",
        description: "Como designers usam o Cursor para design de UI e web — Design Mode, Figma-para-código, o MCP do Figma — e como o Open Design transforma o Cursor em um agente de design local-first e open-source.",
        breadcrumb: "Cursor",
        label: "Agente · Cursor",
        heading: "Cursor para designers.",
        lead: "O Cursor é o editor de código com IA, agora com um Design Mode visual. Designers o usam para editar a UI apontando e desenhando, e para transformar o Figma em código. O Open Design conecta o Cursor Agent a um fluxo de design open-source que mantém seus arquivos locais.",
        rich: {"heroCtaLead": "O Open Design transforma o Cursor em um agente de design local-first e open-source — sua conta do Cursor ou chaves de modelo, seus arquivos, com uma biblioteca curada de skills e design systems ao redor.", "heroCtaActions": [{"label": "Use o Cursor dentro do Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Dê uma estrela no GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Baixe o aplicativo desktop", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["O Cursor é o editor de código IA-first que tornou “criar e ver renderizar” a forma padrão de entregar UI. Com o modo Agent, edições inline, um preview dentro do editor e o Figma via MCP, ele se tornou uma ferramenta de design genuína — desde que você lhe dê as referências, regras e um loop de verificação certos. Este é um guia prático e completo para usar o Cursor em trabalho de UI, frontend e design system, e para conectá-lo a um fluxo de design estruturado com o Open Design.", "Ele cobre o que o Cursor realmente é, por que seu loop apertado de iterar e observar é bom para design, como configurá-lo do zero, o loop de screenshot e preview até a UI, a integração de ida e volta com o Figma via MCP, como ele se compara ao Codex e ao Claude Code, as armadilhas que fazem a saída de IA parecer genérica e como o Open Design fecha essa lacuna como uma camada de design aberta e local-first."], "heroImage": {"src": "/agents/cursor-design/cursor-design-hero.webp", "alt": "Convergência de design do Cursor: o editor à esquerda, um hub curado de skills e design systems no meio com a marca do Cursor ao centro, e uma UI renderizada à direita", "caption": "A ideia central: o Cursor edita e renderiza a UI no editor, enquanto um hub de design curado o alimenta com o system, as skills e as referências que fazem a saída parecer intencional."}, "tocLabel": "Nesta página", "toc": [{"id": "what-is-cursor", "label": "O que o Cursor realmente é"}, {"id": "why-design", "label": "Por que o Cursor é bom em design"}, {"id": "setup", "label": "Configure o Cursor para design (do zero)"}, {"id": "preview-workflow", "label": "O fluxo de preview para UI"}, {"id": "figma", "label": "Cursor + Figma via MCP"}, {"id": "vs", "label": "Cursor vs Codex vs Claude Code"}, {"id": "pitfalls", "label": "Armadilhas e a aparência de “lixo de IA”"}, {"id": "open-design", "label": "Projetando com o Cursor no Open Design"}, {"id": "faq", "label": "Perguntas frequentes"}], "sections": [{"id": "what-is-cursor", "heading": "O que o Cursor realmente é", "blocks": [{"kind": "p", "text": "O Cursor é um editor de código IA-first criado pela Anysphere. É um fork do VS Code, então mantém o editor, as extensões e os atalhos de teclado familiares, mas reconstrói o fluxo de trabalho em torno de um agente de IA que pode ler seu projeto inteiro, editar múltiplos arquivos, executar comandos e iterar com você no loop."}, {"kind": "p", "text": "Para trabalho de design, as superfícies importantes são o modo Agent (você descreve um resultado e o Cursor planeja e edita entre arquivos), edições inline e completions com Tab para ajustes rápidos, um preview / navegador dentro do editor para que você veja a UI em execução sem sair da janela, e o suporte a MCP que permite trazer contexto externo como um arquivo Figma ao vivo."}, {"kind": "steps", "items": [{"label": "Regras de projeto", "body": "O Cursor lê arquivos de instruções do projeto — regras `.mdc` versionadas em `.cursor/rules` e um `AGENTS.md` simples — para que você codifique suas convenções de design onde o agente as lê a cada execução."}, {"label": "Modelos", "body": "O Cursor é flexível quanto a modelos: ele vem com modelos de fronteira pela sua assinatura e também suporta trazer suas próprias chaves de modelo, então você escolhe o motor por trás do mesmo fluxo de trabalho do editor."}, {"label": "MCP", "body": "Ele fala o Model Context Protocol, então servidores externos — o mais relevante sendo o servidor MCP do Figma — se tornam contexto de primeira classe para o agente."}]}, {"kind": "ul", "items": ["Fornecedor: Anysphere", "Credencial: conta / assinatura do Cursor (Hobby / Pro / Business) ou suas próprias chaves de modelo (BYOK)", "Forma: editor de código IA-first (fork do VS Code) com um agente e preview dentro do editor"]}]}, {"id": "why-design", "heading": "Por que o Cursor é bom em design", "blocks": [{"kind": "p", "text": "A vantagem do Cursor em design não é um único recurso — é a precisão do loop de criar e ver. Três coisas o fazem parecer uma ferramenta de design em vez de um gerador de código genérico."}, {"kind": "steps", "items": [{"label": "Um loop apertado de iterar e observar", "body": "Você escreve o prompt, o Cursor edita entre arquivos e o preview dentro do editor renderiza o resultado imediatamente — então você ajusta espaçamento, hierarquia e movimento em segundos, em vez de ir e voltar entre um terminal e um navegador separados."}, {"label": "Edição visual direta", "body": "Além do chat, o Cursor permite selecionar elementos no preview e ajustar estilos, de modo que pequenas correções visuais parecem edições de design em vez de arqueologia de código."}, {"label": "Regras de projeto e contexto de MCP", "body": "Com `.cursor/rules` (ou `AGENTS.md`) e o servidor MCP do Figma, o agente trabalha a partir dos seus tokens, componentes e specs de design reais, em vez de adivinhar."}]}, {"kind": "image", "src": "/agents/cursor-design/cursor-design-taste-triangle.webp", "alt": "Diagrama mostrando design system, skill e imagem de referência convergindo para um bom resultado de design", "caption": "O bom gosto vem de três insumos que você fornece: um design system, uma skill e imagens de referência reais."}, {"kind": "p", "text": "A lição é a mesma que todo agente ensina: o Cursor não tem bom gosto por padrão. Ele produz bom design quando você lhe dá restrições — um design system, uma skill estética e referências concretas. O Open Design empacota exatamente esses insumos, e é por isso que os dois se encaixam (mais sobre isso abaixo)."}]}, {"id": "setup", "heading": "Configure o Cursor para trabalho de design, do zero", "blocks": [{"kind": "p", "text": "Aqui está o caminho completo, de uma máquina limpa até um Cursor capaz de criar, visualizar e verificar UI em relação ao seu design system."}, {"kind": "ol", "items": ["Instale o Cursor a partir de cursor.com e faça login com sua conta do Cursor, ou configure suas próprias chaves de modelo (BYOK) em Settings.", "Abra seu projeto e escolha um modelo no painel de chat / Agent.", "Adicione regras de projeto: crie `.cursor/rules/*.mdc` para convenções estruturadas e com escopo por glob, ou um `AGENTS.md` simples para instruções legíveis e diretas.", "Conecte o servidor MCP do Figma (opcional) para que o agente possa ler o contexto de design ao vivo.", "Rode seu servidor de desenvolvimento e use o preview dentro do editor para ver e verificar a UI enquanto você itera."]}, {"kind": "image", "src": "/agents/cursor-design/cursor-design-setup-flow.webp", "alt": "Fluxo de configuração em cinco passos: instalar, autenticar, configurar regras, adicionar skill, verificar", "caption": "A sequência de configuração: instalar → autenticar → configurar as regras de projeto → adicionar uma skill → habilitar a verificação no preview."}, {"kind": "p", "text": "Um arquivo mínimo de regras de projeto faz o agente projetar para uma marca em vez de cair em uma aparência genérica. Coloque-o onde o Cursor o lê a cada execução:"}, {"kind": "code", "lang": "markdown", "code": "# .cursor/rules/design.mdc\n---\ndescription: Project design conventions\nalwaysApply: true\n---\n\n- Reuse existing design-system tokens and components; never hardcode hex or spacing.\n- At most two typefaces and one accent color.\n- Brand-first hierarchy; restrained motion. No hero cards, no oversized rounded corners.\n- Build responsive by default; verify desktop and mobile in the preview before finishing."}, {"kind": "steps", "items": [{"label": "Codifique suas regras de design", "body": "Coloque seus tokens, primitivos e convenções em `.cursor/rules` ou `AGENTS.md` e aponte o Cursor para eles, para que a saída combine com uma marca em vez de cair em uma aparência genérica."}, {"label": "Mantenha os prompts pequenos", "body": "O loop apertado do Cursor recompensa pedidos focados — itere um componente ou estado de cada vez e observe o preview entre as passadas."}]}]}, {"id": "preview-workflow", "heading": "O fluxo de preview para UI", "blocks": [{"kind": "p", "text": "O loop de design de maior alavancagem com o Cursor é transformar uma referência em uma UI funcional e responsiva e iterar no editor até que ela corresponda — observando o preview ao vivo o tempo todo, em vez de adivinhar."}, {"kind": "ol", "items": ["Comece pelas referências visuais mais claras que você tiver — e inclua múltiplos estados (desktop e mobile, hover, vazio, carregando), não apenas uma única imagem de destaque.", "Seja específico no prompt; prompts vagos produzem UI genérica.", "Prepare um design system e diga ao Cursor onde ficam os tokens e os primitivos canônicos.", "Mantenha o preview dentro do editor aberto e seu servidor de desenvolvimento rodando para que cada edição renderize imediatamente nos breakpoints que importam para você.", "Itere comparando a UI renderizada de volta com as referências — e use a seleção direta de elementos no preview para pequenas correções visuais."]}, {"kind": "p", "text": "Alimente as referências anexando uma imagem ao chat e então escreva o prompt com restrições concretas:"}, {"kind": "code", "lang": "text", "code": "Implement this design in React + Vite + Tailwind + TypeScript.\nReuse my existing design-system components and tokens.\nMatch spacing, layout, and hierarchy; make it responsive.\nKeep the preview open — verify desktop and mobile match the\nreferences and iterate until they do."}, {"kind": "p", "text": "Faça commit das boas iterações e reverta as ruins (avisando o Cursor quando reverter), para que cada passada parta de uma base limpa — a mesma disciplina que impede qualquer loop de agente de derivar."}]}, {"id": "figma", "heading": "Cursor + Figma: design ↔ código via MCP", "blocks": [{"kind": "p", "text": "O Cursor se conecta ao Figma por meio do servidor MCP oficial do Figma, que dá ao agente acesso estruturado a um arquivo Figma ao vivo em vez de uma captura de tela plana. Isso elimina a adivinhação do handoff."}, {"kind": "steps", "items": [{"label": "Design → Código", "body": "Copie o link de um frame no Figma, cole-o no Cursor e peça que ele implemente o design. O servidor MCP expõe o contexto de design real — componentes, variáveis, dados de layout, tokens — para que o código gerado corresponda à fonte em vez de aproximá-la."}, {"label": "Mantenha o alinhamento", "body": "Com tokens de design, estilos e componentes usados de forma consistente no Figma (e o Code Connect quando disponível), a saída do Cursor permanece mapeada ao seu design system real, em vez de reinventar primitivos."}]}, {"kind": "p", "text": "Configure o servidor MCP remoto do Figma uma vez e ele fica disponível para o Cursor como contexto de primeira classe. Como o MCP é um padrão aberto, o mesmo servidor é reutilizável entre Cursor, Claude Code, Codex e VS Code — exatamente o tipo de capacidade portátil e multiagente que o Open Design foi feito para orquestrar."}]}, {"id": "vs", "heading": "Cursor vs Codex vs Claude Code para design", "blocks": [{"kind": "p", "text": "Não há um único vencedor para o trabalho de design — cada agente tem uma força diferente, e times experientes os combinam. Um resumo justo:"}, {"kind": "table", "columns": ["Agente", "Força em design", "Melhor para"], "rows": [["Cursor", "Loop visual de criar e ver com preview ao vivo dentro do editor e edição direta de elementos", "Trabalho de UI em iteração rápida e observação dentro de uma IDE"], ["Codex", "Forte refinamento visual com uma skill de frontend; compreensão de imagens e execuções em sandbox", "Builds assíncronos delegados e regras portáteis em AGENTS.md"], ["Claude Code", "Decisões de design específicas (hex, espaçamento, tipografia) e UX ciente da base de código", "Raciocínio de frontend e refatorações com contexto amplo"]]}, {"kind": "p", "text": "O veredito recorrente da comunidade é que o bom gosto vem dos humanos: todos os três caem em uma estética genérica sem skills, referências e restrições. Esse é o problema real a resolver — e ele tem forma de ferramenta de design, não de modelo."}]}, {"id": "pitfalls", "heading": "Armadilhas e como evitar a aparência de “lixo de IA”", "blocks": [{"kind": "p", "text": "A reclamação mais comum sobre o design gerado pelo Cursor é que ele parece genérico — gradientes suaves, painéis flutuantes, cantos arredondados exagerados, sombras dramáticas, uma vibe de Inter-e-roxo que “grita que uma IA fez isso”. Outros problemas relatados incluem layouts que quebram no mobile e instruções vazando para o texto da UI."}, {"kind": "steps", "items": [{"label": "Adicione uma skill de design", "body": "Uma skill estética curada força o Cursor a se comprometer com uma direção real em vez da aparência padrão."}, {"label": "Use o preview para verificar", "body": "Renderize e verifique a si mesmo nos diferentes breakpoints no preview dentro do editor para que os layouts não quebrem silenciosamente no mobile."}, {"label": "Forneça tokens e referências", "body": "Tokens de design reais e capturas de tela de referência são a maior alavanca isolada sobre a qualidade da saída."}, {"label": "Codifique regras em `.cursor/rules`", "body": "Coloque regras de estilo como “sem hero cards, no máximo dois tipos de fonte, hierarquia que prioriza a marca” onde o agente as lê a cada execução."}]}, {"kind": "p", "text": "Note que toda mitigação tem a ver com dar ao agente um contexto de design curado. Manter esse contexto na mão, projeto a projeto, é o trabalho braçal que o Open Design elimina."}]}, {"id": "open-design", "heading": "Projetando com o Cursor dentro do Open Design", "blocks": [{"kind": "p", "text": "O Open Design é a camada de design open-source que o fluxo acima fica pedindo. Ele trata o Cursor como um adaptador de primeira parte e o envolve em uma biblioteca curada de skills e design systems, um pipeline de renderização estruturado e uma UI desktop local — para que o contexto de design que torna o Cursor bom esteja presente desde a primeira execução, e não montado à mão a cada vez."}, {"kind": "ol", "items": ["Instale o Open Design e selecione o Cursor como seu agente.", "Autentique-se com sua conta do Cursor ou suas próprias chaves de modelo (BYOK) — as credenciais permanecem na sua máquina e nunca passam por um proxy nosso.", "Escolha um design system e uma skill, e então gere decks, protótipos e landing pages com bom gosto consistente.", "Cada artefato e arquivo DESIGN.md vive no seu próprio repositório, não em uma nuvem hospedada."]}, {"kind": "p", "text": "O mesmo agente Cursor, a mesma chave — mais um fluxo de design real, portátil e open-source ao redor. É local-first e Apache-2.0, então nada do seu trabalho ou das suas credenciais sai da sua máquina."}]}], "faqTitle": "Perguntas frequentes", "faq": [{"name": "O Cursor realmente consegue fazer trabalho de design?", "text": "Sim — com uma skill de design, um design system e imagens de referência reais no contexto, o Cursor produz UI responsiva e de qualidade de produção, e seu preview dentro do editor permite verificá-la e refiná-la visualmente. Sem esse contexto, ele tende a cair em uma aparência genérica, e é essa a lacuna que o Open Design preenche."}, {"name": "Isto é um produto oficial do Cursor?", "text": "Não. O Open Design é um projeto open-source independente que integra o Cursor como um agente. Ele complementa o Cursor com uma biblioteca aberta e local-first de skills e design systems."}, {"name": "Preciso de uma assinatura do Cursor para projetar com o Cursor?", "text": "Você pode usar uma conta / assinatura do Cursor ou trazer suas próprias chaves de modelo (BYOK). De qualquer forma, o Open Design nunca usa um proxy para suas credenciais — elas são usadas diretamente pelo seu agente."}, {"name": "Cursor ou Claude Code para design de frontend?", "text": "Ambos são fortes. O Claude Code é conhecido por decisões de design específicas e cientes da base de código; a vantagem do Cursor é seu loop apertado de criar e ver com um preview ao vivo dentro do editor. Muitos times usam os dois — o Open Design permite trocar de agente sem mudar o seu fluxo de design."}, {"name": "Como conecto o Cursor ao Figma?", "text": "Adicione o servidor MCP oficial do Figma no Cursor, então cole um link de frame do Figma no chat e peça ao Cursor que o implemente. O servidor expõe componentes, variáveis e dados de layout reais para que o código gerado corresponda ao design de origem."}, {"name": "Como evito a estética genérica de “lixo de IA”?", "text": "Adicione uma skill de design, forneça tokens de design reais e capturas de tela de referência, codifique as regras da marca em `.cursor/rules` ou `AGENTS.md` e verifique nos diferentes breakpoints no preview. O Open Design entrega tudo isso como uma biblioteca curada para que você pule a configuração projeto a projeto."}, {"name": "O Open Design é afiliado ao Cursor ou à Anysphere?", "text": "Não. O Cursor é um produto da Anysphere; o Open Design é um projeto open-source independente que o suporta como um adaptador de primeira parte. Cursor e Anysphere são marcas registradas da Anysphere, Inc."}, {"name": "Meus arquivos e credenciais estão seguros?", "text": "Sim — o Open Design é local-first. Seus arquivos, artefatos e DESIGN.md permanecem no seu próprio repositório, e suas credenciais do Cursor ou de modelo são usadas diretamente pelo seu agente, nunca roteadas por servidores do Open Design."}], "ctaTitle": "Projete com o Cursor, do jeito aberto.", "ctaBody": "Traga sua própria conta do Cursor ou chaves de modelo, mantenha cada arquivo local e tenha uma biblioteca de design curada ao redor do agente que você já usa.", "ctaActions": [{"label": "Use o Cursor dentro do Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Dê uma estrela no GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Baixe o aplicativo desktop", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Veja todos os agentes suportados"},
      },
      'opencode': {
        ...en['opencode']!,
        title: "OpenCode para design — Open Design",
        description: "Como as pessoas usam o OpenCode para design de UI e web — arquivos design.md, skills de UI/UX, MCP do Figma — e como o Open Design transforma o OpenCode em um agente de design local-first e open-source.",
        breadcrumb: "OpenCode",
        label: "Agente · OpenCode",
        heading: "OpenCode para design.",
        lead: "O OpenCode é o agente de programação com IA no terminal, open-source. Designers acoplam a ele skills de design e arquivos DESIGN.md para gerar UI de verdade. O Open Design transforma isso em um fluxo estruturado e open-source — traga suas chaves de provedor e mantenha tudo local.",
        rich: {"heroCtaLead": "O Open Design transforma o OpenCode em um agente de design local-first e open-source — qualquer modelo que você escolher com sua própria chave de provedor, seus arquivos, com uma biblioteca curada de skills e design systems ao redor.", "heroCtaActions": [{"label": "Use o OpenCode dentro do Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Dê uma estrela no GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Baixe o aplicativo desktop", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["O OpenCode é um agente de programação com IA, open-source e que prioriza o terminal, deliberadamente agnóstico quanto a modelos: você traz sua própria chave de provedor e roda qualquer modelo que quiser por trás do mesmo fluxo. Essa abertura o torna uma base natural para trabalho de design — mas, como todo agente, ele só produz boa UI quando você lhe dá as referências, skills e um loop de verificação certos. Este é um guia prático e completo para usar o OpenCode em trabalho de UI, frontend e design system, e para conectá-lo a um fluxo de design estruturado com o Open Design.", "Ele cobre o que o OpenCode realmente é, por que um agente aberto e agnóstico quanto a modelos se encaixa bem em design, como configurá-lo do zero, o loop de screenshot para UI, como o AGENTS.md e o MCP o estendem, como ele se compara ao Codex, ao Claude Code e ao Cursor, as armadilhas que fazem a saída de IA parecer genérica e como o Open Design fecha essa lacuna como uma camada de design aberta e local-first — uma combinação natural, já que ambos os projetos são open-source e rodam na sua própria máquina."], "heroImage": {"src": "/agents/opencode-design/opencode-design-hero.webp", "alt": "Loop de feedback de design do OpenCode: um agente TUI no terminal, um navegador renderizando a UI e um espaço de trabalho, com uma seta de feedback voltando ao início", "caption": "O loop central: o OpenCode cria a UI no terminal, renderiza e a verifica em um navegador real e itera em direção às suas referências — em qualquer modelo que você escolher."}, "tocLabel": "Nesta página", "toc": [{"id": "what-is-opencode", "label": "O que o OpenCode realmente é"}, {"id": "why-design", "label": "Por que um agente aberto e de qualquer modelo se encaixa em design"}, {"id": "setup", "label": "Configure o OpenCode para design (do zero)"}, {"id": "screenshot-workflow", "label": "O fluxo de screenshot para UI"}, {"id": "extend", "label": "AGENTS.md, MCP e sessões compartilháveis"}, {"id": "vs", "label": "OpenCode vs Codex vs Claude Code vs Cursor"}, {"id": "pitfalls", "label": "Armadilhas e a aparência de “lixo de IA”"}, {"id": "open-design", "label": "Projetando com o OpenCode no Open Design"}, {"id": "faq", "label": "Perguntas frequentes"}], "sections": [{"id": "what-is-opencode", "heading": "O que o OpenCode realmente é", "blocks": [{"kind": "p", "text": "O OpenCode é um agente de programação com IA open-source feito para o terminal, mantido pelo time por trás do SST (Anomaly Innovations). Ele lê seu repositório, executa comandos, edita arquivos e conversa com um grande modelo de linguagem — mas, diferente dos agentes presos a um fornecedor, ele não traz seu próprio modelo. Você o aponta para qualquer provedor e modelo que quiser e traz sua própria chave."}, {"kind": "p", "text": "Ele roda como uma UI de terminal (TUI), com um aplicativo desktop e extensões para IDE em cima do mesmo motor. Por baixo, ele usa uma arquitetura cliente/servidor, então o agente que faz o trabalho é desacoplado da superfície a partir da qual você o controla. Dois agentes embutidos — build e plan — alternam com a tecla Tab."}, {"kind": "steps", "items": [{"label": "Agnóstico quanto a modelos", "body": "Os modelos e provedores vêm do models.dev, um catálogo aberto. Você os configura no opencode.json com uma string provider/model-id e pode desabilitar provedores que não quer carregar — então o mesmo fluxo de design roda em Anthropic, OpenAI, Google, OpenRouter, modelos locais e mais."}, {"label": "Arquivo de instruções", "body": "O OpenCode lê um arquivo AGENTS.md no seu projeto (o padrão entre ferramentas, também compatível com CLAUDE.md) para as regras do projeto — o lugar natural para codificar suas convenções de design. Execute /init para gerar um."}, {"label": "Extensível", "body": "Ele suporta integração com LSP, servidores MCP, temas, atalhos de teclado e comandos personalizados, além de links de sessão compartilháveis para colaboração."}]}, {"kind": "ul", "items": ["Mantenedor: SST / Anomaly Innovations (projeto open-source)", "Credencial: sua(s) própria(s) chave(s) de API de provedor de modelo — BYOK, sem lock-in de fornecedor", "Licença: MIT, open source"]}]}, {"id": "why-design", "heading": "Por que um agente aberto e de qualquer modelo se encaixa em trabalho de design", "blocks": [{"kind": "p", "text": "O OpenCode não tem um único “modelo de design” como tem um agente de fornecedor — e é esse o ponto. Como ele é agnóstico quanto a modelos e aberto, você pode rodar o mesmo fluxo de design em qualquer modelo que esteja atualmente melhor em frontend, trocá-lo depois ou recorrer a um modelo local, tudo sem mudar sua configuração."}, {"kind": "p", "text": "Mas a escolha do modelo sozinha não compra bom gosto. Como todo agente de programação, o OpenCode produz UI genérica a menos que você lhe dê restrições. Boa saída de design vem de três insumos que você fornece."}, {"kind": "steps", "items": [{"label": "Um design system", "body": "Tokens, primitivos e convenções reais que o agente reutiliza, para que a saída combine com uma marca em vez de cair em uma aparência genérica."}, {"label": "Uma skill estética", "body": "Uma skill curada que impõe bom gosto de verdade — movimento contido, hierarquia que prioriza a marca, no máximo dois tipos de fonte e uma cor de destaque — e faz o agente se comprometer com uma direção antes de construir."}, {"label": "Referências concretas", "body": "Imagens de referência reais e múltiplos estados (desktop e mobile, hover, vazio, carregando), não uma única imagem de destaque."}]}, {"kind": "image", "src": "/agents/opencode-design/opencode-design-taste-triangle.webp", "alt": "Diagrama mostrando design system, skill e imagem de referência convergindo para um bom resultado de design", "caption": "O bom gosto vem de três insumos que você fornece: um design system, uma skill e imagens de referência reais — independentemente do modelo que você roda."}, {"kind": "p", "text": "A lição: o OpenCode lhe dá liberdade de modelo, mas o bom gosto ainda vem de um contexto de design curado. O Open Design empacota exatamente esses insumos, e é por isso que os dois se encaixam — ambos são open-source e local-first (mais sobre isso abaixo)."}]}, {"id": "setup", "heading": "Configure o OpenCode para trabalho de design, do zero", "blocks": [{"kind": "p", "text": "Aqui está o caminho completo, de uma máquina limpa até um OpenCode capaz de criar e verificar UI."}, {"kind": "code", "lang": "bash", "code": "# 1. Install OpenCode\ncurl -fsSL https://opencode.ai/install | bash\n# or: npm i -g opencode-ai@latest\n# or: brew install sst/tap/opencode\n\n# 2. Start the TUI in your project, then authenticate your provider\nopencode          # then run /login and pick your provider + paste your key\n\n# 3. Generate project context\nopencode          # inside your project, run /init to create AGENTS.md\n\n# 4. Pick your model (any provider, via models.dev)\n#    set \"provider/model-id\" in opencode.json or switch in the TUI\n\n# 5. Add an MCP server (optional, e.g. for design handoff)\n#    configure it under the \"mcp\" key in opencode.json"}, {"kind": "image", "src": "/agents/opencode-design/opencode-design-setup-flow.webp", "alt": "Fluxo de configuração em cinco passos: instalar, autenticar com sua chave de provedor, configurar o AGENTS.md, adicionar uma skill, verificar", "caption": "A sequência de configuração: instalar → autenticar (sua chave de provedor) → configurar o AGENTS.md → adicionar uma skill → verificar em um navegador real."}, {"kind": "steps", "items": [{"label": "Codifique suas regras de design", "body": "Coloque seus tokens, primitivos e convenções no AGENTS.md (ou em um DESIGN.md referenciado a partir dele) para que a saída combine com uma marca em vez de cair em uma aparência genérica. A opção instructions no opencode.json pode apontar para arquivos de regras adicionais via globs."}, {"label": "Escolha um modelo capaz", "body": "Como o OpenCode é agnóstico quanto a modelos, escolha o provedor/modelo que estiver atualmente mais forte em frontend para a passada de design — e mantenha o resto do seu fluxo inalterado."}]}]}, {"id": "screenshot-workflow", "heading": "O fluxo de screenshot para UI", "blocks": [{"kind": "p", "text": "O loop de design de maior alavancagem com qualquer agente é transformar uma imagem de referência em uma UI funcional e responsiva e iterar até que ela corresponda. A mesma forma de cinco passos se aplica no OpenCode."}, {"kind": "ol", "items": ["Comece pelas referências visuais mais claras que você tiver — e inclua múltiplos estados (desktop e mobile, hover, vazio, carregando), não apenas uma única imagem de destaque.", "Seja específico no prompt; prompts vagos produzem UI genérica.", "Prepare um design system e diga ao OpenCode onde ficam os tokens e os primitivos canônicos (no AGENTS.md).", "Rode um servidor de desenvolvimento e faça o agente renderizar em um navegador real, redimensionando para os breakpoints para checar o resultado.", "Itere fazendo o OpenCode comparar sua implementação de volta com as capturas de tela — em vez de apenas confirmar que o build funciona."]}, {"kind": "p", "text": "Referencie arquivos com @ na TUI para uma busca aproximada no seu diretório de trabalho, execute comandos de shell inline com um ! inicial e dispare ações com comandos /. Então escreva o prompt com restrições concretas:"}, {"kind": "code", "lang": "bash", "code": "opencode\n# in the TUI:\n> @reference-desktop.png @reference-mobile.png\n  Implement this design in React + Vite + Tailwind + TypeScript.\n  Reuse my existing design-system components and tokens from AGENTS.md.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Run the dev server, open it in a browser, and iterate until the\n  UI matches the references across breakpoints."}, {"kind": "p", "text": "Mantenha os prompts pequenos e focados, faça commit das boas iterações e reverta as ruins (avisando o OpenCode quando reverter), para que cada passada parta de uma base limpa."}]}, {"id": "extend", "heading": "AGENTS.md, MCP e sessões compartilháveis", "blocks": [{"kind": "p", "text": "Três pontos de extensão tornam o OpenCode prático para trabalho de design sustentado, e todos os três mapeiam de forma limpa para um fluxo de design aberto."}, {"kind": "steps", "items": [{"label": "Regras do AGENTS.md", "body": "As regras de projeto vivem em um AGENTS.md na raiz do repositório (ou regras globais em ~/.config/opencode/AGENTS.md). É a casa durável das suas convenções de design, lida a cada execução, e é compatível com os arquivos CLAUDE.md que outros agentes usam."}, {"label": "Servidores MCP", "body": "O OpenCode suporta servidores MCP locais (comando) e remotos (URL), configurados sob a chave mcp — a forma portátil de trazer contexto de design e ferramentas externas que funcionam entre agentes, não só no OpenCode."}, {"label": "Sessões compartilháveis", "body": "O comando /share cria um link público para uma conversa para colaboração ou revisão, e o /unshare o revoga — útil para obter feedback sobre uma passada de design."}]}, {"kind": "p", "text": "Essas são capacidades portáteis e multiagente — exatamente o tipo de coisa que o Open Design foi feito para orquestrar, em vez de recriar projeto a projeto."}]}, {"id": "vs", "heading": "OpenCode vs Codex vs Claude Code vs Cursor para design", "blocks": [{"kind": "p", "text": "Não há um único vencedor para o trabalho de design — cada agente tem uma força diferente, e times experientes os combinam. Um resumo justo:"}, {"kind": "table", "columns": ["Agente", "Força em design", "Melhor para"], "rows": [["OpenCode", "Open-source e agnóstico quanto a modelos; rode qualquer provedor por trás de um único fluxo no terminal", "Liberdade BYOK, troca de modelos, configurações totalmente abertas e local-first"], ["Codex", "Forte refinamento visual com uma skill de frontend; compreensão de imagens", "Builds delegados, assíncronos e em sandbox, regras portáteis em AGENTS.md"], ["Claude Code", "Decisões de design específicas (hex, espaçamento, tipografia) e UX ciente da base de código", "Raciocínio de frontend e refatorações com contexto amplo"], ["Cursor", "Loop visual de criar e ver com preview ao vivo e edições inline", "Trabalho de UI em iteração rápida e observação dentro de uma IDE"]]}, {"kind": "p", "text": "O veredito recorrente da comunidade é que o bom gosto vem dos humanos: todos eles caem em uma estética genérica sem skills, referências e restrições. Esse é o problema real a resolver — e ele tem forma de ferramenta de design, não de modelo, que é precisamente por que um agente aberto como o OpenCode combina tão bem com uma camada de design aberta."}]}, {"id": "pitfalls", "heading": "Armadilhas e como evitar a aparência de “lixo de IA”", "blocks": [{"kind": "p", "text": "A reclamação mais comum sobre o design gerado por IA é que ele parece genérico — gradientes suaves, painéis flutuantes, cantos arredondados exagerados, sombras dramáticas, uma vibe de Inter-e-roxo que “grita que uma IA fez isso”. Outros problemas relatados incluem layouts mobile quebrados e instruções vazando para o texto da UI. Nenhum deles é exclusivo do OpenCode; é o que acontece quando qualquer agente roda sem um contexto de design curado."}, {"kind": "steps", "items": [{"label": "Adicione uma skill estética", "body": "Uma skill de design curada força o agente a se comprometer com uma direção real em vez da aparência padrão."}, {"label": "Verifique em um navegador real", "body": "Renderize e verifique a si mesmo nos diferentes breakpoints para que os layouts não quebrem silenciosamente no mobile."}, {"label": "Forneça tokens e referências", "body": "Tokens de design reais e capturas de tela de referência são a maior alavanca isolada sobre a qualidade da saída."}, {"label": "Codifique regras no AGENTS.md", "body": "Coloque regras de estilo como “sem hero cards, no máximo dois tipos de fonte, hierarquia que prioriza a marca” onde o agente as lê a cada execução."}]}, {"kind": "p", "text": "Note que toda mitigação tem a ver com dar ao agente um contexto de design curado — independentemente do modelo que você roda. Manter esse contexto na mão, projeto a projeto, é o trabalho braçal que o Open Design elimina."}]}, {"id": "open-design", "heading": "Projetando com o OpenCode dentro do Open Design", "blocks": [{"kind": "p", "text": "O Open Design é a camada de design open-source que o fluxo acima fica pedindo. Ele trata o OpenCode como um adaptador de primeira parte e o envolve em uma biblioteca curada de skills e design systems, um pipeline de renderização estruturado e uma UI desktop local — para que o contexto de design que torna qualquer agente bom esteja presente desde a primeira execução, e não montado à mão a cada vez. Ambos os projetos são open-source e local-first, o que torna a combinação um encaixe natural."}, {"kind": "ol", "items": ["Instale o Open Design e selecione o OpenCode como seu agente.", "Autentique-se com sua própria chave de API de provedor de modelo (BYOK) — as credenciais permanecem na sua máquina e nunca passam por um proxy nosso.", "Escolha qualquer provedor e modelo, mais um design system e uma skill, e então gere decks, protótipos e landing pages com bom gosto consistente.", "Cada artefato e arquivo DESIGN.md vive no seu próprio repositório, não em uma nuvem hospedada."]}, {"kind": "p", "text": "O mesmo agente OpenCode, a mesma liberdade de modelo — mais um fluxo de design real, portátil e open-source ao redor. É local-first e Apache-2.0, então nada do seu trabalho ou das suas credenciais sai da sua máquina."}]}], "faqTitle": "Perguntas frequentes", "faq": [{"name": "O OpenCode realmente consegue fazer trabalho de design?", "text": "Sim — com uma skill estética, um design system e imagens de referência reais no contexto, o OpenCode produz UI responsiva e de qualidade de produção e pode verificá-la em um navegador. Como ele é agnóstico quanto a modelos, você roda qualquer modelo que esteja atualmente melhor em frontend. Sem esse contexto curado, ele tende a cair em uma aparência genérica, e é essa a lacuna que o Open Design preenche."}, {"name": "Qual modelo devo usar com o OpenCode para design?", "text": "O que você preferir — o OpenCode é agnóstico quanto a provedores via models.dev, então você pode rodar Anthropic, OpenAI, Google, OpenRouter ou modelos locais por trás do mesmo fluxo e trocar a qualquer momento. A qualidade da saída de design depende muito mais da sua skill, do seu design system e das suas referências do que do modelo sozinho."}, {"name": "O Open Design é feito pelo time do OpenCode (SST)?", "text": "Não. O Open Design é um projeto open-source independente que integra o OpenCode como um agente. Ele complementa o OpenCode com uma biblioteca aberta e local-first de skills e design systems."}, {"name": "Preciso de uma assinatura especial para projetar com o OpenCode?", "text": "Não — o OpenCode é BYOK. Você traz sua própria chave de API de provedor de modelo, e o Open Design nunca usa um proxy para suas credenciais. Não há lock-in de fornecedor."}, {"name": "OpenCode, Codex ou Claude Code para design de frontend?", "text": "Todos são fortes, e muitos times os combinam. A vantagem do OpenCode é ser totalmente open-source e agnóstico quanto a modelos; o Codex se destaca em builds delegados e em sandbox; o Claude Code é conhecido por decisões de design específicas e cientes da base de código. O Open Design permite trocar de agente sem mudar o seu fluxo de design."}, {"name": "Como estendo o OpenCode para contexto de design?", "text": "Codifique regras no AGENTS.md, adicione servidores MCP sob a chave mcp para ferramentas portáteis e contexto de design, e use sessões compartilháveis para revisão. O Open Design oferece uma biblioteca curada de skills e design systems para que você pule a configuração projeto a projeto."}, {"name": "O Open Design é afiliado ao OpenCode ou ao SST?", "text": "Não. O OpenCode é um projeto open-source mantido pelo SST (Anomaly Innovations); o Open Design é um projeto open-source independente que o suporta como um adaptador de primeira parte."}, {"name": "Meus arquivos e credenciais estão seguros?", "text": "Sim — o Open Design é local-first. Seus arquivos, artefatos e DESIGN.md permanecem no seu próprio repositório, e suas credenciais de provedor de modelo são usadas diretamente pelo seu agente, nunca roteadas por servidores do Open Design."}], "ctaTitle": "Projete com o OpenCode, do jeito aberto.", "ctaBody": "Traga sua própria chave de provedor de modelo, mantenha cada arquivo local e tenha uma biblioteca de design curada ao redor do agente aberto que você já usa.", "ctaActions": [{"label": "Use o OpenCode dentro do Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Dê uma estrela no GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Baixe o aplicativo desktop", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Veja todos os agentes suportados"},
      },
    },
  };
}
